-- SUPPRESSION des paroles importées depuis islamsunnite.net (seeding 006).
-- Retire par le texte arabe EXACT les entrées importées cette session, sans
-- toucher au reste. Robuste : essaie les noms de table au singulier ET au
-- pluriel ; chaque nom absent est ignoré (message NOTICE), donc aucune erreur
-- "relation does not exist". Le nombre de lignes supprimées est affiché par table.
-- À exécuter dans l'éditeur SQL de Supabase.

DO $$
DECLARE n integer;
BEGIN
  IF to_regclass('public.parole') IS NULL THEN
    RAISE NOTICE 'parole : table absente, ignorée.';
  ELSE
    DELETE FROM "parole" WHERE texte_arabe = ANY (ARRAY[
      'ولا يتصف سبحانه بالحركة والسكون، ولا بالكبر والصغر، ولا بالطول والقصر، ولا بالقرب والبعد بالمسافة، ولا بغير ذلك من صفات الحوادث',
      'وأنّه -أي الله- تعالى منزّه عن الجهة والمكان والجسم وسائر أوصاف الحدوث، وهذا معتقد أهل الحقّ ومنهم الإمام أحمد، وما نسبه إليه بعضهم من القول بالجهة أو نحوها كذب صراح عليه وعلى أصحابه المتقدمين كما أفاده ابن الجوزي من أكابر الحنابلة، وما وقع في كلام بعض المحدّثين والفقهاء ممّا يوهم الجهة أو التجسيم أوّله العلماء، وقالوا إنّ ظاهره غير مراد، فعليك بحفظ هذا الاعتقاد، واحذر زيغ المجسّمة والجهمية أرباب الفساد',
      'عقيدة إمام السنة أحمد بن حنبل رضي الله عنه وأرضاه وجعل جنان المعارف متقلَّبه ومأواه وأفاض علينا وعليه من سوابغ إمتنانه وبوأه الفردوس الأعلى من جنانه، موافقة لعقيدة أهل السنة والجماعة من المبالغة التامة في تنزيه الله تعالى عما يقول الظالمون والجاحدون علوًا كبيرًا من الجهة والجسمية وغيرهما من سائر سمات النقص، بل وعن كل وَصْف ليس فيه كمال مطلق، وما اشتهر بين جهلة المنسوبين إلى هذا الإمام الأعظم المجتهد من أنه قائل بشيء من الجهة أو نحوها فكذب وبُهتان وافتراء عليه، فلعن الله من نسب ذلك إليه، أو رماه بشيء من هذه المثالب التي برَّأه الله منها، وقد بيّـن الحافظ الحجة القدوة الإمام أبو الفرج بن الجوزي من أئمة مذهبه المبرئّيـن من هذه الوصمة القبيحة الشنيعة، أنَّ كل ما نسب إليه من ذلك كذب عليه وافتراء وبهتان وأن نصوصه صريحة في بطلان ذلك، وتنزيه الله تعالى عنه فاعلم ذلك فإنه مهم',
      'و إن ربي قال: يا محمد إني إذا قضيت قضاء فإنه لا يرد',
      'ما شاءَ اللهُ كانَ وما لَمْ يَشَأْ لَمْ يَكُنْ',
      'لا يردُّ القضاء إلا الدعاءُ',
      'إن القول بإثبات الجهة له تعالى كفر عند الأئمة الأربعة هداة الأمة كما نقل عنهم العراقي على ما في شرح المشكاة لعلي القاري',
      '{وجاء ربك} قال الحسن : جاء أمره وقضاؤه وقال الكلبي : ينزل حكمه',
      '{وَهُوَ الْقَاهِرُ فَوْقَ عِبَادِهِ} القادرُ الغالبُ، والمرادُ بفَوْقَ: علوُّ القدرةِ والشأنِ؛ كقوله: {وَإِنَّا فَوْقَهُمْ قَاهِرُونَ}',
      'إذا أطلق أهل السنة والجماعة فالمراد بهم الأشاعرة والماتريدية',
      'زيارة القبور مستحبة على الجملة للتذكر والاعتبار وزيارة قبور الصالحين مستحبة لاجل التبرك مع الاعتبار وقد كان رسول الله صلى الله عليه وسلم نهى عن زيارة القبور ثم أذن في ذلك بعد',
      'وما أحسن قول الإمام المهدي [أي محمد بن تومرت] في عقيدته حيث قال: لا يقالُ: متى كانَ؟ ولا أينَ كانَ؟ ولا كيفَ، كان ولا مكان، دبَّر الزمانَ، لا يتقيَّدُ بالزمانِ ولا يتخصَّصُ بالمكان',
      'إشارة إلى تكفيره بفساد اعتقاده كفساد اعتقاد المجسمة والمشبهة والقدرية ونحوهم',
      'صونوا عقائدكم من التمسك بظاهر ما تشابه من الكتاب والسنة فانّ ذلك من أصول الكفر',
      'بيــان: لا خلاف في تكفير من نفى الربوبية أو الوحدانية ، أو عبد مع الله غيره ، أو كان على دين اليهود أو النصارى أو المجوس أو الصابئين ، أو قال بالحلول أو التناسخ ، أو اعتقد أن الله غير حي أو غير عليم ، أو نفى عنه صفة من صفاته، أو قال: ( صنع العالم غيره) أو قال: ( هو متولد عن شيئ ) أو الدعى مجالسة الله حقيقة أو العروج إليه ، أو قال بقدم العالم ، أو شك في ذلك كله، أو قال بنبوة أحد بعد سيدنا محمد صلى الله عليه وسلم ، أو جوز الكذب على الأنبياء ـ عليهم الصلاة والسلام ـ أو قال بتخصيص الرسالة للعرب أو أدعى أنه يوحى إليه أو يدخل الجنة في الدنيا حقيقة ، أو كفر جميع الصحابة ـ رضي الله عنهم ـ أو جحد شيئا مما يعلم من الدين ضرورة ، أو سعى إلى الكنائيس في زي النصارى ، أو قال بسقوط العبادة عن بعض الأولياء ، أو جحد حرفا فأكثر من القرآن أوزاده أو غيره ، أو قال ليس بمعجز ، أو قال : ( الثواب والعقاب معنويان) أو قال: ( الأئمة أفضل من الأنبياء )',
      'وَمَنْ لَمْ يُؤْمِنْ بِاللهِ وَرَسُولِهِ فَإِنَّا أَعْتَدْنَا لِلْكَافِرِينَ سَعِيراً',
      'قُلْ أَطِيعُوا اللهَ وَالرَّسُولَ فَإِنْ تَوَلَّوْا فَإِنَّ اللهَ لاَ يُحِبُّ الْكَافِرِينَ',
      'وَمَن يَبْتَغِ غَيْرَ الإِسْلاَمِ دِينًا فَلَن يُقْبَلَ مِنْهُ وَهُوَ فِي الآخِرَةِ مِنَ الْخَاسِرِينَ',
      'إِنَّ الدِّينَ عِنْدَ اللهِ الإِسْلاَم',
      '« والذي نفْسُ محمدٍ بيدِهِ ، لا يسمعُ بي أحدٌ من هذه الأمةِ ، لا يهودِيٌّ ، و لا نصرانِيٌّ ، ثُمَّ يموتُ ولم يؤمِنْ بالذي أُرْسِلْتُ به ، إلَّا كان من أصحابِ النارِ «',
      'إِنَّ اللهَ لاَ يَغْفِرُ أَنْ يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَلِكَ لِمَنْ يَشَاءُ',
      'إِنَّ الَّذِينَ كَفَرُوا وَصَدُّوا عَنْ سَبِيلِ اللهِ ثُمَّ مَاتُوا وَهُمْ كُفَّارٌ فَلَنْ يَغْفِرَ اللهُ لَهُمْ',
      'إنَّ الذِينَ كَفَرُوا وظَلَمُوا لَمْ يَكُنِ اللهُ لِيَغْفِرَ لَهُم ولا لِيَهْدِيَهُم طَرِيقًا إِلاّ طَرِيقَ جَهَنَّمَ خالِدِينَ فيها أَبَدًا',
      'مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آَمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ',
      'وَرَحْمَتِي وَسِعَتْ كُلَّ شَيْءٍ فَسَأَكْتُبُهَا لِلَّذِينَ يَتَّقُونَ',
      'مَثَلُ الّذِينَ كَفَرُواْ بِرَبِّهِمْ أَعْمَالُهُمْ كَرَمَادٍ اشْتَدّتْ بِهِ الرِّيحُ فِي يَوْمٍ عَاصِفٍ',
      '« وَأَمَّا الْكَافِرُ فَيُطْعَمُ بِحَسَنَاتِهِ في الدُّنْيَا حَتّى إِذا أَفْضَى إِلى الآخِرَةِ لَم يَكُنْ لُهُ مِنْهَا نَصِيبٌ «',
      'يَجِبُ عَلَى كُلِّ بَالِغٍ عَاقِلٍ أَنْ يَعْلَمَ أَن لَا إِلَهَ إِلَّا الـلَّهُ سُبْحَانَهُ وَتَعَالَى وَأَنَّهُ وَاحِدٌ لَا شَرِيكَ لَهُ قَدِيمٌ لَا أَوَّلَ لَهُ دَائِمٌ لَا آخِرَ لَهُ لَيْسَ لَهُ ضِدٌّ، وَلَا نَظِيرٌ، وَلَا مُعِينٌ، وَلَا وَزِيرٌ، وَلَا تُـمَاثِلُهُ الـمَوْجُودَاتُ، وَلَا يُمَاثِلُهَا، وَلَا تَـحْوِيهِ الأَزْمَانُ، وَلَا الجِهَاتُ، وَلَا يَحُلُّ فِيهَا وَلَا يَحْتَاجُ إِلَى مَكَانٍ، وَلَا يَفْتَقِرُ إِلَى زَمَانٍ',
      'يفتح هذا الموضع المبارك – أي منزل النبي صلى الله عليه وسلم- فيدخله الناس كافة متبركين به في شهر ربيع الأول ويوم الاثنين منه، لأنه كان شهر مولد النبي صلى الله عليه وسلم، وفي اليوم المذكور الذي ولد فيه النبي صلى الله عليه وسلم، تفتح المواضع المقدسة المذكورة كلها وهو يوم مشهود بمكة دائما',
      'فأما الحرة فجميع بدنها عورة إلا الوجه والكفين لقوله تعالى : {وَلا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا } [النور: ٣١] قال ابن عباس رضي الله عنهما: وجهها وكفيها ولأن النبي صلى الله عليه وسلم نهى المرأة في الحرام عن لبس القفازين والنقاب ولو كان الوجه والكف عورة لما حرم سترهما في الإحرام',
      '« يا أسماء إن المرأة إذا بلغت المحيض لم تصلح أن يُرى منها إلا هذا وهذا » وأشار إلى وجهه وكفيه.',
      'لا تَنْتَقِبُ الْمَرْأَةُ الْمُحْرِمَةُ وَلا تَلْبَسُ الْقُفَّازَيْنِ',
      'وأنه لا يشبه شيئا ولا يشبهه شيء، ومن شبَّهه بخلقه فقد كفر، نص عليه أحمد، وكذا من جسَّم، أو قال إنه جسم لا كالأجسام، ذكره القاضي',
      'ثم قال : « ومن قال إنه بذاته في كل مكان أو في مكان، فكافر »',
      'ثم تكلم عن حكم الفئة الباغية وهم عصاة متأولون كمقاتلة عثمان ومقاتلة علي يوم صفين ويوم الجمل ولا يخرجهم القتال بالتأويل إلى حد الكفر فيغسل قتلاهم ،ويصلى عليهم، ولا يتبعون بما استهلكوا من الأموال إذا تابوا ، ولم يطالب أحد من البغاة المقاتلين لعلي رضي الله عنه في صفين بما استهلكوا من نفوس وأموال ، وقد أجمع أهل الحل والعقد على أن فئة معاوية بغاة ظلمة بالتأويل .',
      'وَيْحَ عَمَّار تَقْتُلُهُ الْفِئَةُ البَاغِيَةُ',
      'ومنهم المجسمة لأنهم يقولون بالجسم والحلول ومعتقد هذا لا يصح منه الايمان […] لأن من لا يعرف معبوده كيف يصح له الايمان به وذلك محال',
      '« بيان معنى العلو في قوله تعالى: ﴿الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى﴾',
      'الله سبحانه وتعالى لا يحويه مكان.',
      'من ثوابت العقيدة عند المسلمين أن الله تعالى لا يحويه مكانٌ ولا يحدُّه زمانٌ؛ لأن المكان والزمان مخلوقين، وتعالى الله سبحانه أن يحيط به شيءٌ من خلقه، بل هو خالق كل شيء، وهو المحيط بكل شيء، وهذا الاعتقاد متفقٌ عليه بين المسلمين، وقد عبَّر عن ذلك أهل العلم بقولهم: كان الله ولا مكان، وهو على ما كان قبل خلق المكان، لم يتغير عمَّا كان. »',
      '« والنبي ﷺ حين سئل عن صوم يوم الإثنين قال : « ذلك يوم ولدت فيه » فلمح إلى الاحتفال به لكونه ولد فيه . و صام يوم عاشوراء وأمر بصيامه احتفالا بنجاة موسى ، والله تعالى شرع لنا العقيقة فرحا بوجود الولد . أنفرح بوجود ولد و نذبح عنه ولا نفرح بوجود النبي ﷺ ؟ وعدم الاحتفال به في عهد السلف لا يدل على منعه، وإنما يدل على جواز تركه ، وهذه قاعدة أصولية لا يعرفها كثير من الناس ، وهي داخلة في العبادات أيضا ، ودليلها عدة أحاديث مذكورة في كتابي « إتقان الصنعة » والذي سألك لم يتنبه لها ، لانه متشبع بفكرة كل ما لم يحدث في عهد السلف فهو بدعة لا تجوز»',
      'فإذا وجدت في كلام الله أو كلام رسوله ما يوهم المماثلة فلا تعتقد ظاهره لإجماع العلماء على تأويله أي صرفه عن ظاهره',
      '« في قول النبي صلى الله عليه وسلم لما سئل عن صيام يوم الإثنين؟: « ذاك يوم ولدت فيه وأنزلت علي فيه النبوة » إشارة إلى استحباب صيام الأيام التي تتجدد فيها نعم الله على عباده فإن أعظم نعم الله على هذه الأمة إظهار محمد صلى الله عليه وسلم لهم وبعثته وإرساله إليهم كما قال تعالى: {لَقَدْ مَنَّ اللَّهُ عَلَى الْمُؤْمِنِينَ إِذْ بَعَثَ فِيهِمْ رَسُولاً مِنْ أَنْفُسِهِمْ} »',
      'علا عليها علوّ مُلْك وسُلْطان، لا علوّ انتقال وزَوال',
      'واعلموا أن مذهب أهل الحق: أن الرب سبحانه يـتقـدس عـن شغــل حيـّـز ويتنزه عن الاختصاص بجهة',
      '« إطلاق لفظ النور على الله تعالى.',
      'قالت المشبهة : يجوز أن يقال بأن الله نور يتلألأ.',
      'وقال أهل السنة والجماعة :لا بل هو خالق النور ومنور النـور ، لأن النور له لون. فلو قلنا : بأنه نور يلزمنا التشبيه فالله تعالى منزه عن التشبيه قال تعالى : * ليس كمثله شيء وهو السميع البصير * هم احتجوا بقوله تعالى : * الله نور السماوات والأرض * سمى نفسه نوراً والجواب عنه أن نقول قال ابن عباس رضي الله عنهما يعني منور السموات والارض * وقال بعضهم هـادي أهل السموات والارض »',
      'ولا يعلم متى تقوم الساعة الا الله',
      'أنا فرَطُكم على الحوضِ وليختلجنَّ رجالٌ دوني فأقولُ : يا ربِّ أصحابي فيقال : إنك لا تدْري ما أحدَثوا بعدكَ',
      'ولم يُجِزْ عامَّةُ الفُقَهاءِ إخراجَ القيمةِ وأجازَهُ أبو حنيفة',
      'قَوْلُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ : (فَرَجَعْتُ إِلَى رَبِّي) مَعْنَاهُ رَجَعْتُ إِلَى الْمَوْضِعِ الَّذِي نَاجَيْتُهُ مِنْهُ أَوَّلًا فَنَاجَيْتُهُ فِيهِ ثَانِيًا. وَقَوْلُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ : (فَلَمْ أَزَلْ أَرْجِعُ بَيْنَ رَبِّي تَبَارَكَ وَتَعَالَى وَبَيْنَ مُوسَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ) مَعْنَاهُ بَيْنَ مَوْضِعِ مُنَاجَاةِ رَبِّي. وَاللَّهُ أَعْلَمُ.',
      'ويجب أن يعلم أن الله تعالى لا يتصف كلامه القديم بالحروف والأصوات ولا شىء من صفات الخلق وأنه تعالى لا يفتقر في كلامه إلى مخارج وأدوات بل يتقدس عن جميـع ذلك',
      'كَـــــانَ اللهُ وَلَــــمْ يَــــكُــــنْ شَــىءٌ غَــيْـــرُهُ',
      'السادس: بمعنى القهر والقدرة : {اسْتَوَى عَلَى الْعَرْشِ}{الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى}',
      'ما نص عليه الشافعي رحمه الله […] [من] اعتقد أن الله تعالی جالس على العرش ، فإنه يحكم بكفره ، ولا تصح الصلاة خلف هؤلاء',
      'استواء منزهاً عن المماسة والاستقرار والتمكن والحلول والانتقال : يعني لأن ذلك كله عليه محال، إذ هو من صفات المحدثات، وتعالى ربنا عن سمات الحدوث. هذا معنى ما أشار إليه مالك رحمه الله تعالى بقوله: والكيف غير معقول. وفي بعض الروايات: والكيفية مجهولة، ولا يصح لأن المجهولة يمكن تعلقها، وغير المعقول لا يتصور فهمه، وهو المراد هنا',
      '« قوله : « خلق الله آدم على صورته » الهاء وقعت كناية بين اسمين ظاهرين ، فلم تصلح أن تصرف إلى الله عز وجل ، لقيام الدليل على أنه ليس بذي صورة سبحانه ليس كمثله شيء ، فكان مرجعها إلى آدم عليه السلام »',
      'قوله : لا نكفر أحدا من أهل القبلة. أقول : هذا الكلام قد اشتهر بين الناس ونقل عن الأئمة مثل الشافعي و أبي حنيفة و ليس على إطلاقه إذ المجسم كافر و إن صام و صلى',
      'وَأمَّا الصَّلاةُ عَلَى الكَافِرِ والدّعَاءُ لَهُ بِالمَغْفِرَةِ فَحَرَامٌ بِنَصِّ القُرآنِ وَالإِجمَاع',
      'وَمَنْ يَبْتَغِ غَيْرَ الإِسْلاَمِ دِيناً فَلَنْ يُقْبَلَ مِنْهُ',
      'لا يجوز اسباله تحت الكعبين إن كان للخيلاء فإن كان لغيرها فهو مكروه وظواهر الأحاديث في تقييدها بالجر خيلاء تدل على أن التحريم مخصوص بالخيلاء وهكذا نص الشافعي على الفرق كما ذكرنا وأجمع العلماء على جواز الاسبال للنساء وقد صح عن النبي صلى الله عليه وسلم الاذن لهن في ارخاء ذيولهن ذراعا',
      'لا ينظر اللهُ إلى من جَرَّ ثوبَهُ خُيَلاء',
      'مذهب أهل السنة أن المعرفة مرتبطة بالشهادتين لا تنفع إحداهما ولا تنجي من النار دون الأخرى الا لمن لم يقدر على الشهادتين لآفة بلسانه أو لم تمهله المدة ليقولها بل اخترمته المنية',
      '…أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأن محمدا رسول الله',
      'قال المتولي: […] وكذا التردد في أنه يكفر أم لا، فهو كفر في الحال',
      '« مذهب أهل الحق أن الله تعالى ليس في جهة و لا مكان.',
      'وقالوا في قوله تعالى {ٱلرَّحۡمَـٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ} المراد منه استولى.',
      'قال الشاعر: قد استوى بشر على العراق … من غير سيف ودم مهراق»',
      'خَمسُ صَلَواتٍ كَتَبهنَّ اللهُ على العبادِ، فمن جاء بهنَّ لم يُضَيِّعْ منهنَّ شَيئًا استِخفافًا بحَقِّهنَّ، كان له عند الله عَهدٌ أن يُدخِلَه الجنَّةَ، ومن لم يأتِ بهنَّ فليس له عند اللهِ عَهدٌ؛ إن شاء عَذَّبه، وإن شاء أدخَلَه الجنَّةَ',
      'واليد في كلام العرب تكون للجارحة كقوله تعالى (وَخُذْ بِيَدِكَ ضِغْثًا) وهذا محال على الله تعالى',
      'قال ابن حجر الهيتمي : إن البدعة الحسنة متفق على ندبها و عمل المولد و اجتماع الناس له كذلك اي بدعة حسنة',
      'فأما نفي المكان عنه فدليله ما ذكره من أنه مكون المكان، وذلك شاهد بأنه كان قبل خلق المكان، فلا يصح في حقه المكان',
      'قوله فلا يزال يدعو الله تعالى حتى يضحك الله تعالى منه قال العلماء ضحك الله تعالى منه هو رضاه بفعل عبده ومحبته اياه واظهار نعمته عليه وايجابها عليه والله أعلم',
      'الجميل : هو المجمل المحسن',
      'نعلمكم بأن اتجاه القبلة بالنسبة لأهل الولايات المتحدة الأمريكية و كندا هو الجنوب الشرقي و ذلك لأن أمريكا الشمالية واقعة في الربع الشمالي الغربي بالنسبة لمكة و من صلى إلى الشمال الشرقي فاتجاهه غير صحيح و صلاته كذلك',
      'الرب تعالى متقدس عن الاختصاص بالجهات, والاتصاف بالمحاذاة, لا تحده الأفكار, و لا تحيط به الأقطار ولا تكتنفه الأقتار ويجل عن قبول الحد والمقدار',
      'غضب: قد تكرر ذكر (الغضب) في الحديث من الله تعالى ومن الناس، فأما غضب الله فهو إنكاره على من عصاه وسخطه عليه وإعراضه عنه ومعاقبته له، وأما من المخلوقين فمنه محمود ومذموم، فالمحمود ما كان في جانب الدين والحق، والمذموم ما كان في خلافه.»',
      'وجرت العادة بمكة في ليلة الاثنين عشر من ربيع الأول في كل عام أن قاضي مكة الشافعي يتهيأ لزيارة هذا المحل الشريف بعد صلاة المغرب في جمع عظيم منهم الثلاثة القضاة، وأكثر الأعيان من الفقهاء والفضلاء وذوي البيوت بفوانيس كثيرة، وشموع عظيمة، وزحام عظيم',
      '« ما حكمُ الاحتفالِ بالمولدِ النَّبَوِيِّ الشَّرِيفِ؟',
      '[…] وقد سنَّ لنا رسولُ اللهِ ﷺ بنفسه جنسَ الشكرِ لله تعالىٰ علىٰ ميلاده الشريف؛ فقد صحَّ أنه ﷺ كان يصوم يوم الاثنين، فلما سُئل عن ذلك قال: «ذلك يومٌ وُلِدتُ فيه» أخرجه مسلم.',
      'وإذا ثبت ذلك وعُلم فمن الجائز للمسلم -بل من المندوبات له- ألا يمرَّ يومُ مولدِه من غير البهجة والسرور والفرح به ﷺ، وإعلانِ ذلك، واتخاذِ ذلك عُنوانًا وشعارًا.',
      'قال الإمام السخاويُّ رحمه الله تعالىٰ في (الأجوبة المرضية) : (ثم ما زال أهلُ الإسلامِ في سائر الأقطار والمدن العظام يحتفلون في شهر مولده ﷺ وشرَّف وكرَّم، يعملون الولائمَ البديعةَ المشتملةَ علىٰ الأمورِ البهِجَةِ الرفيعة، ويتصدقون في لياليه بأنواع الصدقات، ويُظهرون السرورَ، ويَزيدون في المبرَّاتِ، بل يعتنون بقراءة مولدِه الكريمِ، وتظهر عليهم من بركاته كلُّ فَضْلٍ عميم)اهـ.',
      'وما ذكره الإمامُ السخاويُّ رحمه الله تعالىٰ هو ما نقصده بعمل المولدِ النبويِّ الـمُنيف صلىٰ الله وسلم علىٰ صاحبه.',
      'فهل ينكر عاقلٌ ذو لُبٍّ سليمٍ جوازَ الفرحِ بمولدِه، والاحتفاءِ بطلعته المُنيرةِ علىٰ الأرض ﷺ بهذه الطريقة الشرعية التي تندرج كلُّ تفصيلةٍ منها تحتَ أصلٍ من أصولِ الشرع الشريف، وقواعده الكلِّيَّة!',
      'وعليه؛ فالاحتفال بمولده ﷺ من المندوبات، وهو مظهر من مظاهر تعظيمه وتوقيره ﷺ الذي هو عنوان محبته ﷺ التي لا يكتمل إيمانُ العبدِ إلا بتحقيقها.',
      'وَمِمَّا ذُكِرَ يُعلَمُ الْـجَـوَابُ. »',
      'وَأَمَّا الصَّغَائِرُ فَجَوَّزَهَا جَمَاعَةٌ مِنَ السَّلَفِ وَغَيْرُهُمْ عَلَى الْأَنْبِيَاءِ وَهُوَ مَذْهَبُ أَبِي جَعْفَرٍ الطَّبَرِيِّ وَغَيْرِهِ مِنَ الْفُقَهَاءِ وَالْمُحَدِّثِينَ وَالْمُتَكَلِّمِينَ',
      '(وَأَمَّا الصَّغَائِرُ فَجَوَّزَهَا) أي وجودها ووقوعها (جَمَاعَةٌ مِنَ السَّلَفِ وَغَيْرُهُمْ) مِن الخلف كإمام الحرمَين منَّا وأبي هاشم مِن المُعتزلة حيث جوَّزوا الصَّغائر غير المُنفِّرة (عَلَى الْأَنْبِيَاءِ وَهُوَ مَذْهَبُ أَبِي جَعْفَرٍ الطَّبَرِيِّ وَغَيْرِهِ مِنَ الْفُقَهَاءِ) أي المُجتهدِين (وَالْمُحَدِّثِينَ وَالْمُتَكَلِّمِينَ) أي في أصول الدِّين والمُراد بعضٌ مِن كُلٍّ منهم',
      'وأما المبتدع المتفق على كفره كالمجسمة و أشباههم فإنه كغيره من الكفار, لا توارث بينه و بين المسلمين',
      '{كل شيء هالك } أي فانٍ { إلا وجهه } أي إلا هو والوجه يعبر به عن الذات وقيل معناه إلا ما أريد به وجهه لأن عمل كل شيء أريد به غير الله فهو هالك',
      'واختلف المشايخ رحمهم اللّه تعالى في زيارة القبور للنّساء قال شمس الأئمّة السّرخسيّ رحمه اللّه تعالى الأصحّ أنّه لا بأس بها وفي التّهذيب يستحبّ زيارة القبور',
      'لكنَّه مُخالف لظاهر القُرآن؛ قال الله تعالى: {وَقَدِمْنَا إِلَىٰ مَا عَمِلُوا مِنْ عَمَلٍ فَجَعَلْنَاهُ هَبَاءً مَّنثُورًا} [الفُرقان/23]، وأُجيب أوَّلًا بأنَّ الخبر مُرسل أرسله عُروة ولم يذكر مَن حدَّثه به وعلى تقدير أنْ يكون موصولًا فالَّذي في الخبر رُؤيا منام فلا حُجَّة فيه ولعلَّ الَّذي رآها لم يكن إذ ذاك أسلم بعدُ فلا يُحتجُّ به',
      'ثم قال «وأما عياض فقال : انعقد الإجماع على أنَّ الكُفَّار لا تنفعهم أعمالهم، ولا يُثابون عليها بنعيم ولا تخفيف عذاب، و ان كان بعضهم أشدُّ عذابًا مِن بعض »',
      'وَأَمَّا الْكَافِرُ فَيُطْعَمُ بِحَسَنَاتِهِ فِي الدُّنْيَا حَتَّى إِذَا أَفْضَى إِلَى الْآخِرَةِ لَمْ يَكُنْ لَهُ حَسَنَةٌ يُعْطَى بِهَا خَيْرًا',
      'إن المشبهة ينسبون للخالق ذي الجلال الأعضاء كالمخلوقات فلا تجوز الصلاة خلفهم، فهؤلاء خارجون من الإسلام، من نسب المكان لله أو قال إنه في السماء أيضًا خارج من الإسلام، وكذا يُحكم بالكفر على من اعتقد أن الحق تعالى مستقر على العرش، فويلٌ للوهابية',
      'المظاهر الدينية للاحتفال بذكرى مولد النبي الشريف؛ كقراءة القرآن الكريم، وتلاوة السيرة العطرة، وإحياء مجالس الصلاة على النبي صلى الله عليه وآله وسلم، والإنشاد والتغني بمدائحه الكريمة وشمائله العظيمة، كل ذلك جائز ومستحب شرعًا.',
      'عن قتادة : ( وكان عرشه على الماء ) ، قال : هذا بدء خلقه قبل أن يخلق السماء والأرض',
      'ولا بأس بقراءة القرآن على القبور',
      'إِقْرَءُوا يَس عَلَى مَوْتَاكُم',
      'وَلَقَدْ أُوذِىَ أُنَاسٌ فِى بَيْرُوتَ لِأَنَّهُمْ مَا وَافَقُوا عَلَى صِيَامِ رَمَضَانَ بِقَوْلِ الْمُنَجِّمِ الْفَلَكِىِّ، وَالإِجْمَاعُ إِجْمَاعُ عُلَمَاءِ الإِسْلامِ قَدِ انْعَقَدَ أَنَّ صِيَامَ رَمَضَانَ لا يَثْبُتُ بِقَوْلِ الْفَلَكِىِّ لِأَنَّ الرَّسُولَ ﷺ وَضَعَ قَانُونًا سَمَاوِيًّا فَقَالَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا عِدَّةَ شَعْبَانَ ثَلاثِينَ اهـ [رَوَاهُ الْبُخَارِىُّ] جَمَاعَتُنَا وَقَفُوا عِنْدَ هَذَا الْحَدِيثِ وَلَمْ يُوَافِقُوا مَنْ أَثْبَتَ رَمَضَانَ بِقَوْلِ الْفَلَكِىِّ ثُمَّ أُوذُوا عَلَى ذَلِكَ أَذًى شَدِيدًا حَتَّى مِنْ قِبَلِ بَعْضِ أَصْحَابِ الْعَمَائِمِ مَعَ أَنَّ الَّذِى دَرَسُوهُ فِى دِرَاسَاتِهِمْ هُوَ أَنَّ الصِّيَامَ لا يَثْبُتُ بِقَوْلِ الْفَلَكِىِّ',
      'لا تقَدّموا رمضان بيوم أو يومين صُوموا لِرُؤيَتِهِ وأَفْطِروا لرؤيته فإن غُمَّ عَلَيكُم فَأَكْمِلُوا عِدَّةَ شَعْبَان ثَلاثين يوماً',
      'إنا أمة أمية لا نكتب ولا نحسب الشهر هكذا وهكذا يعني مرة تسعة وعشرين ومرة ثلاثين',
      'باب الدعاء للميت بعد دفنه والقعود عند قبره ساعة للدعاء لَهُ والاستغفار والقراءة',
      'فقال : « قَالَ الشَّافِعِيُّ رَحِمهُ اللَّه: وَيُسْتَحَبُّ أَنْ يُقْرَأَ عِنْدَهُ شَيْءٌ مِنَ القُرآنِ، وَإنْ خَتَمُوا القُرآنَ عِنْدَهُ كَانَ حَسَنًا »',
      '( و) الله ( الذي نفسي بيده) أي بتقديره وتدبيره',
      'وسئل الإمام أحمد رضي الله عنه عن الاستواء، فقال : استوى كما أخبر، لا كما يخطرُ للبشر',
      'حدثنـي مـحمد بن عمرو, قال: حدثنا أبو عاصم, قال: حدثنا عيسى, عن ابن أبـي نـجيح, عن مـجاهد, فـي قول الله: {وكانَ عَرْشُهُ علـى الـمَاءِ} قال : كانَ عَرْشُهُ علـى الـمَاءِ قبل أن يخـلق شيئا.',
      'و تقدم أيضا أن بلالا رضي الله تعالى عنه لما قدم من الشام لزيارة النبى صلى الله تعالى عليه وسلم أتى القبر فجعل يبكى عنده ويمرغ وجهه عليه .واسناده جيد كما سبق',
      'من زار قبري وجبت له شفاعتي',
      'أصول طريق التصوف خمسة: تقوى الله في السر والعلانية، واتباع السنة في الأقوال والأفعال، الإِعراض عن الخلق في الإِقبال والإِدبار، الرضى عن الله في القليل والكثير، والرجوع إِلى الله في السراء والضراء',
      'ولا زال أهل الإسلام يحتفلون ويهتمون بشهر مولده عليه الصلاة والسلام ويعملون الولائم ويتصدقون في لياليه بأنواع الصدقات ويظهرون السرور ويظهر عليهم من بركاته كل فضل عميم. وأول من أحدث فعل المولد الملك المظفر ابو سعيد صاحب اربل فكان يعمله في ربيع الأول ويحتفل احتفالاً هائلاً',
      'ثم يمدح الملك المظفر بقوله : « وكان شهما شجاعا بطلا عاقلا عالما عادلا »',
      'وللفظ (استوى) محامل: (جلس) و (اعتدل) و (استولى) و (علا) مكانا أو رتبة و (قصد)، كقوله تعالى: {ثُمَّ اسْتَوَى إِلَى السَّمَاءِ} [البقرة: 29]: قصد إلى فعل أمر فيها. فالأولان والرابع بمعنى علوِّ المكان محالات في حقه تعالى، بخلاف ما عداها! والعرش لغة سرير الملك والسقف',
      'وبالجملة فيجب على كل مؤمن أن يعتقد من هذا الحديث ومشابهه من المشكلات الواردة في الكتاب والسنة كـ: {الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى} ، {وَيَبْقَى وَجْهُ رَبِّكَ} ،{يَدُ اللَّهِ فَوْقَ أَيْدِيهِمْ} , وغير ذلك مما شاكله أنه ليس المراد بها ظواهرها لاستحالتها عليه تبارك وتعالى عما يقول الظالمون والجاحدون علوًا كبيرًا، ثم هو بعد ذلك مخير إن شاء أولها بنحو ما ذكرناه وهي طريقة الخلف وآثروها لكثرة المبتدعة القائلين بالجهة والجسمية وغيرهما مما هو محال على الله تعالى وإن شاء فوض علمها إلى الله تعالى وهي طريقة السلف وآثروها لخلو زمانهم عما حدث من الضلالات الشنيعة والبدع القبيحة فلم يكن لهم حاجة إلى الخوض فيها',
      'أن عمر بن الخطاب رضي الله عنه كان إذا قحطوا استسقى بالعباس بن عبد المطلب فقال اللهم إنا كنا نتوسل إليك بنبينا فتسقينا وإنا نتوسل إليك بعم نبينا فاسقنا قال فيسقون',
      'إذا سَأَلْتَ فَاسْألِ اللهَ وَ إذا اسْتَعَنْتَ فَاسْتَعِنْ بِاللهِ',
      'لا تُصَاحِبْ إلّا مُؤمِناً وَ لا تَأكُل طَعَامَكَ إلّا تَقِي',
      'وَيُطۡعِمُونَ ٱلطَّعَامَ عَلَىٰ حُبِّهِۦ مِسۡكِينً۬ا وَيَتِيمً۬ا وَأَسِيرًا',
      'اعلم رحمك الله أن زيارة قبر نبينا صلى الله عليه وسلم مشروعة مطلوبة بالكتاب والسنة وإجماع الأمة',
      '« فإن سئلنا عن قوله تعالى :{الرحمن على العرش استوى} قلنا : المراد بـ «الاستواء» القهر والغلبة والعلو. ومنه قول العرب : استوى فلان على المملكة أي استعلى عليها واطردت له. ومنه قول الشاعر : قد استوى بشر على العراق … من غير سيف ودم مهراق »',
      'أخبرنا أبو الوليد الطيالسي ثنا حماد بن سلمة عن محمد بن عمرو عن أبي سلمة عن الشريد قال أتيت النبي صلى الله عليه و سلم فقلت إن على أمي رقبة وإن عندي جارية سوداء نويبية أفتجزىء عنها قال ادع بها فقال أتشهدين أن لا إله إلا الله قالت نعم قال اعتقها فإنها مؤمنة',
      'قوله تعالى : {تجري بأعيننا} فالمراد به الأعين التي انفجرت من الأرض وإضافته إلى الله سبحانه على سبيل الملك',
      '« قال [النبي] :« صوموا لرؤيته، وأفطروا لرؤيته، فإنْ غُمَّ عليكم فأكمِلُوا العِدّة» فتبين أن ديننا لا يحتاج إلى حساب ولا كتاب، كما يفعله أهل الكتاب من ضبط عباداتهم بمسير الشمس وحسباناتها، وأن ديننا في ميقات الصيام معلق بما يُرى بالبصر وهو رؤية الهلال، فإن غمّ أكملنا عدة الشهر ولم نحتج إلى حساب.»',
      'ويلهج المسكين في موضع بحديث (أين الله) على اضطرابه متناً وسنداً مع أن (أين) قد تكون للسؤال عن المكان وقد تكون للسؤال عن المكانة، فيكون الحديث بمعنى ما هي مكانة الله عندك؟ كما نجد تفصيل ذلك في عارضة أبي بكر العربي، ومن المعروف بين العرب قولهم: فلان مكانه في السماء، يعنون علو شأنه من غير ملاحظة السماء ولا التمكن فيها أصلاً، ومن هذا القبيل قول نابغة بني جعد: علونا السماء مجدنا وجدودنا … وإنا لنبغي فوق ذلك مظهرا',
      'وأما الصلاة على النبي صلى الله عليه وسلم بعد الأذان فبدعة حسنة',
      'وقيل هذه الآية نزلت في الخوارج الذين يحرفون تأويل الكتاب والسنة ويستحلون بذلك دماء المسلمين وأموالهم كما هو مشاهد الآن في نظائرهم وهو فرقة بأرض الحجاز يقال لهم الوهابية يحسبون أنهم على شئ إلا أنهم هم الكاذبون استحوذ عليهم الشيطان فأنساهم ذكر الله أولئك حزب الشيطان ألا إن حزب الشيطان هم الخاسرون نسأل الله الكريم أن يقطع دابرهم',
      'قوله تعالى في الإنباء عن سفينة نوح عليه السلام: {تجري بأعيننا} [القمر: 14] ولم يثبت أحد من المنتمين إلى التحقيق أعينا لله تعالى. والمعنى بالأية أنها تجري بأعيننا، وهي منا بالمكان المحوط بالملائكة والحفظ والرعاية، يقال: فلان بمرأى من الملك ومسمع، إذ كان بحيث تحوطه عنايته وتكتنفه رعايته، وقيل المراد بالأعين فى هذه الآية، الأعين التي انفجرت من الأرض، وأضيفت إلى الله تعالى ملكا، وهذا غير بعيد',
      'الحمد لله الكبير المتعال، المنعوت بنعوت الجلال، الموصوف بصفات الكمال، تنزه عن الشكل و الصورة و المثال، و تعالى أن يكون في مكان أو يمر عليه زمان',
      'مباينا أيضا لجنس الحرف و الصوت و الفكرة دون خلف',
      'استوى على العرش المجيد على الوجه الذي قال، وبالمعنى الذي أراده، استواء منزها عن المماسّة والاستقرار والتمكن والحلول والانتقال، فتعالى الله الكبير المتعال عما يقوله أهل الغي والضلال، لا يحمله العرش، بل العرش وحملته محملون بلطف قدرته، مقهورون في قبضته، أحاط بكل شيء علما، وأحصى كل شيء عددا',
      '« من قال بأن الله جسم فهو كافر إجماعا . ولهذا قال إمام الحرمين في « الإرشاد » : إثبات الجهة لله كفر صراح »',
      'الإمام أبو بكر أحمد بن الحسين البيهقي قال : […] إلى أن بلغت النوبة إلى شيخنا أبي الحسن الأشعري رحمه الله فلم يحدث في دين الله حدثا ولم يأت فيه ببدعة بل أخذ أقاويل الصحابة والتابعين ومن بعدهم من الأئمة في أصول الدين فنصرها بزيادة شرح وتبيين وأن ما قالوا في الأصول وجاء به الشرع صحيح في العقول خلاف ما زعم أهل الأهواء من أن بعضه لا يستقيم في الآراء فكان في بيانه تقوية ما لم يدل عليه من أهل السنة والجماعة ونصرة أقاويل من مضى من الأئمة كأبي حنيفة وسفيان الثوري من أهل الكوفة والأوزاعي وغيره من أهل الشام ومالك والشافعي من أهل الحرمين ومن نحا نحوهما من الحجاز وغيرها من سائر البلاد وكأحمد ابن حنبل وغيره من أهل الحديث والليث بن سعد وغيره وأبي عبد الله محمد بن اسمعيل البخاري وأبي الحسن مسلم بن الحجاج النيسابوري إمامي أهل الآثار وحفاظ السنن التي عليها مدار الشرع رضي الله عنهم أجمعين وذلك دأب من تصدى من الأئمة في هذه الأمة وصار رأسا في العلم من أهل السنة في قديم الدهر وحديثه وبذلك وعد سيدنا المصطفى صلى الله عليه و سلم أمته فيما روي عنه أبو هريرة رضي الله عنه إنه قال : {يبعث الله لهذه الأمة على رأس كل مائة سنة من يجدد لها دينها}',
      'اللهم إنا نتوسل إليك بجاه أحب الخلق إليك وأعظمهم قدراً عندك سيدنا ونبينا محمد وبجاه جميع الانبياء والرسل وأهل بدر وبجميع الأولياء والصديقين والشهداء والصالحين أن لا تدع لنا ذنباً إلا غفرته ولا هماً إلا فرجته ولا عيباً إلا سترته ولا ديناً إلا أديته ولا عدواً إلا كفيته ولا مريضاً إلا شفيته ولا حاجة لك فيها رضا ولنا فيها صلاح إلا قضينا يا أرحم الراحمين يارب العالمين',
      'و إضافة عرش إلى اللّه إضافة تشريف مثل إضافة الكعبة إليه في قوله: {وَ طَهِّرْ بَيْتِيَ لِلطّٰائِفِينَ} الآية ، و اللّه منزه عن الجلوس على العرش و عن السكنى في بيت',
      'إن العلماء متفقون على انقسام البدعة إلى محمودة ومذمومة وأن عمر رضى الله عنه أول من نطق بذلك ومتفقون على أن قول النبي صلى الله عليه وسلم “كل بدعة ضلالة” عام مخصوص',
      '« وأما قوله عليه السلام : « ينزل الله في كل ليلة إلى سماء الدنيا » والمراد به انه يبعث ملكا إلى سماء الدنيا حتى ينادي على ما ورد في الخبر ثم أضاف نزول الملك إلى نفسه كما يقال نادى الأمير في البلد إذا أمر بالنداء ويقال قتل الأمير فلانا والقاتل غيره ويضاف إلى الأمير من حيث إنه هو الآمر به»',
      'وليس المحدث والبدعة مذمومًا للفظ محدث وبدعة ولا لمعناها، فقد قال الله تعالى: {مَا يَأْتِيهِمْ مِنْ ذِكْرٍ مِنْ رَبِّهِمْ مُحْدَثٍ} وقال عمر: نعمت البدعة هذه، وإنما يذم من البدعة ما خالف السنة، ويذم من المحدثات ما دعا إلى ضلالة',
      '« وقوله: « وإياكم ومحدثات الأمور » اعلم أن المحدث على قسمين: محدث ليس له أصل في الشريعة فهذا باطل مذموم. ومحدث بحمل النظير على النظير فهذا ليس بمذموم لأن لفظ « المحدث » ولفظ « البدعة » لا يذمان لمجرد الاسم بل لمعنى المخالفة للسنة والداعي إلى الضلالة ولا يذم ذلك مطلقاً . فقد قال الله تعالى: {مَا يَأْتِيهِمْ مِنْ ذِكْرٍ مِنْ رَبِّهِمْ مُحْدَثٍ} . وقال عمر رضي الله عنه: « نعمت البدعة هذه » يعني التراويح. »',
      'فأسأل النفع به على الدوام … من ربِّنا بجاه سيِّدِ الأنام',
      '« الســــؤال: أنا طالب بكلية الشريعة وقد تعلمت ودرست في علم العقيدة : أن الله موجود بلا مكان ولا يتحيز في أي جهة ، فأفتوني في ذلك ؛ حيث إن هناك بعض من يتهجم على عقيدة الأزهر .',
      'الـجـــواب : من ثوابت العقيدة عند المسلمين أن الله تعالى لا يحويه مكان ولا يحده زمان ؛ لأن المكان والزمان مخلـوقان ، وتعالى الله سبحانه أن يحيط به شيء من خلقه ، بل هو خالق كل شيء ، وهو المحيط بكل شيء ، وهذا الاعتقاد متفق عليه بين المسلمين لا يُنكره منهم مُنكِرٌ ، وقد عبَّر عن ذلك أهل العلم بقولهم : « كان الله ولا مكان ، وهو على ما كان قبل خلق المكان ؛ لم يتغير عما كان » .',
      'ومن عبارات السلف الصالح في ذلك : قول الإمام جعفر الصادق عليه السلام : « مَنْ زعم أن الله في شيء أو من شيء أو على شيء فقد أشرك ؛ إذ لو كان في شيء لكان محصورًا ، ولو كان على شيء لكان محمولا ، ولو كان من شيء لكان مُحْدَثًا » اهـ .',
      'وقيل ليحيى بن معاذ الرازي : أَخْبِرْنا عن الله عز وجل ، فقال : إله واحد ، فقيل له : كيف هو ؟ قال : ملك قادر ، فقيل له : أين هو ؟ فقال : بالمرصاد ، فقال السائل : لم أسألك عن هذا ؟ فقال : ما كان غير هذا كان صفة المخلوق ، فأما صفته فما أخبرت عنه .',
      'وسُئِل ذو النون المصري رضي الله عنه عن قوله تعالى { الرَّحْمَنُ عَلَى العَرْشِ اسْتَوَى } ، فقـال : « أثبت ذاته ونفى مكانه ؛ فهو موجود بذاته والأشياء بحكمته كما شاء » اهـ .',
      'وأما ما ورد في الكتاب والسنة من النصوص الدالة على علو الله عز وجل على خلقه فالمراد بها علو المكانة والشرف والهيمنة والقهر ؛ لأنه تعالى منـزه عن مشابهة المخلوقين ، وليست صفاته كصفاتهم ، وليس في صفة الخالق سبحانه ما يتعلق بصفة المخلوق من النقص ، بل له جل وعلا من الصفات كمالُها ومن الأسماء حُسْنَاها ، وكل ما خطر ببالك فالله تعالى خلاف ذلك ، والعجز عن درك الإدراكِ إدراكُ ، والبحث في كنه ذات الرب إشراكُ .',
      'وعقيدة الأزهر الشريف هي العقيدة الأشعرية وهي عقيدة أهل السنة والجماعة ، والسادة الأشاعرة رضي الله تعالى عنهم وأرضاهم هم جمهور العلماء من الأمة ، وهم الذين صَدُّوا الشبهات أمام المَلاَحِدَةِ وغيرهم ، وهم الذين التزموا بكتاب الله وسنة سيدنا رسول الله صلى الله عليه وآله وسلم عبر التاريخ ، ومَنْ كفّرهم أو فسّقهم يُخْشَى عليه في دينه .',
      'قال الحافظ ابن عساكر رحمه الله في كتابه « تبيين كذب المفتري فيما نسب إلى الإمام أبي الحسن الأشعري » : « اعلم وفقني الله وإياك لمرضاته ، وجعلنا ممن يتقيه حق تقاته ، أن لحوم العلماء مسمومة ، وعادة الله في هتك أستار منتقصيهم معلومة ، وأن من أطلق عليهم لسانه بالثلب ، ابتلاه الله قبل موته بموت القلب » اهـ .',
      'والأزهر الشريف هو منارة العلم والدين عبر التاريخ الإسلامي ، وقد كوَّن هذا الصرحُ الشامخُ أعظم حوزة علمية عرفتها الأمة بعد القرون الأولى المُفَضَّلة ، وحفظ الله تعالى به دينه ضد كل معاند ومشكك ؛ فالخائض في عقيدته على خطر عظيم ، ويُخْشَى أن يكون من الخوارج والمرجفين الذي قال الله تعالى فيهم :',
      'والله سبحانه وتعالى أعلم »',
      '« س: كثـر الكلام عن البدعة فمن الناس من يقسمها إلى قسمين، ومن الناس من لا يفرق فيجعل كل محدَث بعد الرسول مهما كان من البدع الضلالة، نرجو توضيح الأمر على حقيقته عند أهل السنة مع ذكر الأدلة الشرعية عند المذاهب الأربعة، مع بيان معنى البدعة لغة واصطلاحا ؟',
      'الجواب: نرفق لكم هذا البحث جوابا على سؤالكم :',
      'بيان أن البدعة بدعتان عند أهل السنة والجماعة وحديث: وكل بدعة ضلالة، عام مخصوص',
      'فالبدعة تنقسم إلى قسمين: بدعة ضلالة: وهي المحدثة المخالفة للقرءان والسنة. وبدعة هدى: وهي المحدثة الموافقة للكتاب والسنة.',
      'فإن قيل: أليس قال رسول الله صلى الله عليه وسلم فيما رواه أبو داود عن العرباض بن سارية: « وإياكم ومحدثات الأمور فإن كل محدثة بدعة وكل بدعة ضلالة ». فالجواب: أن هذا الحديث لفظه عام ومعناه مخصوص بدليل الأحاديث السابق ذكرها فيقال: إن مراد النبي صلى الله عليه وسلم ما أحدث على خلاف الكتاب أو السنة أو الإجماع أو الأثر.',
      'هذا وأما من حيث التفصيل فالبدعة منقسمة إلى الأحكام الخمسة وهي الواجب والمندوب والمباح والمكروه والحرام كما نص علماء المذاهب الأربعة.»',
      'سُئِلَ الأَوْزَاعِيُّ , وَمَالِكٌ ، وَسُفْيَانُ الثَّوْرِيُّ ، والليث بن سعد عَنْ هَذِهِ الأَحَادِيثِ فَقَالُوا : أَمِرُّوهَا كَمَا جَاءَتْ بِلا كَيْفِيَّةٍ.',
      'والاستواء في قوله تعالى : { ثُمَّ اسْتَوَى عَلَى الْعَرْشِ} معناه استولى ، قاله الواحدي وقيل معناه القهر والغلبة. تقول العرب: استوى زيد على أرض كذا أي ملكهم وقهرهم، قال الشاعر: قد استوى بشر على العراق … من غير سيف ودم مهراق ولما أن كان العرش أعظم المخلوقات المهولة اكتفى بذكره عما دونه، إذ أن ما دونه تبع له',
      'قد زرته مرارا كثيرة وما حلت بي شدة في وقت مقامى بطوس فزرت قبر على بن موسى الرضا صلوات الله على جده وعليه ودعوت الله إزالتها عنى إلا أستجيب لي وزالت عنى تلك الشدة وهذا شيء جربته مرارا فوجدته كذلك',
      'ومن الإلحاد تسمية الله بالجوهر والجسم والعقل والعلة',
      'ووقــع ذكر اليد في القرآن والحديث مضافًا إلى الله تعالى، واتفق أهل السنة والجماعة على أنه ليس المراد باليد الجارحة التي هي من صفات المحدثات',
      'والبدعة في الأصل إحداث أمر لم يكن في زمن رسول الله صلى الله عليه وسلم، ثم البدعة على نوعين، إن كانت مما تندرج تحت مستحسن في الشرع فهي بدعة حسنة وإن كانت مما يندرج تحت مستقبح في الشرع فهي بدعة مستقبحة',
      '« الحمد لله الذي تنـزه عن الحد والأين والكيف والزمان والمكان .المتكلم بكلام قديم أزلي صفة من صفاته قائم بذاته لا منفصل عنه ولا عائد إليه ولا يحُل في المحدثات ولا يجانس المخلوقات ولا يوصف بالحروف والأصوات تنـزَّهت صفات ربنا عن الأرض والسماوات. اللهم إنّا نُوَحِّدُك ولا نَحُدُّك ونؤمن بك ولا نكَيِّفُك ونعبدك ولا نُشَبِّهُك ونعتقد أن من شبهك بخلقك لم يعرف الخالق من المخلوق» و قال أيضا : « القُدُّوس على العرش استوى من غير تمكن ولا جلوس » فقال : « العرش بنفسه هو المكان وله جوانب وأركان وكان الله ولا مكان وهو الآن على ما عليه كان ليس له تحتٌ فيُقِلَّه ولا فوقٌ فيُظِلَّه ولا جوانب فتعدله ولا خلْف فيسنده ولا أمام فيحده. جل عن التجريد والتقرير والتكيف والتصوير والتشبيه والنظير.﴿لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّمِيعُ البَصيرُ﴾ »',
      'وقوله {يخافون ربهم من فوقهم} معناه يخافون ربهم أن ينزل عليهم عذابا من فوقهم',
      'لأن استواءه على العرش سبحانه ليس على معنى التمكن والاستقرار، بل هو على معنى العلو بالقهر والتدبير وارتفاع الدرجة بالصفة، على الوجه الذي يقتضي مباينة الخلق',
      '[ومما يستحيل في حق الله : ] المماثلة للحوادث بأن يكون جِرما أي تأخذ ذاته العليّة قدرا من الفراغ أو يكون عَرَضا يقوم بالجرم أو يكون في جهة للجرم أو له هو جهة أو يتقيد بمكان أو زمان أو تتصف ذاته العليّة بالحوادث أو يتصف بالصغر أو الكبر',
      '« وفسر الوجه بالملك. وكذا نقل الطبري عن بعض أهل العربية. وكذا ذكره الفراء وعن أبي عبيد إلا وجهه : إلا جلاله. قوله « ويقال » إلى آخره ، قال سفيان : معناه إلا ما أريد به رضاء الله والتقرب لا الرياء ووجه الناس »',
      'صِفَاتُ اللَّهِ جَلَّ وَعَلا لا تُكَيَّفُ ، وَلا تُقَاسُ إِلَى صِفَاتِ الْمَخْلُوقِينَ ، فَكَمَا أَنَّ اللَّهَ جَلَّ وَعَلا مُتَكَلِّمٌ مِنْ غَيْرِ آلَةٍ بَأَسْنَانٍ وَلَهَوَاتٍ وَلِسَانٍ وَشَفَةٍ كَالْمَخْلُوقِينَ ، جَلَّ رَبُّنَا وَتَعَالَى عَنْ مِثْلِ هَذَا وَأَشْبَاهِهِ ، وَلَمْ يَجُزْ أَنْ يُقَاسَ كَلامُهُ إِلَى كَلامِنَا ، لأَنَّ كَلامَ الْمَخْلُوقِينَ لا يُوجَدُ إِلا بِآلاتٍ ، وَاللَّهُ جَلَّ وَعَلا يَتَكَلَّمُ كَمَا شَاءَ بِلا آلَةٍ',
      '« فصل في تحقيق معنى البدعة وحكمها :',
      'اعلم أن البدعة لغة ما أحدث على غير مثال سابق يقال: جئت بأمر بديع أي محدث عجيب لم يعرف قبل ذلك. وفي الشرع المحدَثُ الذي لم ينص عليه القرءان ولا جاء في السنة، قال ابن العربي: « ليست البدعة والمحدَث مذمومين للفظ بدعة ومحدث ولا معنييهما، وإنما يذم من البدعة ما يخالف السنة، ويذم من المحدثات ما دعا إلى الضلالة » ا.هـ.',
      'أقسام البدعة: والبدعة تنقسم إلى قسمين: بدعة ضلالة: وهي المحدَثة المخالفة للقرءان والسنة. وبدعة هدى: وهي المحدَثة الموافقة للقرءان والسنة.',
      'وهذا التقسيم مفهوم من حديث البخاري ومسلم عن عائشة رضي الله عنها قالت: قال رسول الله صلى الله عليه وسلم: « مَن أحدث في أمرنا هذا ما ليس منه فهو رد ». ورواه مسلم بلفظ ءاخر وهو: « من عمل عملا ليس عليه أمرنا فهو رد ». فأفهم رسول الله صلى الله عليه وسلم بقوله: »ما ليس منه » أن المحدَث إنما يكون ردًّا أي مردوداً إذا كان على خلاف الشريعة، وأن المحدَث الموافق للشريعة ليس مردودًا.',
      'وهو مفهوم أيضًا مما رواه مسلم في صحيحه من حديث جرير بن عبد الله البجلي رضي الله عنه أنه قال: قال رسول الله صلى الله عليه وسلم : « من سن في الإسلام سنة حسنة فله أجرها وأجر من عمل بها بعده من غير أن ينقص من أجورهم شىء، ومن سن في الإسلام سنة سيئة كان عليه وزرها ووزر من عمل بها من بعده من غير أن ينقص من أوزارهم شىء ».',
      'وفي صحيح البخاري في كتاب صلاة التراويح ما نصه: « قال ابن شهاب: فتوفي رسول الله صلى الله عليه وسلم والناس على ذلك »، قال الحافظ ابن حجر: « أي على ترك الجماعة في التراويح ». ثم قال ابن شهاب في تتمة كلامه: « ثم كان الأمر على ذلك في خلافة أبي بكر وصدرًا من خلافة عمر رضي الله عنه ». وفيه أيض تتميمًا لهذه الحادثة عن عبد الرحمن بن عبد القاريّ أنه قال:خرجت مع عمر بن الخطاب رضي الله عنه ليلة في رمضان إلى المسجد، فإذا الناس أوزاع متفرقون يصلي الرجل لنفسه ويصلي الرجل فيصلي بصلاته الرهط، فقال عمر: إني أرى لو جمعت هؤلاء على قارىء واحد لكان أمثل، ثم عزم فجمعهم على أُبيّ بن كعب، ثم خرجت معه ليلة أخرى والناس يصلون بصلاة قارئهم قال عمر: « نعم البدعة هذه ».ا.هـ. وفي الموطأ بلفظ: « نِعمت البدعة هذه ». »',
      'إن البدعة لم تنحصر في الحرام والمكروه، بل قد تكون أيضا: مباحة ومندوبة وواجبة',
      'قوله صلى الله عليه وسلم : (من سن في الإسلام سنة حسنة فله أجرها) إلى آخره ، فيه : الحث على الابتداء بالخيرات وسن السنن الحسنات ، والتحذير من اختراع الأباطيل والمستقبحات.',
      'فقال الإمام النووي : « وفي هذا الحديث تخصيص قوله صلى الله عليه وسلم : كل محدثة بدعة وكل بدعة ضلالة ، وأن المراد به المحدثات الباطلة والبدع المذمومة ، وقد سبق بيان هذا في كتاب صلاة الجمعة ، وذكرنا هناك أن البدع خمسة أقسام : واجبة ومندوبة ومحرمة ومكروهة ومباحة. »',
      'ولا يجوز عليه تعالى ما يجوز على الجواهر والأجسام من الحركة والسكون والزوال والانتقال والتغير والمنافع والمضار، ولا تحويه الأمكنة ولا تحيط به الأزمنة',
      '« حدثنا علي بن حجر حدثنا إسمعيل بن عياش عن محمد بن إسحق عن عمرو ابن شعيب عن أبيه عن جده أن رسول الله صلى الله عليه وسلم قال :',
      'إذا فزع أحدكم في النوم فليقل «أعوذ بكلمات الله التامات من غضبه وعقابه وشر عباده ومن همزات الشياطين وأن يحضرون» فإنها لن تضره.',
      'وكان عبد الله بن عمرو يلقنها من بلغ من ولده ومن لم يبلغ منهم كتبها في صك ثم علقها في عنقه.',
      'قال أبو عيسى هذا حديث حسن غريب.»',
      'ما عرف الله تعالى من شبهه وجسمه من اليهود ، أو أجاز عليه البدا ، أو أضاف إليه الولد منهم ، أو أضاف إليه الصاحبة والولد ، وأجاز الحلول عليه ، والانتقال والامتزاج من النصارى ، أو وصفه بما لا يليق به ، أو أضاف إليه الشريك والمعاند في خلقه و ملكه من المجوس والثنوية فمعبودهم الذي عبدوه ليس بالله وإن سموه به إذ ليس موصوفا بصفات الإله الواجبة له . فإذن ما عرفوا الله و لا عبدوه',
      'وفي هذا الحديث دليل على استحباب التبرك بآثار الصالحين وثيابهم',
      'وقال بعضهم : المبتدعة أقسام : الأول : ما نكفره قطعا ، كقاذف عائشة رضي الله عنها ومنكر علم الجزئيات ، وحشر الأجساد ، والمجسمة ، والقائل بقدم العالم .',
      '{ وَهُوَ مَعَكُمْ } يعني بقدرته وسلطانه وعلمه { أَيْنَ مَا كُنتُمْ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ } يبصر أعمالكم ويراها ولا يخفى عليه شيء منها. وقد جمع في هذه الآية بين { ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ } وبين { وَهُوَ مَعَكُمْ } والأخذ بالظاهرين تناقض فدل على أنه لا بدّ من التأويل، والإعراضُ عن التأويل ٱعتراف بالتناقض.',
      'الله تعالى لا يوصف بالجهات ، و لا أنه في جهة',
      'وأما قوله تعالى {ورافعك إلي} معناه إلى كرامتي ورحمتي',
      'وَكَانَ يذهب -أي الثلجي – مَذْهَب النجار فِي القَوْل بِأَن الله فِي كل مَكَان وَهُوَ مَذْهَب الْمُعْتَزلَة وَهَذَا التَّأْوِيل عندنَا مُنكر من أجل أَنه لَا يجوز أَن يُقَال إِن الله تَعَالَى فِي مَكَان أَو فِي كل مَكَان',
      'أن القول بربوبية النجم كفر بالإجماع والكفر غير جائز بالإجماع على الأنبياء',
      'لا يجوز أن يقال : إن إبراهيم – عليه السلام – قال على سبيل الجزم : هذا ربي',
      'نقول قوله : ( هذا ربي ) معناه هذا ربي في زعمكم واعتقادكم',
      'أن المراد منه الاستفهام على سبيل الإنكار إلا أنه أسقط حرف الاستفهام',
      'وقد قال الإمام أبو المعالي (الجويني) : إن محمداً صلى الله عليه وسلم ليلة الإسراء لم يكن بأقرب إلى الله عز وجل من يونس بن متى حين كان في بطن الحوت',
      'يَنْزِلُ – يعني الله – بِلا آلَةٍ ، وَلا تَحَرُّكٍ ، وَلا انْتِقَالٍ مِنْ مَكَانٍ إِلَى مَكَانٍ […] وَكَذَلِكَ يَنْزِلُ كَيْفَ يَشَاءُ بِلا آلَةٍ مِنْ غَيْرِ أَنْ يُقَاسَ نُزُولُهُ إِلَى نُزُولِ الْمَخْلُوقِينَ ، كَمَا يُكَيَّفُ نُزُولُهُمْ ، جَلَّ رَبُّنَا وَتَقَدَّسَ مِنْ أَنْ تُشَبَّهَ صِفَاتُهُ بِشَيْءٍ مِنْ صِفَاتِ الْمَخْلُوقِينَ',
      'الإجماع على أن الكفار لا تنفعهم أعمالهم , ولا يثابون عليها بنعيم ولا بتخفيف عذاب',
      '« أن رجلاً كان يختلف إلى عثمان بن عفان في حاجة له فكان عثمان لا يلتفت إليه ولا ينظر في حاجته (أي لنسيانه لها كما يأتي) فلقى عثمان بن حنيف فشكا ذلك إليه فقال له عثمان بن حنيف:',
      'ائت الميضأة فتوضأ ثم ائت المسجد فصل فيه ركعتين، ثم قل: اللهم إني أسألك وأتوجه إليك بنبينا محمد صلى الله عليه وسلم نبي الرحمة يا محمد إني أتوجه بك إلى ربي فيقضي لي حاجتي، وتذكر حاجتك، ورح إلي حين أروح معك.',
      'فانطلق الرجل فصنع ما قال له ثم أتى باب عثمان فجاء البواب حتى أخذ بيده فأدخله على عثمان بن عفان فأجلسه معه على الطنفسة وقال: حاجتك؟ فذكر حاجته فقضاها له ثم قال له: ما ذكرت حاجتك حتى كانت هذه الساعة، وقال: ما كانت لك من حاجة فائتنا،',
      'ثم إن الرجل خرج من عنده فلقي عثمان بن حنيف فقال له: جزاك الله خيرًا ما كان ينظر في حاجتي ولا يلتفت إلي حتى كلمته فيّ،',
      'فقال عثمان بن حنيف: والله ما كلمته ولكن شهدت رسول الله صلى الله عليه وسلم وأتاه رجل ضرير فشكا إليه ذهاب بصره ،',
      'فقال له النبي صلى الله عليه وسلم: « أو تصبر؟ » فقال: يا رسول الله إنه ليس لي قائد وقد شق علي، فقال له النبي صلى الله عليه وسلم: « ائت الميضأة فتوضأ ثم صل ركعتين ثم ادع بهذه الدعوات » ،',
      'فقال عثمان بن حنيف: فوالله ما تفرقنا وطال بنا الحديث حتى دخل علينا الرجل كأنه لم يكن به ضرر قط.',
      '[وقد قال الطبر اني : ] والحديث صحيح »',
      'نور: في أَسماء الله تعالى: النُّورُ؛ قال ابن الأَثير: هو الذي يُبْصِرُ بنوره ذو العَمَاية ويَرْشُدُ بهداه ذو الغَوايَةِ، وقيل: هو الظاهر الذي به كل ظهور، والظاهر في نفسه المُظْهِر لغيره يسمى نوراً. قال أَبومنصور: والنُّور من صفات الله عز وجل، قال الله عز وجل: الله نُورُ السموات والأَرض؛ قيل في تفسيره: هادي أَهل السموات والأَرض، وقيل: مَثل نوره كمشكاة فيها مصباح؛ أَي مثل نور هداه في قلب المؤمن كمشكاة فيها مصباح.',
      'إنّه – يعني الإمام أحمد بن حنبل – كان لا يقول بالجهة للباري تعالى',
      '« قوله : « ينزل ربنا إلى السماء الدنيا» استدل به من أثبت الجهة ، وقال : هي جهة العلو؛ وأنكر ذلك الجمهور لأن القول بذلك يفضى إلى التحيز تعالى الله عن ذلك .وقد اختلف في معنى النزول على أقوال:',
      'فمنهم من حمله على ظاهره وحقيقته وهم المشبهة تعالى الله عن قولهم،',
      'ومنهم من أنكر صحة الأحاديث الواردة في ذلك جملة وهم الخوارج والمعتزله وهو مكابرة والعجب إنهم أولوا ما في القرءان من نحو ذلك وانكروا ما في الحديث إما جهلا وإما عنادا،',
      'ومنهم من اجراه على ما ورد مؤمنا به على طريق الإجمال منزها الله تعالى عن الكيفيه والتشبيه وهم جمهور السلف ونقله البيهقي وغيره عن الأئمة الأربعة والسفيانين والحمادين والأوزاعي والليث وغيرهم،',
      'ومنهم من أوله على وجه يليق مستعمل في كلام العرب ومنهم من أفرط في التأويل حتى كاد أن يخرج إلى نوع من التحريف،',
      'ومنهم من فصل بين مايكون تأويله قريبا مستعملا في كلام العرب وبين ما يكون بعيدا مهجورا فأول في بعض وفوض في بعض وهو منقول عن مالك وجزم به من المتأخرين بن دقيق العيد،',
      'قال البيهقي : واسلمها الإيمان بلا كيف والسكوت عن المراد »',
      'و{العليّ} يُراد به علو القدر والـمنـزلة لا علو الـمكان ، لأنَّ الله سبحانه منـزه عن التحيز؛ و كذا {العظيم} هي صفة بمعنى عظم القدر والخطر، لا على معنى عظم الأجرام',
      'قال أبو حنيفة : من قال لا أعرف الله أفي السماء أم في الأرض فقد كفر، لأنه بهذا القول يوهم أن يكون له مكان فكان مشركاً',
      'قال نعيم بن حماد : من شبه الله بشىء من خلقه فقد كفر ومن أنكر ما وصف الله به نفسه فقد كفر',
      'حدثنا ابن عبد الأعلى، قال: ثنا ابن ثور، عن معمر، عن قتادة، في قوله { يَوْمَ يُكْشَفُ عَنْ ساقٍ } قال: يوم يكشف عن شدة الأمر',
      'وأخرج البيهقي في شعب الإِيمان عن سفيان [الثوري] في قوله : {كل شيء هالك إلا وجهه} قال: إلا ما أريد به وجهه من الأعمال الصالحة',
      'ومنها حديث النزول وهو في الصحيحين من حديث أبي هريرة رضي الله عنه أنه قال ينزل ربنا كل ليلة إلى السماء الدنيا حين يبقى ثلث الليل الآخر يقول من يدعوني فأستجيب له إلى آخره .وهذا الحديث رواه عشرون نفسا من الصحابة رضي الله عنهم .وقد تقدم أنه تستحيل على الله عزوجل الحركة والتنقل والتغير لأن ذلك من صفات الحدث فمن قال ذلك في حقه تعالى فقد ألحقه بالمخلوق وذلك كفر صريح لمخالفة القرآن في تنزيهه لنفسه سبحانه وتعالى',
      'وقال إمامنا الشافعي رضي الله عنه لما سئل عن ذلك (أي آية الإستواء) : آمنت بلا تشبيه وصدقت بلا تمثيل واتهمت نفسي في الإدراك وأمسكت عن الخوض فيه كل الإمساك',
      'قال [يعني الإمام الأشعري] في النوادر: من اعتقد أن الله جسم فهو غير عارف بربه وإنه كافر به، كما في شرح الإرشاد لأبي القاسم الأنصاري',
      'قال العلامة إسماعيل حقي في تفسيره روح البيان : من قال إن الله في السماء إن أراد به المكان كفر وإن أراد به الحكاية عما جاء في ظاهر الأخبار لا يكفر',
      'الفرق بين الرسول والنبى : ان كل من نزل عليه الوحى من الله تعالى على لسان ملك من الملائكة وكان مؤيدا بنوع من الكرامات الناقضة للعادات فهو نبى ومن حصلت له هذه الصفة وخص ايضا بشرع جديد او بفسخ بعض احكام شريعة كانت قبله فهو رسول',
      'و قوله {لِمَا خَلَقْتُ بِيَدَيَّ} أي بقدرتي و نعمتي',
      'قَالَ الشَّافِعِي رضِيَ اللَّهُ عَنْهُ: الْمُحْدَثَاتُ مِنَ الْأُمُورِ ضِرْبَانِ: أَحَدُهُمَا: مَا أُحْدِثَ يُخَالِفُ كِتَابًا أَوْ سَنَةً أَوْ أَثَرًا أَوْ إِجْمَاعًا , فَهَذِهِ لَبِدْعَةُ الضَّلَالَةِ. وَالثَّانِيةُ: مَا أُحْدِثَ مِنَ الْخَيْرِ لَا خِلَافَ فِيهِ لِوَاحِدٍ مِنْ هَذَا , فَهَذِهِ مُحْدَثَةٌ غَيْرُ مَذْمُومَةٍ وَقَدْ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فِي قِيَامِ شَهْرِ رَمَضَانَ: «نِعْمَتِ الْبِدْعَةُ هَذِهِ» يَعْنِي أَنَّهَا مُحْدَثَةٌ لَمْ تَكُنْ',
      'خَرَجْتُ مَعَ عُمَرَ بْنِ الْخَطَّابِ فِي رَمَضَانَ إِلَى الْمَسْجِدِ فَإِذَا النَّاسُ أَوْزَاعٌ مُتَفَرِّقُونَ يُصَلِّي الرَّجُلُ لِنَفْسِهِ وَيُصَلِّي الرَّجُلُ فَيُصَلِّي بِصَلَاتِهِ الرَّهْطُ ، فَقَالَ عُمَرُ : » وَاللَّهِ إِنِّي لَأَرَانِي لَوْ جَمَعْتُ هَؤُلَاءِ عَلَى قَارِئٍ وَاحِدٍ ، لَكَانَ أَمْثَلَ » فَجَمَعَهُمْ عَلَى أُبَيِّ بْنِ كَعْبٍ ، قَالَ : ثُمَّ خَرَجْتُ مَعَهُ لَيْلَةً أُخْرَى وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ قَارِئِهِمْ ، فَقَالَ عُمَرُ : » نِعْمَتِ الْبِدْعَةُ هَذِهِ',
      '« قول عمر: « نعم البدعة » فالبدعة اختراع ما لم يكن قبل، فما خالف السنة فهو بدعة ضلالة، وما وافقها فهو بدعة هُدى »',
      'النور ، معناه الهادى',
      'ف(فوق) : لا يجوز أن تكون للجهة، وإنما هى لعلو القدر والشأن، على حد ما تقول الياقوت فوق الحديد',
      'فيكون ما أجمع عليه أهل الحق من علماء السلف والخلف من تنـزه الحق عن الجهة وتقدسه عن المكان وتعاليه عن التجزؤ والتبعيض والصعود والنـزول والقرب والبعد والذهاب والمجيء والحركة والسكون وما أشبه ذلك',
      '{كل شيء هالك إلا وجهه } أي : إلا هو ، وقيل : إلا ملكه ، قال أبو العالية : إلا ما أريد به وجهه',
      'وروى البيهقي بإسناده في مناقب الشافعي عن الشافعي رضي الله عنه قال : المحدثات من الأمور ضربان، أحدهما ما أُحدث مما يخالف كتابا أو سنة أو أثرا أو اجماعا فهذه البدعة الضلالة، والثانية ما أحدث من الخير لا خلاف فيه لواحد من العلماء وهذه محدثة غير مذمومة، وقد قال عمر رضي الله عنه في قيام شهر رمضان: نعمتُ البدعة هذه، يعني أنها محدثة لم تكن',
      '“عَالِمُ قُرَيْشٍ يَمْلأُ طِبَاقَ الأَرْضِ عِلْمًا”',
      'قال الله عز وجل : {كل شيء هالك إلا وجهه} ؛ وقال : {ويبقى وجه ربك} ؛ المعنى: ويبقى ربك؛ والمعنى: كل شيء هالك إلا الله عز وجل.',
      'إنه سبحانه ليس في مكان من الأمكنة ولا في زمان من الأزمنة، لأن المكان والزمان من جملة المخلوقات وهو سبحانه كان موجودا في الأزل ولم يكن معه شىء من الموجودات',
      'وقلنا المراد بقوله الرحمن على العرش استوى بالقدرة فإن قيل إذا حملتم على القدرة لم يكن لتخصيص العرش فائدة قلنا فائدته أن العرش أعظم المخلوقات فإذا قدر عليه علم من طريق التنبيه أنه قادر على ما هو دونه',
      '« ومعنى «ينزل ربّنا» أي : ينزل أمره أو ملائكته أو رحمته »',
      'لا يجوز عليه التغيير ولا التبديل ولا الانتقال ولا التحريك',
      'النزول بمعنى الحركة والانتقال من علو الى سفل من صفات الحوادث فهو مستحيل في حق الله تعالى و ما ورد مما ظاهره نسبة النزول الى الله تعالى فهو مصروف عن ظاهره بإجماع السلف والخلف',
      '« قَالَ سَعِيدُ بْنُ عَامِرِ بْنِ جُذَيْمٍ : « شَهِدْتُ مَصْرَعَ خُبَيْبٍ، وَقَدْ بَضَعَتْ قُرَيْشٌ لَحْمَهُ ، ثُمَّ حَمَلُوهُ عَلَى جَذْعَةٍ ، فَقَالُوا : أَتُحِبُّ أَنَّ مُحَمَّدًا مَكَانَكَ ؟ فَقَالَ : وَاللَّهِ مَا أُحِبُّ أَنِّي فِي أَهْلِي ، وَوَلَدِي ، وَأَنَّ مُحَمَّدًا شِيكَ بِشَوْكَةٍ ، ثُمَّ نَادَى يَا مُحَمَّدُ »',
      'أخبرنا أبو سعيد الشريحي ، أخبرنا أبو إسحاق الثعلبي ، أخبرني الحسن بن محمد الشيباني أخبرنا محمد بن سليمان بن الفتح الحنبلي ، حدثنا علي بن محمد المصري ، أخبرنا أبو إسحاق بن منصور الصعدي ، أخبرنا العباس بن زفر ، عن أبي جعفر الرازي ، عن أبيه عن الربيع بن أنس ، عن أبي العالية ، عن أبي بن كعب عن النبي – صلى الله عليه وسلم – في قوله : » وأن إلى ربك المنتهى » ، قال : » لا فكرة في الرب » ، وهذا مثل ما روي عن أبي هريرة مرفوعا : » تفكروا في الخلق ولا تتفكروا في الخالق » فإنه لا تحيط به الفكرة .',
      'في الحديث: إِن الله تعالى وتقدّس يَنزِل كل ليلة إِلى سماء الدنيا؛ النُّزول والصُّعود والحركة والسكونُ من صفات الأَجسام، والله عز وجل يتعالى عن ذلك ويتقدّس، والمراد به نُزول الرحمةِ',
      'وأنه لا يحويه مكان في سماواته ولا أرضه، بل هو كما كان قبل خلق المكان، وأنه ليس بجوهر ولا جسم، ولا على صورة ولا شكل، ولا له شبيه ولا مثل، بل هو الأحد الصمد الذي لم يلد ولم يولد، ولم يكن له كفؤا أحد',
      'وليس معنى قول المسلمين: إن الله استوى على العرش هو أنه مماس له أو متمكن فيه أو متحيز في جهة من جهاته لكنه بائن من جميع خلقه، وإنما خبر جاء به التوقيف. فقلنا به، ونفينا عنه التكييف، إذ ليس كمثله شيء وهو السميع البصير',
      'وفي الجملة يجب أن يُعلم أن استواء الله سبحانه وتعالى، ليس باستواء اعتدال عن اعوجاج، ولا استقرار في مكان، ولا مماسة لشيء من خلقه، لكنه مستو على عرشه كما أخبر بلا كيف بلا أين',
      '[عن] قوله تعالى وجاء ربك قال الإمام أحمد معناه جاء أمر ربك',
      '« وعن ابن عَبَّاسٍ ، رَضَيَ اللَّه عنهما ، قال : مَرَّ رسُولُ اللَّهِ صَلّى اللهُ عَلَيْهِ وسَلَّم بِقُبورٍ بالمَدِينَةِ فَأَقْبَلَ عَلَيْهِمْ بوَجْهِهِ فقالَ : « السَّلامُ عَلَيْكُمْ يا أَهْلَ القُبُورِ ، يَغْفِرُ اللَّهُ لَنا وَلَكُمْ ، أَنْتُم سَلَفُنا ونحْنُ بالأَثَرِ » رواهُ الترمذي وقال : حديث حسن»',
      'قال المتكلمون هذه المعية إما بالعلم وإما بالحفظ والحراسة وعلى التقديرين فقد انعقد الإجماع على أنه سبحانه ليس معنا بالمكان والجهة والحيز فإذا قوله (وهو معكم) لا بد فيه من التأويل وإذا جوزنا التأويل في موضع وجب تجويزه في سائر المواضع',
      'ويجبُ له تعالى: السمعُ: المقدَّسُ عن الأُذُنِ والصِماخ.',
      'ويجب الجزم بأنّه تعالى ليس بجسم ولا جوهر ولا عرض ،لا تحلّ به الحوادث ولا يحلّ في حادث ولا ينحصر فيه، فمن اعتقد أنّ الله بذاته في كلّ مكان أو في مكان فهو كافر. بل يجب الجزم بأنّه تعالى بائن من خلقه (أي لا يشبههم)، فالله تعالى كان ولا مكان ثم خلق المكان وهو الآن كما كان قبل خلق المكان',
      'بائن من جميع خلقه، وأن إتيانه ليس بإتيان من مكان إلى مكان وأن مجيئه ليس بحركة وأن نزوله ليس بنقلة وأن نفسه ليس بجسم وأن وجهه ليس بصورة أن يده ليست بجارحة وأن عينه ليست بحدقة، وإنما هذه أوصاف جاء بها التوقيف فقلنا بها ونفينا عنها التكييف. فقد قال الله تعالى : (لَيْسَ كَمِثْلِهِ شَيْء). وقال : (وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَد). وقال : (هَلْ تَعْلَمُ لَهُ سَمِيَّا).',
      'قال الله تعالى :{إِنَّ الله وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى النَّبِيِّ} قال ابن عباس : معناه : إن الله و ملائكته يباركون على النبي .وقيل : إن الله يترحم على النبي ، وملائكته يدعون له .',
      'جل عن التمثيل والتشبيه وعن مكان يستقر فيه لأنه كان ولا مكان في أزل لم يحوه الزمان',
      'ولو قال : لا إله إلا ساكن السماء ، لم يكن مؤمنا ، وكذا لو قال : لا إله إلا الله ساكن السماء ; لأن السكون محال على الله تعالى',
      'فإذا قال لك: أين الله؟ فقل: مع كل أحد بعلمه لا بذاته ، وفوق كل أحد بقدرته، وظاهر بكل شىء باثار صفاته، وباطن بحقيقة ذاته أي لا يمكن تصويره في النفس، منزه عن الجهة والجسمية. فلا يقال: له يمين ولا شمال ولا خلف ولا أمام، ولا فوق العرش ولا تحته، ولا عن يمينه ولا عن شماله، ولا داخل في العالم ولا خارج عنه، ولا يقال: لا يعلم مكانه إلا هو. ومن قال: لا أعرف الله في السماء هو أم في الأرض كفر لأنه جعل أحدهما له مكانا. فإذا قال لك: ما دليلك على ذلك؟ فقل: لأنه لو كان له جهة أو هو في جهة لكان متحيزا، وكل متحيز حادث، والحدوث عليه محال',
      'في قوله تعالى : {يد الله فوق أيديهم} : المراد باليد القدرة',
      'ويستحب زيارة قبر رسول الله صلى الله عليه وسلم لما روى ابن عمر رضي الله عنهما أن النبي صلى الله عليه وسلم قال : { من زار قبري وجبت له شفاعتي }',
      'وإن استواءه ليس باستقرارٍ ولا ملاصقةٍ لأن الاستقرار والـملاصقة صفة الأجسام الـمخلوقة ، والرب عز وجل قديمٌ أزليٌّ',
      'باب ما يقوله إذا خدرت رجله : […] عن الهيثم بن حنش قال : ” كنا عند عبد الله بن عمر رضي الله عنهما فخدرت رجله ، فقال له رجل : اذكر أحب الناس إليك ، فقال : يا محمد صلى الله عليه وسلم ، فكأنما نشط من عقال',
      '[قال الإمام أحمد بن حنبل:] قال الله جلَّ ذكره{وجاء ربك والملك صفا صفا} وإنما تأتي قدرته',
      'والرِّدَّةُ ثَلاثَةُ أقْسامٍ: اعْتِقاداتٌ وأفْعالٌ وأقْوالٌ، وكُلُّ قِسْمٍ يَتَشَعَّبُ شُعَبًا كَثِيرَةً',
      'إذا قال لك قائلٌ: من تعبدُ؟ فقل: أعبدُ اللهَ الذي لا إله إلا هو، الذي ليس متحيزًا في الأرضِ ولا في السماء، كان قبلَ المكانَ والزمان وهو الآن كما كان، لا يُمكن تصويرُهُ في القلب لأنهُ لا شبيه له في الموجوداتِ',
      'منزه عن الحلـــــول والجهــــــه والاتصال الانفصال والسفه',
      'قال تعالى {كُلُّ شَيْءٍ هَالِكٌ إِلاَّ وَجْهَهُ} لا بمعنى الجارحة بل بمعنى الذات أي :إلا ذاته',
      'وإن أصل جميع المخلوقات الماء',
      'قال جعفر بن محمد الصادق عليه السلام : من زعم أن الله تعالى في شىء ، أومن شىء أو على شىء فقد أشرك . لأنه لو كان على شىء لكان محمولا ، ولو كان في شىء لكان محصوراً ، ولو كان من شىء لكان محدثًا (أي مخلوقاً) و الله يتعالى عن جميع ذلك',
      'أَجْمَعَ الْعُلَمَاءُ الَّذِينَ يُعْتَدُّ بِهِمْ عَلَى أَنَّ مَنْ تَرَكَ صَلَاةً عَمْدًا لَزِمَهُ قَضَاؤُهَا',
      'وقوله سبحانه: { ثم استوى على العرش} معناه عند أبي المعالي وغيره من حذاق المتكلمين : الملك والسلطان، وخص العرش بالذكر تشريفاً له إذ هو أعظم المخلوقات',
      'وأثبت اليدين والوجه صفات خبرية فيقول ورد بذلك السمع فيجب الاقرار به كما ورد وصغوه إلى طريقة السلف من ترك التعرض للتأويل وله قول أيضا في جواز التأويل',
      'ومعنى: {بأعيننا} أي بإبصارنا إليك وحفظنا لك',
      'وقوله تعالى {وَجَاءَ رَبُّكَ} معناه جاء أمره و قضاؤه',
      'قاضي مكة العالم الصالح العابد نجم الدين محمد بن إمام العالم محيي الدين الطبري، وهو فاضل كثير الصدقات والمؤاساة للمجاورين، حسن الأخلاق كثير الطواف والمشاهدة للكعبة الشريفة، يطعم الطعام الكثير في المواسم المعظمة، وخصوصًا في مولد رسول الله صلى الله عليه وسلم، فإنه يطعم فيه شرفاء مكة وكبراءها وفقراءها وخدام الحرم الشريف وجميع المجاورين.',
      'إنَّه (أي الله) ليس بجسمٍ ولا عَرَضٍ ولا في مكانٍ ولا زمان',
      '« وقد سئل شيخ الإسلام حافظ العصر أبو الفضل ابن حجر عن عمل المولد ، فأجاب بما نصه :',
      'أصل عمل المولد بدعة لم تنقل عن أحد من السلف الصالح من القرون الثلاثة ، ولكنها مع ذلك قد اشتملت على محاسن وضدها ، فمن تحرى في عملها المحاسن وتجنب ضدها كان بدعة حسنة وإلا فلا ، قال : وقد ظهر لي تخريجها على أصل ثابت وهو ما ثبت في الصحيحين من أن النبي صلى الله عليه وسلم قدم المدينة فوجد اليهود يصومون يوم عاشوراء ، فسألهم فقالوا : هو يوم أغرق الله فيه فرعون ونجى موسى فنحن نصومه شكرا لله تعالى ، فيستفاد منه فعل الشكر لله على ما من به في يوم معين من إسداء نعمة أو دفع نقمة ، ويعاد ذلك في نظير ذلك اليوم من كل سنة ، والشكر لله يحصل بأنواع العبادة كالسجود والصيام والصدقة والتلاوة ، وأي نعمة أعظم من النعمة ببروز هذا النبي نبي الرحمة في ذلك اليوم ؟ وعلى هذا فينبغي أن يتحرى اليوم بعينه حتى يطابق قصة موسىفي يوم عاشوراء ، ومن لم يلاحظ ذلك لا يبالي بعمل المولد في أي يوم من الشهر ، بل توسع قوم فنقلوه إلى يوم من السنة ، وفيه ما فيه . فهذا ما يتعلق بأصل عمله . وأما ما يعمل فيه فينبغي أن يقتصر فيه على ما يفهم الشكر لله تعالى من نحو ما تقدم ذكره من التلاوة والإطعام والصدقة وإنشاد شيء من المدائح النبوية والزهدية المحركة للقلوب إلى فعل الخير والعمل للآخرة »',
      'وأن من لم يكفر من دان بغير الإسلام كالنصارى ، أو شك في تكفيرهم ، أو صحح مذهبهم ، فهو كافر ، وإن أظهر مع ذلك الإسلام واعتقده',
      'يجوز التوسل بالرجل الصالح على الصحيح من المذهب، وقيل: يُستحب. قال الإمام أحمد للمروذي : يتوسل بالنبي (صلى الله عليه وسلم) في دعائه وجزم به في المستوعب وغيره.',
      '« وكيف يمكن أن يقال إن السلف ما استعملوا التأويل وقد ورد في الصحيح عن سيد الكونين صلى الله عليه وسلم أنه قدّم له ابن عباس وَضوءه فقال:{ من فعل هذا}, فقال: قلت: أنا يا رسول الله, فقال:{ اللهم فقّهه في الدين وعلّمه التأويل} , فلا يخلو إما أن يكون الرسول أراد أن يدعو له أو عليه, فلا بد أن تقول أراد الدعاء له لا دعاءً عليه, ولو كان التأويل محظورا لكان هذا دعاء عليه لا له. ثم أقول: لا يخلو إما أن تقول: إن دعاء الرسول ليس مستجابا فليس بصحيح, وإن قلت: إنه مستجاب فقد تركت مذهبك وبَطَل قولك: إنهم ما كانوا يقولون بالتأويل,',
      'وكيف والله يقول:{ وَمَا يَعْلَمُ تَأْوِيلَهُ إِلاَّ اللهُ وَالرَّاسِخُونَ فِي الْعِلْمِ يَقُولُونَ ءامَنَّا بِهِ}(7)[سورة ءال عمران] »',
      'اللهم فقِّهْهُ قي الدين وعلِّمهُ التأويلَ',
      'باب ما يقوله إذا خدرت رجله : روينا في كتاب ابن السني عن الهيثم بن حنش قال : » كنا عند عبد الله بن عمر رضي الله عنهما فخدرت رجله ، فقال له رجل : اذكر أحب الناس إليك ، فقال : يا محمد صلى الله عليه وسلم ، فكأنما نشط من عقال',
      'عمل المولد وإن حدث بعد السلف الصالح ليس فيه مخالفة لكتاب الله ولا لسنة رسوله صلى الله تعالى عليه وسلم ولا لإجماع المسلمين، فلا يقول من له مسكة من عقل ودين بأنه مذموم',
      'وَالْكَلامُ الذي لَيْسَ بِحَرْفٍ، وَلاَ صَوْتٍ',
      'وعن علي رضي الله عنه : سيرجعُ قومٌ من هذهِ الأمّةِ عندَ اقتراب السّاعةِ كفّارًا ، قال رجلٌ يا أميرَ المؤمنينَ ، كفرهم بماذا أبِالإحداثِ أم بالإنكارِ ، قال بل بالإنكارِ ، يُنكرونَ خالِقَهُم فيَصِفونهُ بالجِسمِ والأعضاءِ',
      'فمَن شبّهه بخَلقِه فقَد كفَر كمَن اعتَقدَه جِسمًا أو قالَ إنّه جِسمٌ لا كالأجسام',
      'والله تعالى عالٍ على كل شَىء ، وليس الـمراد بالعلو ارتفاع الـمحلِّ ، لأن الله تعالى يجلُّ عن الـمحلِّ والـمكان ، وإنَّما العُلو علوُّ الشأن وارتفاعُ السلطان',
      'غرض البخاري في هذا الباب الرد على الجهمية المجسمة في تعلقها بهذه الظواهر وقد تقرر أن الله ليس بجسم فلا يحتاج الى مكان يستقر فيه فقد كان ولا مكان وانما أضاف المعارج اليه إضافة تشريف ومعنى الارتفاع اليه اعتلاؤه مع تنزيهه عن المكان',
      'وهذا مُنتَظمٌ مَن كفرُهُ مُجمَعٌ عَليهِ ومَن كفَّرناهُ مِن أهلِ القِبلةِ كالقائلينَ بِخَلقِ القُرءآنِ وَبأنَّهُ لايَعلَمُ المَعدوماتِ قَبلَ وُجودِها ومَن لايُؤمِنُ بالقَدرِ وكذا مَن يَعتقدُ أنَّ اللهَ جالسٌ على العَرشِ كما حَكاهُ القاضي حُسَينُ عن نَصِّ الشَّافِعيِّ',
      'حدثنا القاضي أبو علي ، قال : حدثنا أبو الفضل بن خيرون ، قال : حدثنا الحسن بن جعفر ، قال : حدثنا أبو الحسن علي بن عمر الدارقطني ، قال : حدثنا القاضي المحاملي ، قالا : حدثنا محمد بن عبد الرزاق ، قال : حدثنا موسى بن هلال ، عن عبد الله بن عمر ، عن نافع ، عن ابن عمر – رضي الله عنهما – ، قال : قال النبي – صلى الله عليه وسلم – من زار قبري وجبت له شفاعتي .',
      'العلي: هو فَعِيل في معنى فاعل، فالله تعالى عالٍ على خَلْقِه وهو عليٌّ عليهم بقدرته، ولا يجب أن يُذهَب بالعلو ارتفاع مكانٍ، إذ قد بيَّنَّا أن ذلك لا يجوز في صفاته تقدست، ولا يجوز أن يكون على أن يُتصور بذهن، تعالى الله عن ذلك عُلوًّا كبيرًا',
      '« [عن قول مالك لذاك الرجل « صاحب بدعة » : ] لأن سؤاله عن كيفية الاستواء يدل على أنه فهم الاستواء على معناه الظاهر الحسي الذي هو من قبيل تمكن جسم على جسم واستقراره عليه، وإنما شك في كيفية هذا الاستقرار. فسأل عنها، وهذا هو التشبيه بعينه الذي أشار إليه الإمام بالبدعة »',
      'معنى العبادة في اللغة الطاعة مع الخضوع',
      'وإن نواه أي صوم يوم الثلاثين من شعبان بلا مستند شرعيّ من رؤية هلاله أو إكمال شعبان أو حيلولة غيم أو قتر ونحوه ان صامه لحساب ونجوم ولو كثرت إصابتهما أو مع صحو فبان منه لم يجزئه صومه لعدم استناده لما يعوّل عليه شرعًا',
      '… ويسمى الاعتقاد الفاسد كاعتقاد قدم العالم أو تعدد الاله أو أن الله تعالى جسم، وصاحب هذا الاعتقاد مجمع على كفره',
      'يَجِبُ أن يكونَ تفسيرُ هذه الآية بغيرِ الاستِقْرارِ والجلُوسِ ونحوِ ذلكَ ويَكْفُر منْ يعتَقِدُ ذَلِكَ، فَيَجِبُ تَركُ الحَمْلِ علَى الظّاهِر بَلْ يُحمَلُ على مَحْمِلٍ مُسْتَقِيمٍ في العُقُولِ فتُحمَلُ لفْظَةُ الاسْتِواءِ علَى القَهْرِ ففي لُغَةِ العَرَبِ يُقَالُ اسْتَوى فُلانٌ على المَمَالِكِ إذَا احْتَوَى علَى مَقَالِيدِ المُلْكِ واسْتَعْلَى علَى الرّقَابِ كَقَوْلِ الشَّاعِرِ: [الزجر] قَد اسْتَوَى بِشْرٌ علَى العِراقِ مِنْ غَيْرِ سَيْفٍ ودَمٍ مُهْراقِ',
      'وفَائِدَةُ تَخْصِيص العَرْشِ بالذّكْرِ أنَّهُ أعْظَمُ مَخلُوقَاتِ الله تَعَالى حجمًا فيُعْلَمُ شُمُولُ ما دُوْنَه مِنْ بَابِ الأَوْلَى. قَالَ الإمَامُ عَلِيٌّ: « إنَّ الله تَعَالى خَلَقَ العَرْشَ إِظْهَارًا لقُدْرَتِهِ، ولمْ يَتّخِذْهُ مَكَانًا لِذَاتِهِ »، رواهُ الإمامُ المحدثُ الفقيهُ اللغويُّ أبو منصورٍ التميميُّ في كتابهِ الفرق بين الفرق، أَوْ يُقَالُ اسْتَوَى اسْتِوَاءً يَعْلَمُهُ هُوَ مَع تَنزِيْهِهِ عن اسْتِواءِ المخْلُوقِيْنَ كَالجُلوسِ والاسْتِقرارِ.',
      'واعْلَم أَنَّه يَجِبُ الحَذَرُ مِنْ هؤلاءِ الذينَ يُجِيزُوْنَ علَى الله القُعُودَ علَى العَرْشِ والاسْتِقْرارَ عليه مُفَسّرينَ لِقَوله تعالى: ﴿الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى (5)﴾ بالجُلُوسِ أو المحاذاةِ من فوق، ومُدَّعِينَ أَنَّه لا يُعْقَلُ مَوْجُودٌ إلا في مَكَانٍ، وحُجَّتُهم دَاحِضَةٌ، ومُدَّعِيْنَ أيضًا أنَّ قَوْلَ السَّلَفِ اسْتَوى بلا كَيْفٍ مُوافِقٌ لذَلِكَ وَلم يَدْرُوا أنَّ الكَيْفَ الذي نَفاهُ السَّلَفُ هُوَ الجُلُوسُ والاسْتِقْرارُ والتّحَيُّزُ في المَكَانِ والمُحَاذاةُ وكلُّ الهيئاتِ من حركةٍ وسكونٍ وانتقالٍ. »',
      'وحدثني مالك عن بن شهاب عن عبيد الله بن عبد الله بن عتبة بن مسعود أن رجلا من الأنصار جاء إلى رسول الله صلى الله عليه وسلم بجارية له سوداء فقال يا رسول الله ان علي رقبة مؤمنة فإن كنت تراها مؤمنة اعتقها فقال لها رسول الله صلى الله عليه وسلم أتشهدين أن لا إله إلا الله قالت نعم قال أتشهدين أن محمدا رسول الله قالت نعم قال أتوقنين بالبعث بعد الموت قالت نعم فقال رسول الله صلى الله عليه وسلم اعتقها',
      'علي رضي الله عنه قال : لما رمس رسول الله صلى الله عليه وسلم جاءت فاطمة رضي الله عنها فوقفت على قبره وأخذت قبضة من تراب القبر ووضعته على عينيها وبكت وأنشأت تقول: ماذا على من شم تربة أحمد ; أن لا يَشُمَّ مدى الزمان غَوَالَيَا ; صُبَّتْ عَليَّ مصائبٌ لو أنها ; صُبَّت على الأيام عُدْنَ لَيَالِيَا',
      'قال الباجي : وإجماع السلف الصالح حجة عليهم',
      '« فَعَلَّقَ (النبيُّ) الْحُكْمَ بِالصَّوْمِ وَغَيْرِهِ بِالرُّؤْيَةِ (في حديث: صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ) لِرَفْعِ الْحَرَجِ عَنْهُمْ فِي مُعَانَاةِ حِسَابِ التَّسْيِيرِ (أي حِساب تسيير النجوم والقمر) وَاسْتَمَرَّ الْحُكْمُ فِي الصَّوْمِ وَلَوْ حَدَثَ بَعْدَهُمْ مَنْ يَعْرِفُ ذَلِكَ (أي مِن الحُسّاب والمنجِّمين ونحوهم) بَلْ ظَاهِرُ السِّيَاقِ يُشْعِرُ بِنَفْيِ تَعْلِيقِ الْحُكْمِ بِالْحِسَابِ أَصْلًا وَيُوَضِّحُهُ قَوْلُهُ فِي الْحَدِيثِ الْمَاضِي: « فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ ثَلَاثِينَ وَلَمْ يَقُلْ فَسَلُوا أَهْلَ الْحِسَابِ » »',
      'الباب الخامس عشر في بيان اعتقاد أهل السنة والجماعة : وأن تَعلـم أن كل ما دل على حدوث شىءٍ من الحد ، والنهاية ، والـمكان ، والجهة ، والسكون ، والحركة ، فهو مستحيل عليه سبحانه وتعالى ، لأن ما لا يكون محدَثاً لا يجوز عليه ما هو دليل على الحدوث',
      'والاستواء: الاستيلاء، ولم يـزل الله سبحانه مستوليا على الأشياء كلها، إلا أن تخصيص العرش لتعظيم شأنه',
      'والله تعالى نفى المماثلة بين ذاته وبين غيره من الأشياء، فيكون القول باثبات المكان له ردا لهذا النص المحكم- أي قوله تعالى ﴿ليس كمثله شيء﴾ – الذي لا احتمال فيه لوجهٍ ما سوى ظاهره، ورادُّ النص كافر، عصمنا الله عن ذلك',
      'وقد وصف الشافعي رضي الله عنه توبته (أي المرتد) فقال: أن يشهد أن لا إله إلا الله، وأن محمدا رسول الله، ويبرأ من كل دين خالف الاسلام',
      'أو فعل يتضمنه كإلقاء مصحف بقذر',
      'قال الشهاب القرافي عن سند : لو كان إمام يرى الحساب فأثبت به الهلال لم يتبع لإجماع السلف على خلافه',
      'وقالوا: معنى استوى استولى',
      'وَلَوْ كَتَبَ الْقُرْآنَ فِي إنَاءٍ ثُمَّ غَسَلَهُ وَسَقَاهُ الْمَرِيضَ فَقَالَ الْحَسَنُ الْبَصْرِيُّ وَمُجَاهِدٌ وَأَبُو قِلَابَةَ وَالْأَوْزَاعِيُّ لَا بَأْسَ بِهِ',
      'وَنُنَزِّلُ مِنَ الْقُرْآنِ مَا هُوَ شِفَاء وَرَحْمَةٌ لِّلْمُؤْمِنِينَ وَلاَ يَزِيدُ الظَّالِمِينَ إَلاَّ خَسَاراً',
      'قديم لا أوّل له ، باقٍ لا آخِرَ لهُ ، مُخَالفٌ للحوادثِ ، ما هو بجرمٍ، ولا صفَةٍ للْجِرمِ، ولا جهةَ لهُ ولا مكانَ لهُ ، غَنِيٌّ عنِ المَحَلِّ والمُخَصِّصِ، قائم بنفسهِ',
      'ولا تقبل شهادة المجسمة لأنهم كفرة',
      'واحتاط بعضهم أكثر احتياط حتى لم يقرأ اليد بالفارسية ولا الوجه ولا الاستواء ولا ما ورد من جنس ذلك بل إن احتاج في ذكرها إلى عبارة عبر عنها بما ورد : لفظا بلفظ . فهذا هو طريق السلامة وليس هو من التشبيه في شيء',
      'قال المتولي : […] أو أثبت ما هو منفي عنه بالاجماع، كالالوان، أو أثبت له الاتصال والانفصال، كان كافرا',
      'ومن كفرناه من اهل القبلة القائلين بخلق القرءان وبأنه لا يعلم المعدومات قبل وجودها ومن لا يؤمن بالقدر وكذا من يعتقد ان الله جالس على العرش كما حكاه القاضي حسين هنا عن نص الشافعي',
      'وسمعت الإِمَام أبا بَكْر بْن فورك رحمه اللَّه تعالي يَقُول : سمعت أبا عُثْمَان المغربي يَقُول : كنت أعتقد شَيْئًا من حَدِيث الجهة فلما قدمت بغداد زال ذَلِكَ عَن قلبي فكتبت إِلَى أَصْحَابنا بمكة إني أسلمت الآن إسلاما جديدا.',
      'أخبرنا محمد بن أبي بكر الحافظ قال، أخْبَرَنا أبو الفضل أحمد بن إبراهيم بن أحمد البلخي من أصل كتابه أخبرنا جعفر بن محمد بوران الحكاك ببلخ، حَدَّثَنا سليمان بن داود الهروي، حَدَّثَنا إسحاق بن منصور، حَدَّثَنا أبو داود الطيالسي، حَدَّثَنا شعبة، حَدَّثَنا مالك بن أنس عن ابن شهاب قال: دخلت على أنس بن مالك فرأيته يعلق التعويذ على ابن له فقلت له: ياأبا حمزة هل نزل به بلاء؟ قال: لا ثم ضرب بيده على منكبي فقال: يا أبا بكر سمعت رسول الله صلى الله عليه وسلم يقول: لا بأس بتعليق التعويذ من القرآن قبل نزول البلاء وبعد نزول البلاء.',
      'وسواء كفر بقول صريح في الكفر كقوله كفرت بالله أو برسول الله أو بالقرآن أو الإله اثنان أو ثلاثة أو المسيح ابن الله أو العزيز ابن الله أو بلفظ يقتضيه أي يستلزم اللفظ الكفر استلزاما بينا كجحد مشروعية شيء مجمع عليه معلوم من الدين ضرورة ، فإنه يستلزم تكذيب القرآن أو الرسول، وكاعتقاد جسمية الله وتحيزه، فإنه يستلزم حدوثه واحتياجه لمحدِث',
      'و قال رجل لمالك : » يا أبا عبد الله { الرحمن على العرش استوى } كيف استوى ؟ قال : الاستواء غير مجهول و الكيف منه غير معقول و السؤال عنه بدعة و الإيمان به واجب ، و أراك صاحب بدعة ، أخرجوه',
      'وفيه أن من المسلمين من يخرج من الدين من غير أن يقصد الخروج منه ومن غير أن يختار دينًا على دين الإسلام',
      'إِنَّ العَبْدَ لَيَتَكَلَّمُ بِالكَلِمَةِ لا يَرىَ بِهَا بَأْساً يَهْوِي بِهَا فِي النَّارِ سَبْعِينَ خَرِيفاً',
      'المُجسّمة كفّار لأنهم اعتقدوا أنّ كلّ ما لا يكون متحيزاً ولا في جهة فليس بموجود ونحن نعتقد أنّ كلّ متحيّز فهو مُحْدَثٌ وخالقه موجود ليس بمُتحيّز ولا في جهة فالمُجسّمة نَفَوا ذات الشىء الذي هو الإله فيلزمهم الكفر',
      'وهذا الأذان الثاني أحدثه بنو أمية',
      'أعني بالجسم عبارة عن مقدار له طول وعرض وعمق',
      'من عبد جسمًا فهو كافر بإجماع الأئمة السلف منهم والخلف',
      'فترى أقواماً يسمعون أخبار الصفات فيحملونَها على ما يقتضيه الحس ، كقول قائلهم : ينـزل بذاته إلى السماء ويتنقل ، وهذا فهم ردىء ، لأن الـمتنقـل يكون من مكان إلى مكان ، ويوجب ذلك كون الـمكان أكبر منه ، ويلزم منه الحركة ، وكل ذلك محال على الحق عزَّ وجلَّ',
      'ينـزل ربنا إلى سماء الدنيا',
      'أَخْبَرَنَا أَبُو زَكَرِيَّا بْنُ أَبِي إِسْحَاقَ، وَأَبُو بَكْرِ بْنُ الْحَسَنِ قَالَا: ثنا أَبُو الْعَبَّاسِ الْأَصَمُّ، ثنا بَحْرُ بْنُ نَصْرٍ، ثنا ابْنُ وَهْبٍ، أَخْبَرَنِي نَافِعُ بْنُ يَزِيدَ، أَنَّهُ سَأَلَ يَحْيَى بْنَ سَعِيدٍ عَنِ الرُّقَى وَتَعْلِيقِ الْكُتُبِ، فَقَالَ: كَانَ سَعِيدُ بْنُ الْمُسَيِّبِ يَأْمُرُ بِتَعْلِيقِ الْقُرْآنِ وَقَالَ: لَا بَأْسَ بِهِ. قَالَ الشَّيْخُ رَحِمَهُ اللهُ: وَهَذَا كُلُّهُ يَرْجِعُ إِلَى مَا قُلْنَا مِنْ أَنَّهُ إِنْ رَقَى بِمَا لَا يُعْرَفُ أَوْ عَلَى مَا كَانَ مِنْ أَهْلِ الْجَاهِلِيَّةِ مِنْ إِضَافَةِ الْعَافِيَةِ إِلَى الرُّقَى لَمْ يَجُزْ , وَإِنْ رَقَى بِكِتَابِ اللهِ أَوْ بِمَا يُعْرَفُ مِنْ ذِكْرِ اللهِ مُتَبَرِّكًا بِهِ وَهُوَ يَرَى نُزُولَ الشِّفَاءِ مِنَ اللهِ تَعَالَى فَلَا بَأْسَ بِهِ، وَبِاللهِ التَّوْفِيقُ.',
      'ولا بأس بالاكتواء والرقى بكتاب الله وبالكلام الطيب. ولا بأس بالمعاذة تعلق، وفيها القرآن',
      'ولو قال كافر لمسلم : اعرض علي الإسلام ، فقال : حتى أرى ، أو اصبر إلى الغد ، أو طلب عرض الإسلام من واعظ ، فقال : اجلس إلى آخر المجلس ، كفر. وقد حكينا نظيره عن المتولي',
      'قال السخاوي : عمل المولد حدث بعد القرون الثلاثة ثم لا زال أهل الإسلام في سائر الأقطار والمدن الكبار يعملون المولد ويتصدقون في لياليه بأنواع الصدقات ويعتنون بقراءة مولده الكريم ويظهر عليهم من بركاته كل فضل عميم',
      '«وفي الحديث : « من تقرب إلي شبرا تقربت إليه ذراعا ». المراد بقرب العبد من الله تعالى القرب بالذكر والعمل الصالح لا قرب الذات والمكان لأن ذلك من صفات الأجسام والله يتعالى عن ذلك ويتقدس »',
      'من تقرب إلي شبرا تقربت إليه ذراعا',
      'قَالَ أَبُو سُلَيْمَانَ فِيمَا أُخْبِرْتُ عَنْهُ : وَلا يَجُوزُ أَنْ يُتَوَهَّمَ أَنَّ اللَّهَ سُبْحَانَهُ وَتَعَالَى نُورٌ مِنَ الأَنْوَارِ ، فَإِنَّ النُّورَ تُضَادُّهُ الظُّلْمَةُ وَتُعَاقِبُهُ فَتُزِيلُهُ , وَتَعَالَى اللَّهُ أَنْ يَكُونَ لَهُ ضِدٌّ أَوْ نِدٌّ',
      'الاحتفال بالمولد : و لا زال أهل الإسلام يحتفلون بشهر مولده ـ عليه السَّلام ـ ، ويعملون الولائم ويتصدقون في لياليه بأنواع الصدقات،ويظهرون السرور، ويزيدون في المبرات ويعتنون بقراءة مولده الكريم. ويظهر عليهم من بركاته كل فضل عميم',
      'اعلم أن الصحابة رضوان الله عليهم كانوا يتبركون بآثار النبي صلى الله عليه وسلم في حياته وبعد مماته ولا زال المسلمون بعدهم إلى يومنا هذا على ذلك وجواز هذا الأمر يعرف من فعل النبي صلى الله عليه وسلم وذلك أنه صلى الله عليه وسلم قسم شعره حين حلق في حجة الوداع و أظفاره',
      'قال الإمام أبو شامة شيخ النووي : ومن أحسن ما إبتدع في زماننا ما يفعل كل عام في اليوم الموافق ليوم مولده صلى الله عليه و سلم من الصدقات والمعروف ، وإظهار الزينة والسرور ، فإن ذلك – مع ما فيه من الإحسان للفقراء – مشعر بمحبة النبي صلى الله عليه و سلم وتعظيمه في قلب فاعل ذلك وشكر الله تعالى على ما من به من إيجاد رسول الله صلى الله عليه و سلم الذي أرسله رحمة للعالمين.',
      '[…] والكلام كله في مبتدع لا يكفر ببدعته أما من كفر بها كمنكر العلم بالجزئيات، وزاعم التجسيم أو الجهة أو الكون أو الاتصال بالعالم أو الانفصال عنه فلا يوصف عمله بقبول ولا رد لأنه أحقر من ذلك',
      'من يدخل الجنة يَنعَم لا ييْأس، لا تبلى ثيابه، ولا يفنى شبابه',
      'البارئ تعـالى يتقدس عن أن يُحَدَّ بالجهــــات أو أن تكتنفه الأقطار',
      '« فائدة : جرت العادة أن الناس إذا سمعوا ذكر وضعه صلى الله عليه و سلم يقومون تعظيماً له صلى الله عليه و سلم ، وهذا القيام مستحسن لما فيه من تعظيم النبي صلى الله عليه و سلم ، وقد فعل ذلك كثير من علماء الأمة الذين يقتدى بهم. قال الحلبي في السيرة : فقد حكى بعضهم أن الإمام السبكي إجتمع عنده كثير من علماء عصره فأنشد منشده قول الصرصري في مدحه صلى الله عليه و سلم:',
      'قليل لمدح المصطفى الخط بالذهب * على ورق من خط أحسن من كتب وأن تنهض الأشراف عند سماعه * قياماً صفوفاً أو جثياً على الركب',
      'فعند ذلك قام الإمام السبكي وجميع من بالمجلس ، فحصل أنس كبير في ذلك المجلس ، وعمل المولد وإجتماع الناس له كذلك مستحسن.»',
      'الله سبحانه وتعالى هادي أهل السماوات والأرض',
      'وأما البراءة من التشبيه بإثبات أنه ليس بجوهر ولا عرض فلأن قوما زاغوا عن الحق فوصفوا الباري جل وعز ببعض صفات المحدثين ، فمنهم من قالك إنه جوهر، ومنهم من قال إنه جسم، ومنهم من أجاز أن يكون على العرش قاعدا كما يكون الملك على سريره وكل ذلك في وجوب اسم الكفر لقائله كالتعطيل والتشريك',
      'إبليس رن أربع رنات رنة حين لعن ورنة حين أهبط ورنة حين ولد رسول الله صلى الله عليه و سلم ورنة حين أنزلت فاتحة الكتاب',
      'قال الحافظ أبو الخير السخاوي رحمه الله تعالى في فتاويه : عمل المولد الشريف لم ينقل عن أحد من السلف الصالح في القرون الثلاثة الفاضلة، وإنما حدث بعد، ثم لا زال أهل الإسلام في سائر الأقطار والمدن الكبار يحتفلون في شهر مولده صلى الله عليه وسلم بعمل الولائم البديعة، المشتملة على الأمور البهجة الرفيعة، ويتصدقون في لياليه بأنواع الصدقات، ويظهرون السرور ويزيدون في المبرات، ويعتنون بقراءة مولده الكريم، ويظهر عليهم من بركاته كل فضل عميم',
      'فصل في الاحتفال بالمولد الشريف، وذكر أدلة جوازه : من البدع الحسنة الاحتفال بمولد رسول الله صلى الله عليه وسلم، فهذا العمل لم يكن في عهد النبي صلى الله عليه وسلم ولا فيما يليه، إنما أحدث في أوائل القرن السابع للهجرة، وأول من أحدثه ملك إربل وكان عالمًا تقيًّا شجاعًا يقال له المظفر. جمع لهذا كثيرًا من العلماء فيهم من أهل الحديث والصوفية الصادقين. فاستحسن ذلك العمل العلماء في مشارق الأرض ومغاربها، منهم الحافظ أحمد بن حجر العسقلاني، وتلميذه الحافظ السخاوي، وكذلك الحافظ السيوطي وغيرهم',
      'سئلت عن أصل عمل المولد الشريف. فأجبت: لم ينقل عن أحد من السلف الصالح في القرون الثلاثة الفاضلة، وإنما حدث بعد، ثم ما زال أهل الإسلام في سائر الأقطار والمدن العظام يحتفلون في شهر مولده صلى الله عليه وسلم وشرف وكرم يعملون الولائم البديعة المشتملة على الأمور البهجة الرفيعة، ويتصدقون في لياليه بأنواع الصدقات، ويظهرون السرور، ويزيدون في المبرات بل يعتنون بقراءة مولده الكريم وتظهر عليهم من بركاته كل فضل عميم',
      'ولا يجوز أن يثبت له كيفية لأن الشرع لم يرد بذلك، ولا أخبر النبي عليه السلام فيه بشىء، ولا سألته الصحابة عنه، ولأن ذلك يرجع إلى التنقل والتحول وإشغال الحيّز والافتقار إلى الأماكن وذلك يؤول إلى التجسيم وإلى قِدم الأجسام وهذا كفرعند كافة أهل الإسلام',
      'وكذا إذا قيل لرجل : ألا تخشى الله تعالى ؟ فقال في حالة الغضب : لا، يصير كافرًا كذا في فتاوى قاضيخان',
      'والله تعَالى غَنِيٌّ عن العَالمينَ أي مُسْتَغنٍ عَن كُلّ ما سِوَاهُ أَزَلا وأَبَدًا فَلا يَحْتَاجُ إلى مَكَانٍ يتحيز فيه أو شَىءٍ يَحُلُّ به أو إلى جِهَةٍ لأنه ليس كشىءٍ منَ الأشياء ليس حجمًا كثيفًا ولا حجمًا لطيفًا والتحيزُ من صفاتِ الجسمِ الكثيفِ واللطيفِ فالجسمُ الكثيفُ والجسمُ اللطيفُ متحيزٌ في جهةٍ ومكانٍ قال الله تعالى: ﴿وَهُوَ الَّذِي خَلَقَ اللَّيْلَ وَالنَّهَارَ وَالشَّمْسَ وَالْقَمَرَ كُلٌّ فِي فَلَكٍ يَسْبَحُونَ (33)﴾ [سورة الأنبياء] فأثبتَ الله تعالى لكل من الأربعة التحيز في فلكه وهو المدار. ويَكفِي في تَنزِيهِ الله عن المَكَانِ والحَيّزِ والجِهَةِ قَولُه تَعالى: ﴿لَيْسَ كَمِثْلِهِ شَىْءٌ (11)﴾ [سورة الشورى] لأنه لَو كَانَ لَه مَكانٌ لَكَانَ لَهُ أَمثَالٌ وأبعَادٌ طُولٌ وعَرْضٌ وعُمْقٌ، ومَنْ كَانَ كذَلِكَ كَانَ مُحْدَثًا مُحْتَاجًا لِمَنْ حَدَّهُ بِهَذَا الطُّولِ وبِهَذَا العَرْضِ وبِهَذَا العُمْقِ، هذَا الدليلُ منَ القُرءانِ.',
      'أما احتفالنا بذكرى مولده فإنا لم نفعل غير ما فعله حسان بن ثابت رضي الله عنه حين كان يجلس إليه الناس و يُسمعهم مديح رسول الله صلى الله عليه و سلم في شعر, و لم نفعل غير ما فعل علي بن أبي طالب أو البراء بن عازب أو أنس بن مالك رضي الله عنهم حين يتحدثون عن محاسن رسول الله الخُلقية و الخلقية في جماعة',
      'موجودٌ قبل الخلقِ، ليس له قبلٌ ولا بعدٌ، ولا فوقٌ ولا تحتٌ، ولا يَمينٌ ولا شمالٌ، ولا أمامٌ ولا خلفٌ، ولا كلٌّ، ولا بعضٌ. ولا يقالُ متى كانَ ولا أينَ كانَ ولا كيفَ، كان ولا مكان، كوَّنَ الأكوانَ ودبَّر الزمانَ، لا يتقيَّدُ بالزمانِ ولا يتخصَّصُ بالمكان، ولا يشغلُهُ شأنٌ عن شأن، ولا يلحقُهُ وهمٌ، ولا يكتَنِفُهُ عقلٌ، ولا يتخصَّصُ بالذهنِ، ولا يتمثلُ في النفسِ، ولا يتصورُ في الوهمِ، ولا يتكيَّفُ في العقلِ، لا تَلحقُهُ الأوهامُ والأفكارُ، » لَيْسَ كَمِثلِهِ شَىءٌ وَهُوَ السَّمِيعُ البَصِيرُ »',
      'وهو الهادي لا يعلم العباد إلا ما علمهم ولا يدركون إلا ما يسر لهم إدراكه ، فالحواس والعقل فطرته وخلقه وعطيته',
      'كان الله ولـم يكن شىءٌ غيره فلـم يكن زمانٌ ولا مكان ولا قُطْرٌ ولا أوانٌ ، ولا عرشٌ ولا ملكٌ ، ولا كوكبٌ ولا فلكٌ ، ثم أوجد العالـم من غير احتياجٍ إليه ، ولو شاء ما أوجده . فهذا العالـم كله بما فيه من جواهر وأعراض حادثٌ عن عدم ، ليس فيه شائبة من قِدم ، حسبما اقتضته قضايا العقول ، وأيدته دلائل النقول ، أجمع عليه الـملِّيُّون قاطبةً إلاّ شُذاذاً من الفلاسفة قالوا بقدم العالـم ، وهم كفار بلا نزاع',
      '« عن عمر بن الخطاب رضي الله عنه قال: قال رسول الله (صلى الله عليه وسلم): « لما اعترف آدم عليه السلام بالخطيئة قال: يا رب أسألك بحق محمد لما غفرت لي. فقال الله: يا آدم، وكيف عرفت محمدا ولم أخلقه؟ قال: يا رب لأنك لما خلقتني بيدك، ونفخت فيّ من روحك رفعت رأسي، فرأيت على قوائم العرش مكتوبا: (لا إله إلا الله، محمد رسول الله) فعرفت أنك لم تضف إلى اسمك إلا أحب الخلق إليك، فقال الله: صدقت يا آدم، إنه لأحب الخلق إليّ، إذ سألتني بحقه فقد غفرت لك، ولولا محمد ما خلقتك ». قال الحاكم: هذا حديث صحيح الإسناد »',
      '{وَجَاءَ رَبُّكَ} أي أمره و قضاؤه. قاله الحسن ، وهو من باب حذف المضاف',
      'والله جل ثناؤه لا يوصف بالتحول من مكانٍ إلى مكانٍ ، وأنَّى له التحول والانتقال ولا مكان له ولا أوان ، ولا يجري عليه وقتٌ ولا زمــان ، لأن في جريان الوقت على الشىء فــوت الأوقات ، ومن فــاته شىء فهو عاجز',
      'ليس – أي الله – بجسم مصوَّر ، ولا جوهرٍ محدودٍ مقدَّرٍ ، ولا يُشبه شيئاً، ولا يُشبهه شىءٌ ، ولا تحيط به الجهات ، ولا تكتنفه الأرضون ولا السموات ، كان قبل أن كوَّن الـمكان ودبَّر الزمان ، وهو الآن على ما عليه كان',
      'حدثني عليّ، قال: ثنا أبو صالح، قال: ثنا معاوية، عن ابن عباس، قوله { يَوْمَ يُكْشَفُ عَن ساقٍ } هو الأمر الشديد المفظع من الهول يوم القيامة',
      'فـكـل مـا يـخـطـر بالبـال أبـد فـبخـلاف ذاك ربـنـا الأحـد »',
      'ومن علم أن الله سبحانه الغني على الاطلاق نزهه عن المكان و الزمان و الجهة',
      'ويكفر باثبات المكان لله تعالى، فإن قال: الله في السماء، فإن قصد حكاية ما جاء في ظاهر الأخبار لا يكفر، وإن أراد المكان كفر',
      'إن الذي أين الأين لا يقال له أين',
      'إن الذي كيف الكيف لا يقال له كيف',
      'يقول تعالى ذكره { يَوْمَ يُكْشَفُ عَنْ ساقٍ } قال جماعة من الصحابة والتابعين من أهل التأويل : يبدو عن أمر شديد',
      'وزيارة قبره – صلى الله عليه وسلم – سنة من سنن المسلمين مجمع عليها ، وفضيلة مرغب فيها روي عن ابن عمر رضي الله عنه',
      'اعلم أنّ الناس في أخبار الصفات على ثلاث مراتب : إحداها : إصرارها على ما جاءت من غير تفسير ولا تأويل ، إلّا أن تقع ضرورة كقوله تعالى : { وَجَاءَ رَبُّكَ } [الفجر : 22]، أي جاء أمره وهذا مذهب السلف',
      'وقالت المجسمة : فعلو المسافة و بعد المقدار و محاذاة الاجرام تعالى الله عن قولهم',
      '{من في السماء} هذا مجاز وقد قام البرهان العـقلي على أنه تعالى ليس بمتحـيز في جهـة',
      'القول بالـمكان – أي في حق الله – منافيٌ للتوحيد',
      'والمراد هنا ظل العرش كما جاء في حديث آخر مبينا ، والمراد يوم القيامة إذا قام الناس لرب العالمين ودنت منهم الشمس واشتد عليهم حرها ، وأخذهم العرق ، ولا ظل هناك لشيء إلا للعرش',
      'وقد قال جمع من السلف والخلف إن من اعتقد أن الله في جهة فهو كافر كما صرح به العراقي ، وبه قال أبو حنيفة ومالك والشافعي وأبو الحسن الأشعري والباقلاني ، ذكره العلامة ملا علي قاري في شرح المشكاة',
      'فرجعت إلى أسماء فخبرتها فقالت هذه جبة رسول الله صلى الله عليه وسلم فأخرجت إلي جبة طيالسة كسروانية لها لبنة ديباج وفرجيها مكفوفين بالديباج فقالت هذه كانت عند عائشة حتى قبضت فلما قبضت قبضتها وكان النبي صلى الله عليه وسلم يلبسها فنحن نغسلها للمرضى يستشفى بها',
      'وأما علوّه تعالى على خلقه الـمُستفاد من نحو قوله تعالى {وهُوَ القاهرُ فَوْقَ عِبَادِهِ} (سورة الأنعام / 18) فعلوّ مكانة ومَرتبةٍ لا علوّ مكانٍ كما هو مُقرَّرٌ عند أهل السنة والجماعة',
      'إنـه تعـالى ليـس فـي جـهـة',
      'وكفر من يثبت الحركة والقعود والحدود له تعالى مما لا يتنازع فيه مسلمان',
      'وقالت طائفة من العلماء : هو عالي بمعنى منزه عن صفات الحدوث و التشبيه و التحيز و هو قول حسن',
      '« س: كيف يكون الدخول في الإسلام؟',
      'ج: بالنطق بالشهادتين الدخول في الإسلام، وليس بقول أستغفر الله،',
      'أما قول الله تعالى إخبارا عن نوح أنه قال: {فقلت استغفروا ربكم} [سورة نوح]، فمعناه أن نوحا طلب من قومه أن يدخلوا في الإسلام بالإيمان بالله وبنبيه نوح ليغفر الله لهم. الحديث: « أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأني رسول الله » متفق عليه.»',
      'أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَن لاَ إِلَـهَ إِلاَّ اللهُ وَأَنِّي رَسُولُ اللهِ',
      'الاستواء له معان و للعرش ايضا معان في اللغة و ليس فيما يضاف إليه تعالى معنى الاستقرار و التمكن و القعود و الجلوس و الركوب بإجماع أهل الحق بل حكم الآية التفويض مع التنزيه أو الحمل على مثل معنى الملك و الاستئثار بالملك و البدء في إصدار الأمر و النهي و نحو ذلك مما هو مشروع في محله على مقتضى اللغة و لسان التخاطب',
      'وأما التشبيه : فهو الاعقاد ان الله تعالى يشبه شيئا من خلقه، كالذين يعتقدون أن الله تعالى جسم فوق العرش، أو يعتقدون أن له يدين بمعنى الجارحتين، وأن له الصورة الفلانية أو على الكيفية الفلانية، أو أنه نور يتصوره العقل، أو أنه في السماء أو في جهة من الجهات الست، أو أنه في مكان من الاماكن، او في جميع الأماكن، أو أنه ملأ السموات والأرض، أو أن له حلول في شىء من الأشياء، أو في جميع الأشياء، أو أنه متحد بشىء من الاشياء، أو في جميع الأشياء، أو أن الأشياء منحلة منه، أو شيئا منها. وجميع ذلك كفر صريح والعياذ بالله تعالى، وسببه الجهل بمعرفة الامر غلى ما هو عليه',
      'وأما ما قيل من أنه يلزم من نفي الجهات الست عن الله نفي وجوده !! فهو قول باطل بالبداهة لما هو معلوم من أن الله عز وجل كان موجودا قبل وجود الجهات الست المذكورة ، وهي فوق وتحت وأمام وخلف ويمين وشمال ، بل كان موجودا قبل وجود العالم كله بإجماع السابقين واللاحقين ، فكيف يتوهم من عنده أدنى شائبة عقل أنه يلزم من نفي تلك الجهات عنه سبحانه وتعالى نفي وجوده جل وعلا ؟؟!! وكيف يتصور أن الله عز وجل القديم يتوقف وجوده على وجود بعض الحوادث أو كل الحوادث التي خلقها ؟؟!! سبحانك هذا بهتان عظيم',
      'وروى البيهقي بسنده إلى الأعمش عن ابي صالح قال أصاب الناس قحط في زمن عمر رضى اللّه عنه فجاء رجل إلى قبر النبي صلى الله عليه وسلم فقال: يا رسول الله استسق لأمتك فأتاه رسول الله في المنام فقال: أئت عمر فاقرأه مني السلام وأخبره أنهم مسقون وقل له: عليك الكيس،قال فأتى الرجل عمر فأخبره فبكى عمر رضى اللّه عنه وقال: يا ربّ ما ءالو إلا ما عجزت عنه',
      '« ما معنى قوله تعالى: {لم يلد ولم يولد} ج: معناه نفي المادية والانحلال عن الله. فالله لا يحل في شيء ولا ينحل منه شيء ولا يحل فيه شيء.',
      'قال الإمام جعفر الصادق: « من زعم أن الله في شيء أو من شيء أو على شيء فقد أشرك » رواه القشيري في الرسالة القشيرية. »',
      'مَن زَعَمَ أَنَّ اللهَ فِي شِىءٍ أَوْ مِن شَىءٍ أَوْ عَلٰى شَىءٍ فَقَدْ أَشْرَكَ',
      '« وقيل المراد ظل عرشه ، ويدل عليه حديث سلمان عند سعيد بن منصور بإسناد حسن « سبعة يظلهم الله في ظل عرشه» »',
      'حدّثنا عبد الله، حدّثنا محمّد بن عبد الله المخزوميُّ، حدّثنا أحمد بن نصر بن مالك، حدّثنا الحسين بن الوليد، عن هارون بن موسى قال: أوّل مَن نقط المصاحف يحيى بن يعمر',
      'سألته عن الرجل يمس منبر النبي صلى الله عليه وسلم ويتبرك بمسه ويقبله ويفعل بالقبر مثل ذلك أو نحو هذا يريد بذلك التقرب إلى الله عز و جل فقال: لا بأس بذلك',
      '« حكم ساب الله انه كافر‚ بين ذلك مع الدليل : ج: نقل القاضي عياض الإجماع على ان ساب الله كافر ولو كان غاضبا أو مازحا أو غير منشرح الصدر. قال تعالى: ( ولئن سألتهم ليقولن إنما كنا نخوض ونلعب قل ابالله وءاياته ورسوله كنتم تستهزئون لا تعتذروا قد كفرتم بعد إيمانكم) سورة التوبة ءاية 65ـ 66. الحديث : « ان العبد ليتكلم بالكلمة لا يرى بها بأسا يهوي بها في النار سبعين خريفا » رواه الترمذي. »',
      'وأما إقرار الرسول صلى الله عليه وآله وسلم الجارية على إشارتها نحو السماء فاكتفاء منها بما يدل على عدم شركها لتعتق ، لأنه بإشارتها إلى السماء علم أنها ليست ممن يعبد الأصنام التي في الأرض',
      'و أقول : إن التوسل بالنبي (صلى الله عليه وسلم) جائز في كل حال: قبل خلقه، وبعد خلقه، في مدة حياته في الدنيا، وبعد موته، في مدة البرزخ، وبعد البعث في عرصات القيامة والجنة.',
      'يدُهُ صفتُهُ بلا كيفٍ، وغضبُهُ ورضاهُ صفتانِ من صفاتِهِ بلا كيفٍ',
      '« ما هو أول المخلوقات ؟ ج: أول المخلوقات الماء. قال تعالى: ﴿ وَجَعَلْنَا مِنَ المَاءِ كُلَّ شَىءٍ حَيّ ﴾ سورة الأنبياء ءاية 30. الحديث : « كُلُّ شَىءٍ خُلِقَ مِنَ المَاءِ » رواه ابن حبان.»',
      'كُلُّ شَىْءٍ خُلِقَ مَنَ الْمَاءِ',
      'وعند هنا لا يراد بِها ظرف الـمكان لأنه تعالى منـزه عن الـمكان ، بل الـمعنى شرف الـمكانة وعلو الـمنـزلة',
      'لمّا قضى اللهُ الخلق كتب في كتابه فهو عنده فوق العرش: إن رحمتي غلبت غضبي',
      'فمن أظلم ممن كذب على الله أو من ادعى إدعاء معيناً مشتملاً على إثبات المكان والهيئة والجهة من مقابلة وثبوت مسافة وأمثال تلك الحالة ، فيصير كافراً لا محالة',
      '« س: ما حكم نداء نبي أو ولي ولو كان غائبا أو طلب شيء منه لم تجر به العادة ؟ ج: يجوز ذلك لأن مجرد ذلك لا يعد عبادة لغير الله وليس مجرد قول يا رسول الله إشراكا بالله، وقد ثبت أن بلال بن الحارث المزني أتى قبر الرسول عام الرمادة أيام عمر فقال: يا رسول الله استسق لأمتك فإنهم قد هلكوا رواه البيهقي وغيره فلم ينكر عليه عمر ولا غيره بل استحسنوا فعله.',
      'قال تعالى: {ولو أنهم إذ ظلموا أنفسهم جاءوك فاستغفروا الله واستغفر لهم الرسول لوجدوا الله توابا رحيما} [سورة النساء].',
      'وثبت أن ابن عمر قال « يا محمد » لما خدرت رجله رواه البخاري في الأدب المفرد.»',
      'الانبياء كثير و الرسل منهم ثلثمائة عشر واول الرسل أبو جميع البشر و هو آدم عليه السلام وآخرهم محمد صلى الله عليه و السلم',
      'ءادم فمن سواه من الأنبياء تحت لوائي يوم القيامة',
      'لأن كل من في السموات والأرض وما فيهما وما بينهما خلق الله تعالى وملك له وإذا كان كذلك يستحيل على الله أن يكون في السماء أو في الأرض إذ لو كان في شىء لكان محصورا أو محدودا ولو كان كذلك لكان محدثا وهذا مذهب أهل الحق والتحقيق وعلى هذه القاعدة قوله تعالى: {ءأمنتم من في السماء} وقوله عليه السلام للجارية: أين الله؟ قالت في السماء، ولم يُنكر عليها وما كان مثله ليس على ظاهره بل هو مؤول تأويلات صحيحة قد أبداها كثير من أهل العلم في كتبهم',
      '« كُنَّا عِنْدَ مَالِكِ بْنِ أَنَسٍ ، فَجَاءَ رَجُلٌ , فَقَالَ : يَا أَبَا عَبْدِ اللَّهِ ، الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى (سورة طه آية 5) ، كَيْفَ اسْتَوَى ؟ , فَأَطْرَقَ مَالِكٌ رَأْسَهُ ، ثُمَّ عَلاهُ الرُّحَضَاءُ , ثُمَّ قَالَ : الاسْتِوَاءُ غَيْرُ مَجْهُولٍ ، وَالْكَيْفُ غَيْرُ مَعْقُولٍ ، وَالإِيمَانُ بِهِ وَاجِبٌ ، وَالسُّؤَالُ عَنْهُ بِدْعَةٌ ، وَمَا أَرَاكَ إِلا مُبْتَدِعًا ، فَأَمَرَ بِهِ أَنْ يَخْرُجَ .',
      'قَالَ الشَّيْخُ [البيهقي] : وَعَلَى مِثْلِ هَذَا دَرَجَ أَكْثَرُ عُلَمَائِنَا فِي مَسْأَلَةِ الاسْتِوَاءِ وَفِي مَسْأَلَةِ الْمَجِيءِ وَالإِتْيَانِ وَالنُّزُولِ ، قَالَ اللَّهُ عَزَّ {وَجَاءَ رَبُّكَ وَالْمَلَكُ صَفًّا صَفًّا} (سورة الفجر آية 22) وَقَالَ : {هَلْ يَنْظُرُونَ إِلا أَنْ يَأْتِيَهُمُ اللَّهُ فِي ظُلَلٍ مِنَ الْغَمَامِ} (سورة البقرة آية 210) .»',
      'وهو شىءٌ لا كالأشياءِ، ومعنى الشىءِ إثباتُهُ بلا جسمٍ ولا جوهرٍ ولا عَرَضٍ، ولا حدَّ لهُ، ولا ضدَّ لهُ، ولا ندَّ له، ولا مِثلَ لهُ',
      'ومعنى {ينـزل ربنا إلى سماء الدنيا} ينـزل رسوله أو رحمته',
      '« قوله : «قال فرجعت إلى ربي» أي إلى المكان الذي ناجيت فيه ربي و ليس المراد أنَّ اللهَ في ذلك المكان و رجع له فإنَّ اعتقاد ذلك كُفر »',
      'إنّما ذاكَ جبرِيلُ عليه السلام كان يأتِيه، وإنّما أتَاهُ هذِه المرّةَ في صُورَتِه التي هي هَيئَتُه الأصليَّةُ فسَدَّ أُفُقَ السّماء',
      'من سبَّ النبيَّ صلى الله عليه وسلم أو عابَه أو ألَحقَ به نقصَا في نفسِه أو نسَبه أو دِينه أو خصلهً من خصاله أو عرَّضَ به أو شبَّهه بشىء على طريق السبّ له أو الإَزراءِ عَليه أو التصغَير لشأنه أو الغضّ منه والعيب له فهو سَابُّ له',
      'قلتُ : أرأيتَ لو قيل أين الله تعالى ؟ فقال – أي أبو حنيفة – : يقال له كان الله تعالى ولا مكان قبل أن يخلق الخلق ، وكان الله تعالى ولـم يكن أين ولاخَلْق ولاشىء ، وهو خالق كل شىء',
      'إن الله تعالى لا يحويه مكان ولا تحصره جهة، لا فوق ولا تحت، كان الله تعالى في الأزل ولم يكن شيء من الكائنات والأمكنة والجهات على الإطلاق',
      'قال القرطبي : هذا أقرب بالرتبة والكرامة لا بالـمسافة ، لأنه منـزه عن الـمكان والـمساحة والزمان . وقال البدر بن الصاحب في تذكرته : في الحديث إشارةٌ إلى نفي الجهة عن الله تعالى',
      'ومعنى { ءأمنتم من في السماء } من في السماء عذابه أو سلطانه ومصدر أمره ، أو هو كناية عن تعظيم الله تعالى بوصفه بالعلو والعظمة ، وتنـزيهه عن السفل والتحت لا أنه سبحانه وتعالى حال فيها !! لأن الحلول من صفات الأجسام وأمارات الحدوث والله منـزه عن ذلك',
      'اعتاد الناس الاحتفال لاستماع قصة مولده الشريف عليه الصلاة والسلام ولنعمة الذكرى بمولد النبي العظيم الذي أخرج اللهُ الخلق بهديه من الظلمات إلى النور',
      'قال الضحَّاك وأبو عبيدة في قوله: { كُلُّ شَيْءٍ هَالِكٌ إِلاَّ وَجْهَهُ } [ القصص: الآية 88 ] ، أي: إلا هو',
      'قال جمع منهم ومن الخلف : إن معتقد الجهة كافر ، كما صرح به العراقي ، وقال : إنه قول لأبي حنيفة ومالك والشافعي والأشعري والباقلاني',
      'قلت : يا رسول الله إني إذا رأيتك طابت نفسي وقرت عيني أنبئني عن كل شيء ، قال : كُلُّ شَىْءٍ خُلِقَ مَنَ الْمَاءِ',
      'وأما الخلف رحمهم الله تعالى فيقولون في هذه الآيات والأحاديث هي معروفة المعنى ، فمعنى { الرحمن على العرش استوى } استولى بالقهر والتصرف',
      'ليس له (أي حديث جابر) إسناد يعتمد عليه',
      'أنه لا يحل في شئ، ولا يحل فيه شئ، تعالى عن أن يحويه مكان كما تقدس عن أن يحويه زمان، بل كان قبل أن يخلق الزمان والمكان وهو الآن على ما عليه كان',
      'إن الأسماء مأخوذة من الشريعة واللغة، وأهل اللغة وضعوا هذا الاسم على ذي طولٍ وعرضٍ وسمكٍ وتركيبٍ وصورةٍ وتأليف والله تعالى خارج عن ذلك كله، فلم يجز أن يسمى جسمًا لخروجه عن معنى الجسمية، ولم يجىء في الشريعة ذلك فبطل',
      'واعلـم أَنَّا إذا قلنا إن الله عزّ وجل فوق ما خلق لـم يُرْجَعْ به إلى فوقية المكان والارتفاع على الأمكنة بالـمسافة والإشراف عليها بالـمماسة لشىء منها',
      'قوله – صلى الله عليه وسلم – : ( ينزل ربنا كل ليلة إلى السماء الدنيا فيقول : من يدعوني فأستجيب له ) هذا الحديث من أحاديث الصفات ، وفيه مذهبان مشهوران للعلماء سبق إيضاحهما في كتاب الإيمان ومختصرهما أن أحدهما وهو مذهب جمهور السلف وبعض المتكلمين : أنه يؤمن بأنها حق على ما يليق بالله تعالى ، وأن ظاهرها المتعارف في حقنا غير مراد ، ولا يتكلم في تأويلها مع اعتقاد تنزيه الله تعالى عن صفات المخلوق ، وعن الانتقال والحركات وسائر سمات الخلق . والثاني : مذهب أكثر المتكلمين وجماعات من السلف وهو محكي هنا عن مالك والأوزاعي : أنها تتأول على ما يليق بها بحسب مواطنها . فعلى هذا تأولوا هذا الحديث تأويلين أحدهما : تأويل مالك بن أنس وغيره معناه : تنزل رحمته وأمره وملائكته كما يقال : فعل السلطان كذا إذا فعله أتباعه بأمره . والثاني : أنه على الاستعارة ، ومعناه : الإقبال على الداعين بالإجابة واللطف . والله أعلم .',
      'وأما مذهب السلف والخلف بالنسبة للآيات والأحاديث المتشابهة فقد اتفق الكل على أن الله تعالى منـزه عن صفات الحوادث ، فليس له عز وجل مكان في العرش ولا في السماء ولا في غيرهما ، ولا يتصف بالحلول في شيء من الحوادث ، ولا بالاتصال بشيء منها ، ولا بالتحول والانتقال ونحوهما من صفات الحوادث ، بل هو سبحانه وتعالى على ما كان عليه قبل خلق العرش والكرسي والسماوات وغيرها من الحوادث',
      'فإذا معبود هذا الخاسر يقوم ويمشي ويتحرك، ولعل هذا الاعتقاد ورثه هذا السجزي من جيرانه عباد البقر، ومن اعتقد ذلك في إله العالمين يكون كافرًا باتفاق، فيا ويح من يقتدي بمثله في الصلاة أو يناكحه',
      'قال القاضي عياض : لا خلاف بين المسلمين قاطبة فقيههم ومحدثهم ومتكلمهم ونظارهم ومقلدهم أن الظواهر الواردة بذكر الله تعالى في السماء كقوله تعالى {أأمنتم من في السماء أن يخسف بكم الارض} ونحوه ليست على ظاهرها بل متأولة عند جميعهم',
      'وهو فوق العرش والسماء وفوق كل شيء إلى تخوم الثرى، فوقية لا تزيده قرباً إلى العرش والسماء كما لا تزيده بعداً عن الأرض والثرى بل هو رفيع الدرجات عن العرش والسماء كما أنه رفيع الدرجات عن الأرض والثرى',
      'بَابُ مَا يَقُولُ الرَّجُلُ إِذَا خَدِرَتْ رِجْلُهُ : حَدَّثَنَا أَبُو نُعَيْمٍ ، قَالَ : حَدَّثَنَا سُفْيَانُ ، عَنْ أَبِي إِسْحَاقَ ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ , قَالَ : خَدِرَتْ رِجْلُ ابْنِ عُمَرَ ، فَقَالَ لَهُ رَجُلٌ : اذْكُرْ أَحَبَّ النَّاسِ إِلَيْكَ ، فَقَالَ » يَا مُحَمَّد »',
      'لا يجوز على الله عز وجل الحلول في الأماكن لاستحالة كونه محدودًا ومتناهياً وذلك لاستحالة كونه مُحدَثاً',
      'واعلم أنّ القرافيّ وغيره حكوا عن الشّافعيّ ومالكٍ وأحمد وأبي حنيفة رضي الله عنهم القول بكفر القائلين بالجهة والتّجسيم وهم حقيقون بذلك',
      'واستدلاله على زعمه الباطل بهاتين الآيتين ونحوهما أن الله عز وجل يحل في عرشه أو يجلس عليه أو يحل في سماء أو نحو ذلك مما تزعمه تلك الشرذمة ، مع أن كلام الله غير مخلوق وهو من صفات الله تعالى القديمة الموجودة قبل وجود العرش والسماوات ، فالله تعالى موصوف بأنه استوى على العرش قبل وجود العرش ، وهل كان جالسا ـ على زعمهم ـ على العرش المعدوم قبل وجوده ؟؟!! وهل جل جلاله في السماء قبل خلق السماء ؟؟!! هذا مما لا يتوهمه عاقل ، وهل العقل يصدق بحلول القديم في شيء من الحوادث ؟؟!! فإنا لله وإنا إليه راجعون ، وعلى الجملة فهذا القائل المجازف وأمثاله قد ادعوا ما لا يقبل الثبوت لا عقلا ولا نقلا ، وقد كفروا وهم يحسبون أنهم يحسنون صنعا ، والطامة الكبرى التي نـزلت بهؤلاء دعواهم أنهم ( سلفيون ) !!! ، وهم عن سبيل الحق زائغون ، وعلى خيار المسلمين يعيبون ، فلا حول ولا قوة إلا بالله العلي العظيم',
      'اسْتَوَى : استولى عن الزجاج ونبه بذكر العرش وهو أعظم المخلوقات على غيره وقيل لما كان الاستواء على العرش وهو سرير الملك مما يرادف الملك جعلوه كناية عن الملك فقالوا استوى فلان على العرش أي ملك وإن لم يقعد على السرير البتة وهذا كقولك يد فلان مبسوطة أي جواد وإن لم يكن له يد رأسا والمذهب قول علي رضي الله عنه : الاستواء غير مجهول والتكييف غير معقول والإيمان به واجب والسؤال عنه بدعة لأنه تعالى كان ولا مكان فهو على ما كان قبل خلق المكان لم يتغير عما كان',
      'اعتقاده هو أن الله يحويه مكان، وقله سطح، وذلك قول بالتجسيم، ومن يعد الله سبحانه متمكناً بمكان فهو عابد وثن، خارج عن جماعة المسلمين، كما نص على ذلك غير واحد من أئمة أصول الدين، تعالى الله عن إفك الأفاكين.',
      'قال الله تعالى : {وَيَبْقَى وَجْهُ رَبِّكَ ذُو الْجَلاَلِ وَالإِكْرَامِ} [الرحمن: الآية 27]، قال المفسرون : معناه : يبقى ربك',
      'قوله تعالى { وَهُوَ العَلِيُّ العَظِيمُ } لا يجوز أن يكون الـمراد بكونه عليًّا العلو في الجهة والـمكان لـما ثبتت الدلالة على فساده ، ولا يجوز أن يكون الـمراد من العظيم العظمةَ بالجثةَ وكبرَ الجسم ، لأن ذلك يقتضي كونه مؤلَّفًا من الأجزاء والأبعاض ، وذلك ضد قوله : { اللَّهُ أَحَدٌ } ، فوجب أن يكون الـمراد من العَلي الـمتعالي عن مشابَهة الـممكنات ومناسبة الـمحدَثات ، ومن العظيم العظمة بالقدرة والقهر بالاستعلاء وكمال الإلـهية',
      'وأنه مستو على العرش على الوجه الذي قاله وبالمعنى الذي أراده استواء منزهاً عن المماسة والاستقرار والتمكن والحلول والانتقال لا يحمله العرش بل العرش وحملته محمولون بلطف قدرته ومقهورون في قبضته',
      'قد سألني بعض الراغبين في معرفة عقائد الدين ، والوقوف على مذهب السلف والخلف في المتشابه من الآيات والأحاديث بما نصه : ما قول السادة العلماء حفظهم الله تعالى فيمن يعتقد أن الله عز وجل له جهة !! وأنه جالس على العرش في مكان مخصوص !! ويقول : ذلك هو عقيدة السلف',
      'فالحكم أن هذا الاعتقاد باطل ومعتقده كافر بإجماع من يعتد به من علماء المسلمين ، والدليل العقلي على ذلك : قدم الله تعالى ومخالفته للحوادث ، والنقلي قال تعالى : ليس كمثله شىء وهو السميع البصير',
      'والمشتهر المتفق عليه بالإجماع القاطع كجبريل و ميكائيل ومالك […] وكعزرائيل…',
      '« قال الشافعي: لا يكفر أحد من أهل القبلة.',
      '[ فقال السيوطي : ] واستثنى من ذلك المجسم، ومنكر علم الجزئيات »',
      'اتفق علمـاء السنــة على أنّ الله غني عن كلّ شيء وكلَّ شيء مفتقـِر إليه، قائمٌ بنفسِه لا يحتاج إلى محـلّ ولا إلى مُخَـَصَّص، فهو الذي خلق الزمان والمكان وهو على مــا عليه كان قبل أن لا زمان و لا مكان',
      'ورؤيةُ الله تعالى جَائزَةٌ في العقلِ واجبةٌ بالنقلِ، وقد وردَ الدليلُ السَّمعيُّ بإيجاب رؤيةِ المؤمنينَ لله تعالى في دارِ الآخرةِ، فيُرى لا في مكانٍ، ولا على جهةٍ من مُقابلةٍ أو اتصالِ شُعاعٍ أو ثبوتِ مسافةٍ بين الرائي وبينَ الله تعالى',
      'حدثنا آدم قال: حدثنا ابن أبي ذئب، عن الزهري، عن السائب بن يزيد قال: كان النداء يوم الجمعة، أوله إذا جلس الإمام على المنبر، على عهد النبي صلى الله عليه وسلم وأبي بكر وعمر رضي الله عنهما، فلما كان عثمان رضي الله عنه، وكثر الناس، زاد النداء الثالث على الزوراء .',
      'وأنه ليس بجسم مصور ولا جوهر محدود مقدر وأنه لا يماثل والأجسام ولا في التقدير ولا في قبول الانقسام وأنه ليس بجوهر ولا تحله الجواهر ولا بعرض ولا تحله الأعراض بل لا يماثل موجوداً ولا يماثله موجود {ليس كمثله شيء} ولا هو مثل شيء. وأنه لا يحده المقدار ولا تحويه الأقطار ولا تحيط به الجهات ولا تكتنفه الأرضون ولا السموات',
      'أَنَّ النَّبِيَّ صَلَّى الله عَلَيْهِ وَسَلَّمَ اسْتَسْقَى ، فَأَشَارَ بِظَهْرِ كَفَّيْهِ إِلَى السَّمَاءِ',
      '« قوله – صلى الله عليه وسلم – : ( أين الله ؟ قالت في السماء قال : من أنا؟ قالت : أنت رسول الله قال : أعتقها فإنها مؤمنة )',
      'هذا الحديث من أحاديث الصفات ، وفيها مذهبان تقدم ذكرهما مرات في كتاب الإيمان .',
      'أحدهما : الإيمان به من غير خوض في معناه ، مع اعتقاد أن الله تعالى ليس كمثله شيء وتنزيهه عن سمات المخلوقات .',
      'والثاني تأويله بما يليق به ، فمن قال بهذا قال : كان المراد امتحانها ، هل هي موحدة تقر بأن الخالق المدبر الفعال هو الله وحده ، وهو الذي إذا دعاه الداعي استقبل السماء كما إذا صلى المصلي استقبل الكعبة ؟ وليس ذلك ؛ لأنه منحصر في السماء كما أنه ليس منحصرا في جهة الكعبة ، بل ذلك لأن السماء قبلة الداعين ، كما أن الكعبة قبلة المصلين ، أو هي من عبدة الأوثان العابدين للأوثان التي بين أيديهم ، فلما قالت : في السماء ، علم أنها موحدة وليست عابدة للأوثان . »',
      'احتج علماء التوحيد قديماً وحديثاً بهذه الآية في نفي كونه تعالى جسماً مركباً من الأعضاء والأجزاء وحاصلاً في المكان والجهة، وقالوا لو كان جسماً لكان مثلاً لسائر الأجسام، فيلزم حصول الأمثال والأشباه له، وذلك باطل بصريح قوله تعالى: {لَيْسَ كَمِثْلِهِ شَيْءٌ}',
      'قال الخطابي وقد تأول البخاري الضحك في موضع آخر على معنى الرحمة ، وهو قريب ، وتأويله على معنى الرضا أقرب',
      'يضحك الله إلى رجلين يقتل أحدهما الآخر يدخلان الجنة، يقاتل هذا في سبيل الله فيقتل، ثم يتوب الله على القاتل فيقاتل فيستشهد',
      'وأولُ الأنبياءِ ءادمُ عليه السلام وءاخرهم محمدٌ صلى الله عليه وسلم',
      'فكل من اعتقد أنه تعالى حل في مكان أو اتصل به أو بشيء من الحوادث كالعرش أوالكرسي أو السماء أو الأرض أو غير ذلك فهو كافر قطعا ، ويبطل جميع عمله من صلاة وصيام وحج وغير ذلك ، وتبين منه زوجه وعليه أن يتوب فورا ، وإذا مات على هذا الاعتقاد ـ والعياذ بالله تعالى ـ لا يغسل ولا يصلى عليه ولا يدفن في مقابر المسلمين ، ومثله في ذلك كله من صدقه في اعتقاده أعاذنا الله تعالى من شرور أنفسنا وسيئات أعمالنا ، وأما حمله الناس على أن يعتقدوا هذا الاعتقاد المكفر وقوله لهم من لم يعتقد ذلك يكون كافرا !! فهو كفر وبهتان عظيم',
      'فإن قيل: كيف يرى؟ قيل: بلا كيف، إذ الكيفية تكون لدى صورة بل يرى بلا وصف قيام وقعود واتكاء وتعلق واتصال وانفصال ومقابلة ومدابرة، وقصير وطويل، ونور، وظلمة وساكن ومتحرك، ومماس ومباين، وخارج وداخل ولا معنى يأخذه الوهم أو يقدره العقل لتعاليه عن ذلك',
      'وليسَ قربُ اللهِ تعالى ولا بُعدُهُ منْ طريقِ طولِ المسافةِ وقِصَرِها و لكن على معنى الكرامةِ والهوانِ، و المطيعُ قريبٌ منهُ بلا كيفٍ، والعاصي بعيدٌ عنهُ بلا كيفٍ',
      'إنه تعالى كان ولا مكان فهو على ماكان قبل خلق الـمكان ، لـم يتغير عما كان',
      'وتنـزيه الله سبحانه عن الـمكان والـمكانيات والزمان والزمانيات هو عقيدة أهل الحق رغم اغتياظ الـمجسمة الصرحاء',
      'يكفر بإثبات المكان لله تعالى',
      'ولو قال الله تعالى في السماء، فإن قصد به حكاية ما جاء فيه ظاهر الأخبار لا يكفر و إن أراد به المكان يكفر',
      'واعلـم أن المشبِّهة احتجوا على إثبات الـمكان لله تعالى بقوله : { ءأَمِنتُم مَّن فيِ السَّمَاءِ }',
      '« يا أبا عبد الله، أستقبل القبلة ، وأدعو أم أستقبل رسول الله – صلى الله عليه وسلم – ؟',
      'فقال : ولم تصرف وجهك عنه ، وهووسيلتك ، ووسيلة أبيك آدم – عليه السلام – إلى الله – تعالى – يوم القيامة ؟ بل استقبله ، واستشفع به ، فيشفعه الله. قال الله تعالى : {وَلَوْ أَنَّهُمْ إِذْ ظَلَمُوا أَنْفُسَهُمْ جَاءُوكَ فَاسْتَغْفَرُوا اللهَ وَاسْتَغْفَرَ لَهُمُ الرَسُولُ لَوَجَدُوا اللهَ تَوَّابًا رَحِيمًا} »',
      'بسم الله الرحمن الرحيم الحمد لله رب العالمين ، المنـزه عن صفات المخلوقين ، كالجهة والجسمية والمكان والفوقية ، والصلاة والسلام على سيدنا محمد ، الذي جاء بمحو الشرك والإلحاد وأمرنا بتنـزيه الله تعالى عن صفات العباد',
      'وعن جعفر الصادق رضي اللَّه عنه أنه قال: التوحيدُ ثلاثةُ أحرفٍ، أن تعرفَ أنه ليس من شيءٍ، ولا في شيءٍ، ولا على شيءٍ، لأنه من وصفَهُ أنه من شيءٍ فقد وصفهُ بأنه مخلوقٌ فيكفرُ، ومن قال: إِنه في شيءٍ. فقد وصفه بأنه مُحدَثٌ فيكفرُ. ومن قال على شيءٍ فقد وصفهُ بأنه محتاجٌ محمولٌ فيكفر',
      '« لما رمى رسول الله صلى الله عليه وسلم الجمرة, و نحر نسكه و حلق, ناول الحالق شقه الأيمن فحلقه. ثم دعا أبا طلحة الأنصاري فأعطاه إياه. ثم ناوله الشق الأيسر. فقال « احلق » فحلقه, فأعطاه أبا طلحة. فقال « اقسمه بين الناس » »',
      'قال ابن كيسان : قوة الله ونصرته فوق قوتهم ونصرتهم',
      '« وقال الإمام الأعظم (يعني الإمام أبو حنيفة) رحمه الله في كتابه « الوصية » : ولقاء الله تعالى لأهل الجنة بلا كيف ولا تشبيه ولا جهةٍ حقٌّ »',
      '« قال ابن عقيل : « تعالى الله أن يكون له صفة تشغل الأمكنة ، لأنّ هذا عين التجسيم ، وليس الحق بذي أجزاء وأبعاض يعَالج بِها »',
      '« ذكر الشيخ الإمام ابن عبد السلام في كتاب حل الرموز: أنه قال الإمام أبو حنيفة رحمه الله :',
      'من قال لا أعرف الله تعالى في السماء هو أم في الأرض كفر، لأن هذا القول يوهم أن للحق مكانا، ومن توهم أن للحق مكانا فهو مشبه',
      'ولا شك أن ابن عبد السلام من أجل العلماء وأوثقهم، فيجب الاعتماد على نقله »',
      'وقوله تعالى {كل شىء هالك الا وجهه} قالت فرقة : المعنى : كل شىء هالك الا هو سبحانه، قاله الطبرى وجماعة منهم ابو المعالى (الجويني) رحمه الله ، وقال الزجاج الا اياه',
      'معناه : المرتفع عن أن يجوز عليه ما يجوز على المحدَثين من الأزواج والأولاد والجوارح والأعضاء واتخاذ السرير للجلوس عليه، والاحتجاب بالستور عن أن تنفذ الأبصار إليه، والانتقال من مكان إلى مكان ونحو ذلك، فإن إثبات بعض هذه الأشياء يوجب النهاية، وبعضها يوجب الحاجة، وبعضها يوجب التغير والاستحالة، وشىء من ذلك غير لائق بالقديم ولا جائز عليه',
      'واعلـم أن السَّلَفَ قائلون باستحالة العلو الـمكاني عليه تعالى ، خلافاً لبعض الجهلة الذين يخبطون خبط عشواء في هذا الـمقام ، فإن السلف والخلف متفقان على التنـزيه',
      'سمعت خطبة أبي بكر الصديق وعمر بن الخطاب وعثمان بن عفان وعلي بن أبي طالب رضى الله عنهم والخلفاء هلم جرا إلى يومي هذا فما سمعت الكلام من فم مخلوق أفخم ولا أحسن منه من في عائشة رضى الله عنها',
      'وهو الذي إذا دعاه الداعي استقبل السماء كما إذا صلى المصلي استقبل الكعبة وليس ذلك لأنه منحصر في السماء كما أنه ليس منحصرا في جهة الكعبة بل ذلك لأن السماء قبلة الداعين كما أن الكعبة قبلة المصلين',
      'وقيل ليحيى بن معاذ (الرازي) : أَخْبِرْني عن الله عز وجل ، فقال : إله واحد ، فقيل له : كيف هو ؟ قال : ملك قادر ، فقيل : أين هو ؟ فقال : هو بالمرصاد ، فقال السائل : لم أسألك عن هذا ؟ فقال : ما كان غير هذا كان صفة المخلوق ، فأما صفته فما أخبرتك عنها .',
      'وأما ما ورد في التنزيل من الاستواء والوجه واليدين والجنب والمجيء والإتيان والفوقية وغير ذلك فأجروها على ظاهرها أعني ما يفهم عند الإطلاق على الأجسام',
      'وهو متكلمٌ بكلامٍ هو صفةٌ لهُ أزليةٌ ليس من جنسِ الحروفِ والأصواتِ وهو صفةٌ منافيةٌ للسكوتِ والآفةِ، والله تعالى متكلمٌ بها ءامرٌ ناهٍ مخبِرٌ، والقرءانُ كلامُ الله تعالى غيرُ مخلوقٍ',
      'فلا يقال أين ولا كيف ولا متى لأنه خالق الزمان والـمكان',
      'قال البخاري معنى الضحك الرحمة',
      'والأعلى صفة الرب ، والـمراد بالعلو العلو بالقهر والاقتدار ، لا بالـمكان والجهة ، لتنـزهه عن ذلك',
      'والقاعدة تنـزيهه – جل و عز – عن الحركة والانتقال وشغل الأمكنة',
      'الأصل السابع : العلـم بأنَّ الله تعالى منـزه الذات عن الاختصاص بالجهات ، فإنَّ الجهة إما فوق وإما أسفل وإما يمين وإما شمال أو قدَّام أو خلف ، وهذه الجهات هو الذي خلقها',
      '« و سئل ذو النون المصري عن قوله تعالى : « ٱلرَّحۡمَـٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ ».',
      'فقال : أثبتَ ذاته و نفى مكانه، فهو موجود بذاته، والأشياء موجودة بحكمه، كما شاء سبحنه »',
      'اللهم ربَّ السموات ورب الأرض، ورب العرش العظيم، ربنا ورب كل شيء، فالق الحب والنوى، ومُنزل التوراة والإنجيل والفرقان، أعوذ بك من شر كل شيء أنت آخذٌ بناصيته، اللهم أنت الأول فليس قبلك شيء، وأنت الآخر فليس بعدك شيء، وأنت الظاهر فليس فوقك شيء، وأنت الباطن فليس دونك شيء، اقض عنا الدَّيْنَ واغننا من الفقر',
      'والمحدِثُ للعالم هو الله تعالى الواحدُ القديمُ الحيُّ القادرُ العليمُ السميعُ البصيرُ الشائي المريدُ ليس بِعَرَضٍ، ولا جسمٍ، ولا جوهرٍ، ولا مُصوَّرٍ، ولا محدودٍ، ولا معدودٍ، ولا متبعِّضٍ، ولا متجزّ، ولا مُتَركّبٍ، ولا متناهٍ، ولا يُوصف بالماهيةِ، ولا بالكيفيةِ، ولا يتمكَّنُ في مكانٍ، ولا يجري عليهِ زمانٌ، ولا يُشبههُ شىءٌ، ولا يَخرُجُ عن علمِهِ وقدرتِهِ شىءٌ.',
      '{كُلُّ شَىءٍ هَالِكٌ إِلَّا وَجهَهُ}: إِلَّا مُلكَهُ ، ويقال: إلا ما أريد به وجه الله',
      '« أن كل رسول نبي ، وليس كل نبي رسولا . وأول الرسل آدم ، وآخرهم محمد (صلى الله عليه وسلم). وفي حديث أبي ذر (رضي الله عنه): « إن الأنبياء مائة ألف ، وأربعة وعشرون ألف نبي». وذكر أن الرسل منهم ثلاثمائة وثلاثة عشر ، أولهم آدم (عليه السلام). »',
      '« قال محمد بن سحنون : أجمع العلماء أن شاتم النبي – صلى الله عليه وسلم – المتنقص له كافر . والوعيد جار عليه بعذاب الله ، […] ومن شك في كفره ، وعذابه كفر » .',
      'اعلم أن النزول الذي هو الانتقال من علو إلى سفل لا يجوز حمل الحديث عليه، لوجوه : الأول : النزول من صفات الأجسام والمحدَثات ويحتاج إلى ثلاثة : منتقِل، ومنتقَل عنه ومنتقَل إليه، وذلك على الله تعالى محال. الثاني : لو كان النزول لذاته حقيقة لتجددت له في كل يوم وليلة حركات عديدة تستوعب الليل كله، وتنقلات كثيرة، لأن ثلث الليل يتجدد على أهل الأرض مع اللحظات شيئا فشيئا، فيلزم انتقاله في السماء الدنيا ليلا نهارا، من قوم إلى قوم، وعوده إلى العرش في كل لحظة على قولهم، ونزوله فيها إلى سماء الدنيا، ولا يقول ذلك ذو لب وتحصيل. الثالث، أن القائل بأنه فوق العرش، وأنه ملأه كيف تسعه سماء الدنيا، وهي بالنسبة إلى العرش كحلقة في فلاة، فيلزم عليه أحد أمرين: إما اتساع سماء الدنيا كل ساعة حتى تسعه، أو تضاؤل الذات المقدس عن ذلك حتى تسعه، ونحن نقطع بانتفاء الأمرين.',
      'من قال أن الله جسم لا كالأجسام كفر',
      'فَيُرَى سبحانه لا في مكانٍ ولا جهةٍ ولا باتصال شعاعٍ ولا ثبوت مسافةٍ بين الرائيين وبينه تعالى بل على الوجه الذي يليق بقدسيته وجلاله سبحانه',
      'يتفق الجميع من علـماء سلف أهل السنة وخلفهم- وكذا العقلانيون من الـمتكلـمين – على أن ظاهر الاستواء على العرش بمعنى الجلوس على كرسي والتمكن عليه والتحيز فيه مستحيلٌ ، لأن الأدلة القطعية تُنَـزِّهُ الله تعالى عن أن يُشبهَ خلقه أو أن يحتاج إلى شىءٍ مخلوق ، سواء أكان مكاناً يحل فيه أو غيره ، وكذلك لأنه سبحانه نفى عن نفسه الـمماثلة لخلقه في أي شىء فأثبت لذاته الغِنى الـمطلق فقال تعالى :{ لَيْسَ كَمِثْلِهِ شَىءٌ}',
      'قال جعفر الصادق : من زعم أن الله في شىء ، أومن شىء أو على شىء فقد أشرك . إذ لو كان على شىء لكان محمولا ، ولو كان في شىء لكان محصوراً ، ولو كان من شىء لكان محدثًا (أي مخلوقاً)',
      'قال البيضاوي : لـما ثبت بالقواطع أنه سبحانه منـزه عن الجسمية والتحيز امتنع عليه النـزول على معنى الانتقال من موضعٍ إلى موضعٍ أخفض منه',
      'ولا يلزم من كون جهتي العلو والسفل مُحالاً على الله أن لا يوصف بالعلو ، لأن وصفه بالعلو من جهة الـمعنى ، والـمستحيل كون ذلك من جهة الحس، ولذلك ورد في صفته العالي والعلي والـمتعالي ، ولـم يرد ضد ذلك وإن كان قد أحاط بكل شىءٍ علـماً',
      'قوله سبحانه { لَيْسَ كَمِثْلِهِ شَىءٌ} [ سورة الشورى / 11] نصٌّ في نفي الجهة عنه تعالى ، إذ لو لـم تنف عنه الجهة لكانت له أمثال لا تحصى ، تعالى الله عن ذلك',
      'مَنْ سَنَّ فِى الإِسْلامِ سُنَّةً حَسَنَةً فَلَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا بَعْدَهُ مِنْ غَيْرِ أَنْ ينْقُصَ مِنْ أُجُورِهِمْ شَىْءٌ ، وَمَنْ سَنَّ فِى الإِسْلام سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ ينْقصَ مِنْ أَوْزَارِهِمْ شَىْءٌ',
      'وإنَّما ترفع الأيدي بالدعاء إلى السماء لأنَّ السَّماء مهبط الوحي ومنـزل القطر ومحل القُدس (أي الطهر) ومعدن الـمطهَّرين من الـملائكة ، وإليها ترفع أعمال العباد ، وفوقها عرشه وجنته ، كما جعل الله الكعبة قِبلةً للدعاء والصلاة ، ولأنه خلق الأمكنة وهو غير محتاج إليها ، وكان في أزله قبل خلق الـمكان والزمان ولامكان له ولازمان ، وهو الآن على ما عليه كان',
      'أنا سيّدُ ولد ءادم يوم القيامةِ ولا فخر',
      'أن الله تعالى ليس كمثله شيء وأنه منزه عن التجسم والانتقال والتحيز في جهة وعن سائر صفات المخلوق',
      'واستدل به على جواز إحداث ذكر في الصلاة غير مأثور إذا كان غير مخالف للمأثور',
      'وكذا حكى عن مالك أنه أوله بنزول رحمته وأمره أو ملائكته كما يقال فعل الملِك كذا أي أتباعه بأمره',
      'الواجب علينا أن نعتقد أن ذات الله تعالى لا تتبعض و لا يحويها مكان ولا توصف بالتغـيّر والانتقال',
      'وقال ابن خلكان في ترجمة الحافظ أبي الخطاب بن دحية : كان من أعيان العلماء ومشاهير الفضلاء ، قدم من المغرب ، فدخل الشام والعراق واجتاز بإربل سنة أربع وستمائة ، فوجد ملكها المعظم مظفر الدين بن زين الدين يعتني بالمولد النبوي ، فعمل له كتاب التنوير في مولد البشير النذير ، وقرأه عليه بنفسه ، فأجازه بألف دينار',
      'إن الله منـزهٌ عن جميع النقائص ، وسمات الحدوث ، ومنها الزمان والـمكان ، فلا يُقارنه زمانٌ ولا يحويه مكانٌ إذ هو الخالق لهما فكيف يحتاج إليهما',
      'قوله تعالى { ليس كمثله شيء } فيه الرد على المشبهة وأنه تعــــــالى ليس بجوهـــــر ولا جسم ولا عرض ولا لــــــون ولا طعم ولا حالّ في مكان ولا زمان',
      'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَ كُنَّا يَوْمًا نُصَلِّي وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ قَالَ مَنْ الْمُتَكَلِّمُ قَالَ أَنَا قَالَ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلُ',
      'والـمراد بِها توقيره [مراده : تعظيمه ] وتنـزيهه عن السفل والتحت ، ووصفه بالعلوِّ والعظمة لا بالأماكن والجهات والحدود لأنَّها صفات الأجسام',
      'فمعتقد سلف الأئمة وعلـماء السنة من الخلف أن الله منـزه عن الحركة والتحول والحلول ، ليس كمثله شىء',
      'كان أحمد – يعني الإمام أحمد بن حنبل – لا يقول بالجهة للباري',
      'وقال البيضاوي : لـما ثبت بالقواطع أنه سبحانه منـزه عن الجسمية والتحيز امتنع عليه النـزول على معنى الانتقال من موضعٍ إلى موضعٍ أخفض منه',
      '« قوله « في السماء » ظاهره غير مراد، إذ الله منـزه عن الحلول في الـمكان، لكن لما كانت جهة العلو أشرف من غيرها أضافها إليه إشارة إلى علو الذات والصفات »',
      'ولانقول إن العرش له ( أي لله ) قرارٌ ولامكانٌ ، لأن الله تعالى كان ولا مكان ، فلـما خلق الـمكان لـم يتغيّر عما كان',
      '« قوْلُهُ : « لا عِبْرَةَ بِقَوْلِ المُوَقّتينَ» أيْ في وجوبِ الصومِ على الناسِ »',
      'وقال : « لا يُعْتَبَرُ قولهُمْ بالإجماعِ ولا يجوزُ للمنجّمِ أنْ يعملَ بحسابِ نَفْسِهِ »',
      'قال شيخنا – يعني الحافظ ابن حجر العسقلاني – : إنَّ علـم الله يشمل جميع الأقطار ، والله سبحانه وتعالى منـزه عن الحلول في الأماكن ، فإنه سبحانه وتعالى كان قبل أن تحدث الأماكن',
      'و{العليّ} يُراد به علو القدر والـمنـزلة لا علو الـمكان ، لأنَّ الله منـزه عن التحيز. وحكى الطبري عن قوم أنهم قالوا : هو العلي عن خلقه بارتفاع مكانه عن أماكن خلقه . قال ابن عطية : وهذا قول جهلة مجسمين',
      '« البدعة بكسر الباء في الشرع هي: إحداث ما لم يكن في عهد رسول الله صلّى الله عليه وءاله وسلم، وهي منقسمة إلى حسنة وقبيحة.',
      'قال الإمام الشيخ المجمع على إمامته وجلالته وتمكنه في أنواع العلوم وبراعته أبو محمد عبد العزيز ابن عبد السلام رحمه الله ورضي عنه في ءاخر كتاب القواعد: البدعة منقسمة إلى: واجبة ومحرمة ومندوبة ومكروهة ومباحة. قال: والطريق في ذلك أن تعرض البدعة على قواعد الشريعة، فإن دخلت في قواعد الإيجاب فهي واجبة أو في قواعد التحريم فمحرمة أو الندب فمندوبة أو المكروه فمكروهة أو المباح فمباحة »',
      'وإضافته – أي العرش – إلى الله تعالى إنَّما هو بمعنى التشريف له كما يقال : بيتُ الله وحرمه ، لا أنه محلٌّ له وموضع لاستقراره اذ ليس – الله – في مكان ، فقد كان قبل أن يَخْلُقَ الـمكان',
      'مذهب أهل الحق قاطبةً أن الله سبحانه وتعالى يتعالى عن التحيّز والتخصص بالجهات',
      'ويجب أن يُعلـم أن كل ما يدل على الحدوث أو على سمة النقص فالرَّبُّ تعالى يتقدّس عنه ، فمن ذلك : أنه تعالى متقدّسٌ عن الاختصاص بالجهات ، والاتصاف بصفات الـمحدثات ، وكذلك لا يوصف بالتحول والانتقال ، ولا القيام ولا القعود ، لقوله تعالى : { لَيْسَ كَمِثْلِهِ شَىءٌ } [سورة الشورى/ 11] ، وقوله : { وَلـم يَكُن لَّهُ كُفُواً أَحَدٌ } [سورة الإخلاص/ 4] ، ولأن هذه الصفات تدل على الحدوث والله تعالى يتقدّس عن ذلك',
      'البارئ سبحانه وتعالى قائمٌ بنفسه، متعال عن الافتقار إلى محلٍّ يحله أو مكانٍ يُقله',
      'والناس فيها وفيما شاكلها على ثلاثة أوجه قال بعضهم : نقرؤها ونؤمن بها ولا نفسرها ، وذهب إليه كثير من الأئمة ، وهذا كما روي عن مالك رحمه الله أن رجلا سأله عن قوله تعالى : الرحمن على العرش استوى ، قال مالك : الاستواء غير مجهول ، والكيف غير معقول ، والإيمان به واجب ، والسؤال عنه بدعة ، وأراك رجل سوء أخرجوه . وقال بعضهم : نقرؤها ونفسرها على ما يحتمله ظاهر اللغة . وهذا قول المشبهة . وقال بعضهم : نقرؤها ونتأولها ونحيل حملها على ظاهرها',
      'خرجت مع عمر بن الخطاب – رضي الله عنه – ليلة في رمضان إلى المسجد فإذا الناس أوزاع متفرقون يصلي الرجل لنفسه ، ويصلي الرجل فيصلي بصلاته الرهط ، فقال عمر : إني أرى لو جمعت هؤلاء على قارئ واحد لكان أمثل ، ثم عزم فجمعهم على أبي بن كعب ، ثم خرجت معه ليلة أخرى والناس يصلون بصلاة قارئهم ، قال عمر : نعم البدعة هذه',
      'والله تعالى يُرى في الآخرة، ويراه المؤمنون وهم في الجنة بأعين رؤوسهم بلا تشبيه ولا كيفية، ولا يكون بينه وبين خلقه مسافة',
      'وَقَدْ تَأَوَّلَهُ بَعْضُهُمْ عَلَى مَعْنَى قَوْلِهِ : » يَوْمَ يُكْشَفُ عَنْ سَاقٍ » فَرُوِيَ عَنِ ابْنِ عَبَّاسٍ , أَنَّهُ قَالَ : عَنْ شِدَّةٍ وَكَرْبٍ . قَالَ أَبُو سُلَيْمَانَ : فَيُحْتَمَلُ أَنْ يَكُونَ مَعْنَى قَوْلِهِ : » يَوْمَ يَكْشِفُ رَبُّنَا عَنْ سَاقِهِ » ، أَيْ عَنْ قُدْرَتِهِ الَّتِي تَنْكَشِفُ عَنِ الشِّدَّةِ وَالْمَعَرَّةِ',
      'ومعنى { فَوقَ عِباَدِهِ } فوقية الاستعلاء بالقهر والغلبة عليهم ، أي : هم تحت تسخيره ، لا فوقية مكان',
      'ويتكلم ( يعني الله) لا ككلامنا. و نحن نتكلم بالآلات و الحروف و الله تعالى يتكلم بلا آلة و لا حروف , و الحروف مخلوقة و كلام الله تعالى غير مخلوق',
      'قوله قال عمر: (نعم البدعة) في بعض الروايات (نعمت البدعة) بزيادة التاء، والبدعة أصلها ما أحدث على غير مثال سابق، وتطلق في الشرع في مقابل السنة فتكون مذمومة، والتحقيق أنها إن كانت مما تندرج تحت مستحسن في الشرع فهي حسنة، وإن كانت مما تندرج تحت مستقبح في الشرع فهي مستقبحة، وإلا فهي من قسم المباح، وقد تنقسم إلى الأحكام الخمسة',
      'يجب لله الوجود والقدم كذا البقاء و الغنى المطلق عم وخلفه لخلقه بلا مـثال و وحدة الذات ووصف الفعال و قدرة إرادة علم حـياة سمع كلام بصر ذي واجبات',
      'الحمد لله الذي ليس له حدٌّ محدودٌ فيُحتوى ، ولا له أجلٌ معدودٌ فيَفنى ، ولا يحيط به جوامع الـمكان ، ولا يشتمل عليه تواتر الزمان',
      'أنت الله الَّذي لا يَحويك مكان',
      'أنت اللهُ الذي لاَ تُحَدُّ فَتـكُونَ مـحدوداً',
      'البدعة بدعتان : بدعة محمودة ، وبدعة مذمومة ، فما وافق السنة فهو محمود ، وما خالف السنة فهو مذموم . واحتج بقول عمر بن الخطاب في قيام رمضان : نعمت البدعة هي',
      'سمعت الشَّافِعيُّ رَضِيَ اللهُ عَنْهُ يَقُولُ: إِنِّي لأَتَبَرَّكُ بِأَبي حَنِيفَةَ وَأَجِيءُ إِلى قَبْرِهِ في كُلِّ يَوْمٍ فَإِذَا عَرَضَتْ لي حَاجَةٌ صَلَّيْتُ رَكْعَتَيْنِ وَجِئْتُ إِلى قَبْرِهِ وَسَأَلْتُ اللهَ تَعَالى الْحَاجَةَ عِنْدَهُ فَمَا تَبْعُدُ عَنِّي حَتَّى تُقْضَى',
      'نُقِرُّ بأنَّ اللهَ تعالى على العرشِ استوى من غيرِ أن يكونَ له حاجةٌ إليه واستقرار عليه وهو الحافظُ للعرش وغيرِ العرش منْ غيرِ احتياج، فلو كان محتاجا لما قَدَرَ على إيجادِ العالم وتدبيرِه كالمخلوق ولو كان محتاجا إلى الجلوس والقرار فقبل خلقِ العرشِ أين كان الله تعالى الله عن ذلك علوًا كبير',
      'ويستحب أن يقعد عنده بعد الفراغ ساعة قدر ما يُنحَر جَزُورٌ ويُقَسَّم لحمُها. ويشتغل القاعدون بتلاوة القرآن، والدعاء للميت، والوعظ، وحكايات أهل الخير، وأحوال الصالحين',
      'قال الشافعي والأصحاب: يُستحبّ أن يقرؤوا عنده شيئاً من القرآن، قالوا: فإن ختموا القرآن كلَّه كان حسناً',
      'وروينا في سنن البيهقي بإسناد حسن؛ أن ابن عمر استحبَّ أن يقرأ على القبر بعد الدفن أوّل سورة البقرة وخاتمتها',
      '« المحدثات من الأمور ضربان:',
      '– أحدهما : ما أحدث يخالف كتاباً أو سنة أو أثراً أو إجماعاً، فهذه البدعة الضلالة.',
      '– والثانية: ما أحدث من الخير لا خلاف فيه لواحد من هذا، وهذه محدثة غير مذمومة.',
      '[وقد] قال عمر، رضي الله عنه، في قيام شهر رمضان: نعمت البدعة هذه يعني أنها محدثة لم تكن، وإذا كانت فليس فيها ردّ لما مضى »',
      'قوله : { مَن فِي السَّمَاءِ } في الـموضعين من قبيل الـمتشابه الذي يعطي ظاهره معنى الحلول في مكان ، وذلك لا يليق بالله',
      'اتفق العقلاء من أهل السنة الشافعية والحنفية والـمالكية وفضلاء الحنابلة وغيرهم على أن الله تبارك وتعالىَ مُنَـزَّهٌ عن الجهة والجسمية والحد والـمكان ومشابَهة مخلوقاته',
      'مذهب الفرقة الناجية وما عليه أجمع السُّنِّيُّـون أن الله تعالى مُنَـزَّهٌ عن مشابـهة الحوادث مخالف لها في جميع سمات الحدوث، ومن ذلك تَنَـزُّهُهُ عن الجهة والـمكان كما دلت على ذلك البراهين القطعية',
      '« قالت النجارية : « إن الباري سبحانه بكل مكان من غير حلول ولا جهة »، وقالت الحشوية والمجسمة : « إنه سبحانه حالٌ في العرش، وإن العرش مكان له وهو جالس عليه »، فسلك -أي الإمام الأشعري رضي الله عنه- طريقة بينهما فقال: « كان ولا مكان، فخلق العرش والكرسي ولم يحتج إلى مكان، وهو بعد خلق المكان كما كان قبل خلقه ».»',
      'إنَّ الذي يجبُ علينا وعلى كلِّ مسلم أن يَعلَمَهُ أنَّ ربنا ليس بذي صورةٍ ولا هيئة فإنَّ الصورة تقتضي الكيفية وهي عن الله وعن صفاته منفية',
      '« واستدل بعض أصحابنا في نفي الـمكان عنه بقول النبيِّ صلى الله عليه و سلم :',
      '« أنت الظاهر فليس فوقك شىء ، وأنت الباطن فليس دونك شىء » ،',
      'وإذا لـم يكن فوقه شىء ولا دونه شىء لـم يكن في مكان »',
      'فقد وقع السؤال عن عمل المولد النبوي في شهر ربيع الأول ، ما حكمه من حيث الشرع ؟ وهل هو محمود أو مذموم ؟ وهل يثاب فاعله أو لا ؟ الجواب : عندي أن أصل عمل المولد الذي هو اجتماع الناس وقراءة ما تيسر من القرآن ورواية الأخبار الواردة في مبدأ أمر النبي صلى الله عليه وسلم وما وقع في مولده من الآيات ، ثم يمد لهم سماط يأكلونه وينصرفون من غير زيادة على ذلك – هو من البدع الحسنة التي يثاب عليها صاحبها لما فيه من تعظيم قدر النبي صلى الله عليه وسلم وإظهار الفرح والاستبشار بمولده الشريف ، وأول من أحدث فعل ذلك صاحب إربل الملك المظفر أبو سعيد كوكبري بن زين الدين علي بن بكتكين ، أحد الملوك الأمجاد والكبراء الأجواد ، وكان له آثار حسنة ، وهو الذي عمر الجامع المظفري بسفح قاسيون',
      'لا خلاف أن ساب الله تعالى من المسلمين كافر',
      'حدثني أبي, قال: حدثنا يحيى بن زكريا بن أبي زائدة, قال: أخبرني إسماعيل بن أبي خالد, عن فراس, عن الشعبي قال: لا بأس بالتعويذ من القرءان يعلق على الإنسان',
      'فقد تكون البدعة واجبة كنصب الأدلّة للردّ على أهل الفِرق الضالّة، وتعلّم النحو المفهم للكتاب والسنّة، ومندوبة كإحداث نحو رباط ومدرسة، وكل إحسان لم يكن في الصدر الأول، ومكروهة كزخرفة المساجد، ومباحة كالتوسّع بلذيذ المآكل والمشارب والثياب',
      'تـعـالى – أي الله – عن الحدود والغايات والأركان والأعضاء والأدوات لا تحـويه الجهـاتُ السـِتُّ كسائر المبتَدَعات',
      '« قوله صلى الله عليه وسلم : ( وكل بدعة ضلالة ) هذا عام مخصوص ، والمراد غالب البدع .',
      'قال أهل اللغة : هي كل شيء عمل على غير مثال سابق . قال العلماء : البدعة خمسة أقسام : واجبة ، ومندوبة ومحرمة ، ومكروهة ، ومباحة . فمن الواجبة : نظم أدلة المتكلمين للرد على الملاحدة والمبتدعين وشبه ذلك . ومن المندوبة : تصنيف كتب العلم ، وبناء المدارس والربط وغير ذلك . ومن المباح : التبسط في ألوان الأطعمة وغير ذلك . والحرام والمكروه ظاهران . وقد أوضحت المسألة بأدلتها المبسوطة في تهذيب الأسماء واللغات ، فإذا عرف ما ذكرته علم أن الحديث من العام المخصوص . وكذا ما أشبهه من الأحاديث الواردة ، ويؤيد ما قلناه قول عمر بن الخطاب – رضي الله عنه – في التراويح : نعمت البدعة ، ولا يمنع من كون الحديث عاما مخصوصا . قوله : ( كل بدعة ) مؤكدا ( بكل ) ، بل يدخله التخصيص مع ذلك ، كقوله تعالى : تدمر كل شيء . »',
      'إنه تعالى كان ولا مكان فخلق الـمكان وهو على صفة الأزلية كما كان قبل خلقه الـمكان لا يجوز عليه التغيِير فى ذاته ولا في صفاته',
      'أَجمعَ أَهْلُ الحَقِّ قَاطِبَةً على أنَّ الله تَعالى لاجِهَةَ له، فلا فوقَ ولا تحتَ ولايمينَ ولا شمالَ ولا أمامَ ولا خَلْفَ',
      'العَجْزُ عن دَرَكِ الإِدْرَاكِ إِدْرَاكُ والبَحْثُ عن ذَاتِهِ كُفْرٌ وإِشْرَاكُ',
      '﴾ وَلاَ يُحِيطُونَ بِهِ عِلْمًا ﴿'
    ]::text[]);
    GET DIAGNOSTICS n = ROW_COUNT;
    RAISE NOTICE 'parole : % ligne(s) supprimée(s) (islamsunnite.net).', n;
  END IF;
END $$;

DO $$
DECLARE n integer;
BEGIN
  IF to_regclass('public.paroles') IS NULL THEN
    RAISE NOTICE 'paroles : table absente, ignorée.';
  ELSE
    DELETE FROM "paroles" WHERE texte_arabe = ANY (ARRAY[
      'ولا يتصف سبحانه بالحركة والسكون، ولا بالكبر والصغر، ولا بالطول والقصر، ولا بالقرب والبعد بالمسافة، ولا بغير ذلك من صفات الحوادث',
      'وأنّه -أي الله- تعالى منزّه عن الجهة والمكان والجسم وسائر أوصاف الحدوث، وهذا معتقد أهل الحقّ ومنهم الإمام أحمد، وما نسبه إليه بعضهم من القول بالجهة أو نحوها كذب صراح عليه وعلى أصحابه المتقدمين كما أفاده ابن الجوزي من أكابر الحنابلة، وما وقع في كلام بعض المحدّثين والفقهاء ممّا يوهم الجهة أو التجسيم أوّله العلماء، وقالوا إنّ ظاهره غير مراد، فعليك بحفظ هذا الاعتقاد، واحذر زيغ المجسّمة والجهمية أرباب الفساد',
      'عقيدة إمام السنة أحمد بن حنبل رضي الله عنه وأرضاه وجعل جنان المعارف متقلَّبه ومأواه وأفاض علينا وعليه من سوابغ إمتنانه وبوأه الفردوس الأعلى من جنانه، موافقة لعقيدة أهل السنة والجماعة من المبالغة التامة في تنزيه الله تعالى عما يقول الظالمون والجاحدون علوًا كبيرًا من الجهة والجسمية وغيرهما من سائر سمات النقص، بل وعن كل وَصْف ليس فيه كمال مطلق، وما اشتهر بين جهلة المنسوبين إلى هذا الإمام الأعظم المجتهد من أنه قائل بشيء من الجهة أو نحوها فكذب وبُهتان وافتراء عليه، فلعن الله من نسب ذلك إليه، أو رماه بشيء من هذه المثالب التي برَّأه الله منها، وقد بيّـن الحافظ الحجة القدوة الإمام أبو الفرج بن الجوزي من أئمة مذهبه المبرئّيـن من هذه الوصمة القبيحة الشنيعة، أنَّ كل ما نسب إليه من ذلك كذب عليه وافتراء وبهتان وأن نصوصه صريحة في بطلان ذلك، وتنزيه الله تعالى عنه فاعلم ذلك فإنه مهم',
      'و إن ربي قال: يا محمد إني إذا قضيت قضاء فإنه لا يرد',
      'ما شاءَ اللهُ كانَ وما لَمْ يَشَأْ لَمْ يَكُنْ',
      'لا يردُّ القضاء إلا الدعاءُ',
      'إن القول بإثبات الجهة له تعالى كفر عند الأئمة الأربعة هداة الأمة كما نقل عنهم العراقي على ما في شرح المشكاة لعلي القاري',
      '{وجاء ربك} قال الحسن : جاء أمره وقضاؤه وقال الكلبي : ينزل حكمه',
      '{وَهُوَ الْقَاهِرُ فَوْقَ عِبَادِهِ} القادرُ الغالبُ، والمرادُ بفَوْقَ: علوُّ القدرةِ والشأنِ؛ كقوله: {وَإِنَّا فَوْقَهُمْ قَاهِرُونَ}',
      'إذا أطلق أهل السنة والجماعة فالمراد بهم الأشاعرة والماتريدية',
      'زيارة القبور مستحبة على الجملة للتذكر والاعتبار وزيارة قبور الصالحين مستحبة لاجل التبرك مع الاعتبار وقد كان رسول الله صلى الله عليه وسلم نهى عن زيارة القبور ثم أذن في ذلك بعد',
      'وما أحسن قول الإمام المهدي [أي محمد بن تومرت] في عقيدته حيث قال: لا يقالُ: متى كانَ؟ ولا أينَ كانَ؟ ولا كيفَ، كان ولا مكان، دبَّر الزمانَ، لا يتقيَّدُ بالزمانِ ولا يتخصَّصُ بالمكان',
      'إشارة إلى تكفيره بفساد اعتقاده كفساد اعتقاد المجسمة والمشبهة والقدرية ونحوهم',
      'صونوا عقائدكم من التمسك بظاهر ما تشابه من الكتاب والسنة فانّ ذلك من أصول الكفر',
      'بيــان: لا خلاف في تكفير من نفى الربوبية أو الوحدانية ، أو عبد مع الله غيره ، أو كان على دين اليهود أو النصارى أو المجوس أو الصابئين ، أو قال بالحلول أو التناسخ ، أو اعتقد أن الله غير حي أو غير عليم ، أو نفى عنه صفة من صفاته، أو قال: ( صنع العالم غيره) أو قال: ( هو متولد عن شيئ ) أو الدعى مجالسة الله حقيقة أو العروج إليه ، أو قال بقدم العالم ، أو شك في ذلك كله، أو قال بنبوة أحد بعد سيدنا محمد صلى الله عليه وسلم ، أو جوز الكذب على الأنبياء ـ عليهم الصلاة والسلام ـ أو قال بتخصيص الرسالة للعرب أو أدعى أنه يوحى إليه أو يدخل الجنة في الدنيا حقيقة ، أو كفر جميع الصحابة ـ رضي الله عنهم ـ أو جحد شيئا مما يعلم من الدين ضرورة ، أو سعى إلى الكنائيس في زي النصارى ، أو قال بسقوط العبادة عن بعض الأولياء ، أو جحد حرفا فأكثر من القرآن أوزاده أو غيره ، أو قال ليس بمعجز ، أو قال : ( الثواب والعقاب معنويان) أو قال: ( الأئمة أفضل من الأنبياء )',
      'وَمَنْ لَمْ يُؤْمِنْ بِاللهِ وَرَسُولِهِ فَإِنَّا أَعْتَدْنَا لِلْكَافِرِينَ سَعِيراً',
      'قُلْ أَطِيعُوا اللهَ وَالرَّسُولَ فَإِنْ تَوَلَّوْا فَإِنَّ اللهَ لاَ يُحِبُّ الْكَافِرِينَ',
      'وَمَن يَبْتَغِ غَيْرَ الإِسْلاَمِ دِينًا فَلَن يُقْبَلَ مِنْهُ وَهُوَ فِي الآخِرَةِ مِنَ الْخَاسِرِينَ',
      'إِنَّ الدِّينَ عِنْدَ اللهِ الإِسْلاَم',
      '« والذي نفْسُ محمدٍ بيدِهِ ، لا يسمعُ بي أحدٌ من هذه الأمةِ ، لا يهودِيٌّ ، و لا نصرانِيٌّ ، ثُمَّ يموتُ ولم يؤمِنْ بالذي أُرْسِلْتُ به ، إلَّا كان من أصحابِ النارِ «',
      'إِنَّ اللهَ لاَ يَغْفِرُ أَنْ يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَلِكَ لِمَنْ يَشَاءُ',
      'إِنَّ الَّذِينَ كَفَرُوا وَصَدُّوا عَنْ سَبِيلِ اللهِ ثُمَّ مَاتُوا وَهُمْ كُفَّارٌ فَلَنْ يَغْفِرَ اللهُ لَهُمْ',
      'إنَّ الذِينَ كَفَرُوا وظَلَمُوا لَمْ يَكُنِ اللهُ لِيَغْفِرَ لَهُم ولا لِيَهْدِيَهُم طَرِيقًا إِلاّ طَرِيقَ جَهَنَّمَ خالِدِينَ فيها أَبَدًا',
      'مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آَمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ',
      'وَرَحْمَتِي وَسِعَتْ كُلَّ شَيْءٍ فَسَأَكْتُبُهَا لِلَّذِينَ يَتَّقُونَ',
      'مَثَلُ الّذِينَ كَفَرُواْ بِرَبِّهِمْ أَعْمَالُهُمْ كَرَمَادٍ اشْتَدّتْ بِهِ الرِّيحُ فِي يَوْمٍ عَاصِفٍ',
      '« وَأَمَّا الْكَافِرُ فَيُطْعَمُ بِحَسَنَاتِهِ في الدُّنْيَا حَتّى إِذا أَفْضَى إِلى الآخِرَةِ لَم يَكُنْ لُهُ مِنْهَا نَصِيبٌ «',
      'يَجِبُ عَلَى كُلِّ بَالِغٍ عَاقِلٍ أَنْ يَعْلَمَ أَن لَا إِلَهَ إِلَّا الـلَّهُ سُبْحَانَهُ وَتَعَالَى وَأَنَّهُ وَاحِدٌ لَا شَرِيكَ لَهُ قَدِيمٌ لَا أَوَّلَ لَهُ دَائِمٌ لَا آخِرَ لَهُ لَيْسَ لَهُ ضِدٌّ، وَلَا نَظِيرٌ، وَلَا مُعِينٌ، وَلَا وَزِيرٌ، وَلَا تُـمَاثِلُهُ الـمَوْجُودَاتُ، وَلَا يُمَاثِلُهَا، وَلَا تَـحْوِيهِ الأَزْمَانُ، وَلَا الجِهَاتُ، وَلَا يَحُلُّ فِيهَا وَلَا يَحْتَاجُ إِلَى مَكَانٍ، وَلَا يَفْتَقِرُ إِلَى زَمَانٍ',
      'يفتح هذا الموضع المبارك – أي منزل النبي صلى الله عليه وسلم- فيدخله الناس كافة متبركين به في شهر ربيع الأول ويوم الاثنين منه، لأنه كان شهر مولد النبي صلى الله عليه وسلم، وفي اليوم المذكور الذي ولد فيه النبي صلى الله عليه وسلم، تفتح المواضع المقدسة المذكورة كلها وهو يوم مشهود بمكة دائما',
      'فأما الحرة فجميع بدنها عورة إلا الوجه والكفين لقوله تعالى : {وَلا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا } [النور: ٣١] قال ابن عباس رضي الله عنهما: وجهها وكفيها ولأن النبي صلى الله عليه وسلم نهى المرأة في الحرام عن لبس القفازين والنقاب ولو كان الوجه والكف عورة لما حرم سترهما في الإحرام',
      '« يا أسماء إن المرأة إذا بلغت المحيض لم تصلح أن يُرى منها إلا هذا وهذا » وأشار إلى وجهه وكفيه.',
      'لا تَنْتَقِبُ الْمَرْأَةُ الْمُحْرِمَةُ وَلا تَلْبَسُ الْقُفَّازَيْنِ',
      'وأنه لا يشبه شيئا ولا يشبهه شيء، ومن شبَّهه بخلقه فقد كفر، نص عليه أحمد، وكذا من جسَّم، أو قال إنه جسم لا كالأجسام، ذكره القاضي',
      'ثم قال : « ومن قال إنه بذاته في كل مكان أو في مكان، فكافر »',
      'ثم تكلم عن حكم الفئة الباغية وهم عصاة متأولون كمقاتلة عثمان ومقاتلة علي يوم صفين ويوم الجمل ولا يخرجهم القتال بالتأويل إلى حد الكفر فيغسل قتلاهم ،ويصلى عليهم، ولا يتبعون بما استهلكوا من الأموال إذا تابوا ، ولم يطالب أحد من البغاة المقاتلين لعلي رضي الله عنه في صفين بما استهلكوا من نفوس وأموال ، وقد أجمع أهل الحل والعقد على أن فئة معاوية بغاة ظلمة بالتأويل .',
      'وَيْحَ عَمَّار تَقْتُلُهُ الْفِئَةُ البَاغِيَةُ',
      'ومنهم المجسمة لأنهم يقولون بالجسم والحلول ومعتقد هذا لا يصح منه الايمان […] لأن من لا يعرف معبوده كيف يصح له الايمان به وذلك محال',
      '« بيان معنى العلو في قوله تعالى: ﴿الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى﴾',
      'الله سبحانه وتعالى لا يحويه مكان.',
      'من ثوابت العقيدة عند المسلمين أن الله تعالى لا يحويه مكانٌ ولا يحدُّه زمانٌ؛ لأن المكان والزمان مخلوقين، وتعالى الله سبحانه أن يحيط به شيءٌ من خلقه، بل هو خالق كل شيء، وهو المحيط بكل شيء، وهذا الاعتقاد متفقٌ عليه بين المسلمين، وقد عبَّر عن ذلك أهل العلم بقولهم: كان الله ولا مكان، وهو على ما كان قبل خلق المكان، لم يتغير عمَّا كان. »',
      '« والنبي ﷺ حين سئل عن صوم يوم الإثنين قال : « ذلك يوم ولدت فيه » فلمح إلى الاحتفال به لكونه ولد فيه . و صام يوم عاشوراء وأمر بصيامه احتفالا بنجاة موسى ، والله تعالى شرع لنا العقيقة فرحا بوجود الولد . أنفرح بوجود ولد و نذبح عنه ولا نفرح بوجود النبي ﷺ ؟ وعدم الاحتفال به في عهد السلف لا يدل على منعه، وإنما يدل على جواز تركه ، وهذه قاعدة أصولية لا يعرفها كثير من الناس ، وهي داخلة في العبادات أيضا ، ودليلها عدة أحاديث مذكورة في كتابي « إتقان الصنعة » والذي سألك لم يتنبه لها ، لانه متشبع بفكرة كل ما لم يحدث في عهد السلف فهو بدعة لا تجوز»',
      'فإذا وجدت في كلام الله أو كلام رسوله ما يوهم المماثلة فلا تعتقد ظاهره لإجماع العلماء على تأويله أي صرفه عن ظاهره',
      '« في قول النبي صلى الله عليه وسلم لما سئل عن صيام يوم الإثنين؟: « ذاك يوم ولدت فيه وأنزلت علي فيه النبوة » إشارة إلى استحباب صيام الأيام التي تتجدد فيها نعم الله على عباده فإن أعظم نعم الله على هذه الأمة إظهار محمد صلى الله عليه وسلم لهم وبعثته وإرساله إليهم كما قال تعالى: {لَقَدْ مَنَّ اللَّهُ عَلَى الْمُؤْمِنِينَ إِذْ بَعَثَ فِيهِمْ رَسُولاً مِنْ أَنْفُسِهِمْ} »',
      'علا عليها علوّ مُلْك وسُلْطان، لا علوّ انتقال وزَوال',
      'واعلموا أن مذهب أهل الحق: أن الرب سبحانه يـتقـدس عـن شغــل حيـّـز ويتنزه عن الاختصاص بجهة',
      '« إطلاق لفظ النور على الله تعالى.',
      'قالت المشبهة : يجوز أن يقال بأن الله نور يتلألأ.',
      'وقال أهل السنة والجماعة :لا بل هو خالق النور ومنور النـور ، لأن النور له لون. فلو قلنا : بأنه نور يلزمنا التشبيه فالله تعالى منزه عن التشبيه قال تعالى : * ليس كمثله شيء وهو السميع البصير * هم احتجوا بقوله تعالى : * الله نور السماوات والأرض * سمى نفسه نوراً والجواب عنه أن نقول قال ابن عباس رضي الله عنهما يعني منور السموات والارض * وقال بعضهم هـادي أهل السموات والارض »',
      'ولا يعلم متى تقوم الساعة الا الله',
      'أنا فرَطُكم على الحوضِ وليختلجنَّ رجالٌ دوني فأقولُ : يا ربِّ أصحابي فيقال : إنك لا تدْري ما أحدَثوا بعدكَ',
      'ولم يُجِزْ عامَّةُ الفُقَهاءِ إخراجَ القيمةِ وأجازَهُ أبو حنيفة',
      'قَوْلُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ : (فَرَجَعْتُ إِلَى رَبِّي) مَعْنَاهُ رَجَعْتُ إِلَى الْمَوْضِعِ الَّذِي نَاجَيْتُهُ مِنْهُ أَوَّلًا فَنَاجَيْتُهُ فِيهِ ثَانِيًا. وَقَوْلُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ : (فَلَمْ أَزَلْ أَرْجِعُ بَيْنَ رَبِّي تَبَارَكَ وَتَعَالَى وَبَيْنَ مُوسَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ) مَعْنَاهُ بَيْنَ مَوْضِعِ مُنَاجَاةِ رَبِّي. وَاللَّهُ أَعْلَمُ.',
      'ويجب أن يعلم أن الله تعالى لا يتصف كلامه القديم بالحروف والأصوات ولا شىء من صفات الخلق وأنه تعالى لا يفتقر في كلامه إلى مخارج وأدوات بل يتقدس عن جميـع ذلك',
      'كَـــــانَ اللهُ وَلَــــمْ يَــــكُــــنْ شَــىءٌ غَــيْـــرُهُ',
      'السادس: بمعنى القهر والقدرة : {اسْتَوَى عَلَى الْعَرْشِ}{الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى}',
      'ما نص عليه الشافعي رحمه الله […] [من] اعتقد أن الله تعالی جالس على العرش ، فإنه يحكم بكفره ، ولا تصح الصلاة خلف هؤلاء',
      'استواء منزهاً عن المماسة والاستقرار والتمكن والحلول والانتقال : يعني لأن ذلك كله عليه محال، إذ هو من صفات المحدثات، وتعالى ربنا عن سمات الحدوث. هذا معنى ما أشار إليه مالك رحمه الله تعالى بقوله: والكيف غير معقول. وفي بعض الروايات: والكيفية مجهولة، ولا يصح لأن المجهولة يمكن تعلقها، وغير المعقول لا يتصور فهمه، وهو المراد هنا',
      '« قوله : « خلق الله آدم على صورته » الهاء وقعت كناية بين اسمين ظاهرين ، فلم تصلح أن تصرف إلى الله عز وجل ، لقيام الدليل على أنه ليس بذي صورة سبحانه ليس كمثله شيء ، فكان مرجعها إلى آدم عليه السلام »',
      'قوله : لا نكفر أحدا من أهل القبلة. أقول : هذا الكلام قد اشتهر بين الناس ونقل عن الأئمة مثل الشافعي و أبي حنيفة و ليس على إطلاقه إذ المجسم كافر و إن صام و صلى',
      'وَأمَّا الصَّلاةُ عَلَى الكَافِرِ والدّعَاءُ لَهُ بِالمَغْفِرَةِ فَحَرَامٌ بِنَصِّ القُرآنِ وَالإِجمَاع',
      'وَمَنْ يَبْتَغِ غَيْرَ الإِسْلاَمِ دِيناً فَلَنْ يُقْبَلَ مِنْهُ',
      'لا يجوز اسباله تحت الكعبين إن كان للخيلاء فإن كان لغيرها فهو مكروه وظواهر الأحاديث في تقييدها بالجر خيلاء تدل على أن التحريم مخصوص بالخيلاء وهكذا نص الشافعي على الفرق كما ذكرنا وأجمع العلماء على جواز الاسبال للنساء وقد صح عن النبي صلى الله عليه وسلم الاذن لهن في ارخاء ذيولهن ذراعا',
      'لا ينظر اللهُ إلى من جَرَّ ثوبَهُ خُيَلاء',
      'مذهب أهل السنة أن المعرفة مرتبطة بالشهادتين لا تنفع إحداهما ولا تنجي من النار دون الأخرى الا لمن لم يقدر على الشهادتين لآفة بلسانه أو لم تمهله المدة ليقولها بل اخترمته المنية',
      '…أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأن محمدا رسول الله',
      'قال المتولي: […] وكذا التردد في أنه يكفر أم لا، فهو كفر في الحال',
      '« مذهب أهل الحق أن الله تعالى ليس في جهة و لا مكان.',
      'وقالوا في قوله تعالى {ٱلرَّحۡمَـٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ} المراد منه استولى.',
      'قال الشاعر: قد استوى بشر على العراق … من غير سيف ودم مهراق»',
      'خَمسُ صَلَواتٍ كَتَبهنَّ اللهُ على العبادِ، فمن جاء بهنَّ لم يُضَيِّعْ منهنَّ شَيئًا استِخفافًا بحَقِّهنَّ، كان له عند الله عَهدٌ أن يُدخِلَه الجنَّةَ، ومن لم يأتِ بهنَّ فليس له عند اللهِ عَهدٌ؛ إن شاء عَذَّبه، وإن شاء أدخَلَه الجنَّةَ',
      'واليد في كلام العرب تكون للجارحة كقوله تعالى (وَخُذْ بِيَدِكَ ضِغْثًا) وهذا محال على الله تعالى',
      'قال ابن حجر الهيتمي : إن البدعة الحسنة متفق على ندبها و عمل المولد و اجتماع الناس له كذلك اي بدعة حسنة',
      'فأما نفي المكان عنه فدليله ما ذكره من أنه مكون المكان، وذلك شاهد بأنه كان قبل خلق المكان، فلا يصح في حقه المكان',
      'قوله فلا يزال يدعو الله تعالى حتى يضحك الله تعالى منه قال العلماء ضحك الله تعالى منه هو رضاه بفعل عبده ومحبته اياه واظهار نعمته عليه وايجابها عليه والله أعلم',
      'الجميل : هو المجمل المحسن',
      'نعلمكم بأن اتجاه القبلة بالنسبة لأهل الولايات المتحدة الأمريكية و كندا هو الجنوب الشرقي و ذلك لأن أمريكا الشمالية واقعة في الربع الشمالي الغربي بالنسبة لمكة و من صلى إلى الشمال الشرقي فاتجاهه غير صحيح و صلاته كذلك',
      'الرب تعالى متقدس عن الاختصاص بالجهات, والاتصاف بالمحاذاة, لا تحده الأفكار, و لا تحيط به الأقطار ولا تكتنفه الأقتار ويجل عن قبول الحد والمقدار',
      'غضب: قد تكرر ذكر (الغضب) في الحديث من الله تعالى ومن الناس، فأما غضب الله فهو إنكاره على من عصاه وسخطه عليه وإعراضه عنه ومعاقبته له، وأما من المخلوقين فمنه محمود ومذموم، فالمحمود ما كان في جانب الدين والحق، والمذموم ما كان في خلافه.»',
      'وجرت العادة بمكة في ليلة الاثنين عشر من ربيع الأول في كل عام أن قاضي مكة الشافعي يتهيأ لزيارة هذا المحل الشريف بعد صلاة المغرب في جمع عظيم منهم الثلاثة القضاة، وأكثر الأعيان من الفقهاء والفضلاء وذوي البيوت بفوانيس كثيرة، وشموع عظيمة، وزحام عظيم',
      '« ما حكمُ الاحتفالِ بالمولدِ النَّبَوِيِّ الشَّرِيفِ؟',
      '[…] وقد سنَّ لنا رسولُ اللهِ ﷺ بنفسه جنسَ الشكرِ لله تعالىٰ علىٰ ميلاده الشريف؛ فقد صحَّ أنه ﷺ كان يصوم يوم الاثنين، فلما سُئل عن ذلك قال: «ذلك يومٌ وُلِدتُ فيه» أخرجه مسلم.',
      'وإذا ثبت ذلك وعُلم فمن الجائز للمسلم -بل من المندوبات له- ألا يمرَّ يومُ مولدِه من غير البهجة والسرور والفرح به ﷺ، وإعلانِ ذلك، واتخاذِ ذلك عُنوانًا وشعارًا.',
      'قال الإمام السخاويُّ رحمه الله تعالىٰ في (الأجوبة المرضية) : (ثم ما زال أهلُ الإسلامِ في سائر الأقطار والمدن العظام يحتفلون في شهر مولده ﷺ وشرَّف وكرَّم، يعملون الولائمَ البديعةَ المشتملةَ علىٰ الأمورِ البهِجَةِ الرفيعة، ويتصدقون في لياليه بأنواع الصدقات، ويُظهرون السرورَ، ويَزيدون في المبرَّاتِ، بل يعتنون بقراءة مولدِه الكريمِ، وتظهر عليهم من بركاته كلُّ فَضْلٍ عميم)اهـ.',
      'وما ذكره الإمامُ السخاويُّ رحمه الله تعالىٰ هو ما نقصده بعمل المولدِ النبويِّ الـمُنيف صلىٰ الله وسلم علىٰ صاحبه.',
      'فهل ينكر عاقلٌ ذو لُبٍّ سليمٍ جوازَ الفرحِ بمولدِه، والاحتفاءِ بطلعته المُنيرةِ علىٰ الأرض ﷺ بهذه الطريقة الشرعية التي تندرج كلُّ تفصيلةٍ منها تحتَ أصلٍ من أصولِ الشرع الشريف، وقواعده الكلِّيَّة!',
      'وعليه؛ فالاحتفال بمولده ﷺ من المندوبات، وهو مظهر من مظاهر تعظيمه وتوقيره ﷺ الذي هو عنوان محبته ﷺ التي لا يكتمل إيمانُ العبدِ إلا بتحقيقها.',
      'وَمِمَّا ذُكِرَ يُعلَمُ الْـجَـوَابُ. »',
      'وَأَمَّا الصَّغَائِرُ فَجَوَّزَهَا جَمَاعَةٌ مِنَ السَّلَفِ وَغَيْرُهُمْ عَلَى الْأَنْبِيَاءِ وَهُوَ مَذْهَبُ أَبِي جَعْفَرٍ الطَّبَرِيِّ وَغَيْرِهِ مِنَ الْفُقَهَاءِ وَالْمُحَدِّثِينَ وَالْمُتَكَلِّمِينَ',
      '(وَأَمَّا الصَّغَائِرُ فَجَوَّزَهَا) أي وجودها ووقوعها (جَمَاعَةٌ مِنَ السَّلَفِ وَغَيْرُهُمْ) مِن الخلف كإمام الحرمَين منَّا وأبي هاشم مِن المُعتزلة حيث جوَّزوا الصَّغائر غير المُنفِّرة (عَلَى الْأَنْبِيَاءِ وَهُوَ مَذْهَبُ أَبِي جَعْفَرٍ الطَّبَرِيِّ وَغَيْرِهِ مِنَ الْفُقَهَاءِ) أي المُجتهدِين (وَالْمُحَدِّثِينَ وَالْمُتَكَلِّمِينَ) أي في أصول الدِّين والمُراد بعضٌ مِن كُلٍّ منهم',
      'وأما المبتدع المتفق على كفره كالمجسمة و أشباههم فإنه كغيره من الكفار, لا توارث بينه و بين المسلمين',
      '{كل شيء هالك } أي فانٍ { إلا وجهه } أي إلا هو والوجه يعبر به عن الذات وقيل معناه إلا ما أريد به وجهه لأن عمل كل شيء أريد به غير الله فهو هالك',
      'واختلف المشايخ رحمهم اللّه تعالى في زيارة القبور للنّساء قال شمس الأئمّة السّرخسيّ رحمه اللّه تعالى الأصحّ أنّه لا بأس بها وفي التّهذيب يستحبّ زيارة القبور',
      'لكنَّه مُخالف لظاهر القُرآن؛ قال الله تعالى: {وَقَدِمْنَا إِلَىٰ مَا عَمِلُوا مِنْ عَمَلٍ فَجَعَلْنَاهُ هَبَاءً مَّنثُورًا} [الفُرقان/23]، وأُجيب أوَّلًا بأنَّ الخبر مُرسل أرسله عُروة ولم يذكر مَن حدَّثه به وعلى تقدير أنْ يكون موصولًا فالَّذي في الخبر رُؤيا منام فلا حُجَّة فيه ولعلَّ الَّذي رآها لم يكن إذ ذاك أسلم بعدُ فلا يُحتجُّ به',
      'ثم قال «وأما عياض فقال : انعقد الإجماع على أنَّ الكُفَّار لا تنفعهم أعمالهم، ولا يُثابون عليها بنعيم ولا تخفيف عذاب، و ان كان بعضهم أشدُّ عذابًا مِن بعض »',
      'وَأَمَّا الْكَافِرُ فَيُطْعَمُ بِحَسَنَاتِهِ فِي الدُّنْيَا حَتَّى إِذَا أَفْضَى إِلَى الْآخِرَةِ لَمْ يَكُنْ لَهُ حَسَنَةٌ يُعْطَى بِهَا خَيْرًا',
      'إن المشبهة ينسبون للخالق ذي الجلال الأعضاء كالمخلوقات فلا تجوز الصلاة خلفهم، فهؤلاء خارجون من الإسلام، من نسب المكان لله أو قال إنه في السماء أيضًا خارج من الإسلام، وكذا يُحكم بالكفر على من اعتقد أن الحق تعالى مستقر على العرش، فويلٌ للوهابية',
      'المظاهر الدينية للاحتفال بذكرى مولد النبي الشريف؛ كقراءة القرآن الكريم، وتلاوة السيرة العطرة، وإحياء مجالس الصلاة على النبي صلى الله عليه وآله وسلم، والإنشاد والتغني بمدائحه الكريمة وشمائله العظيمة، كل ذلك جائز ومستحب شرعًا.',
      'عن قتادة : ( وكان عرشه على الماء ) ، قال : هذا بدء خلقه قبل أن يخلق السماء والأرض',
      'ولا بأس بقراءة القرآن على القبور',
      'إِقْرَءُوا يَس عَلَى مَوْتَاكُم',
      'وَلَقَدْ أُوذِىَ أُنَاسٌ فِى بَيْرُوتَ لِأَنَّهُمْ مَا وَافَقُوا عَلَى صِيَامِ رَمَضَانَ بِقَوْلِ الْمُنَجِّمِ الْفَلَكِىِّ، وَالإِجْمَاعُ إِجْمَاعُ عُلَمَاءِ الإِسْلامِ قَدِ انْعَقَدَ أَنَّ صِيَامَ رَمَضَانَ لا يَثْبُتُ بِقَوْلِ الْفَلَكِىِّ لِأَنَّ الرَّسُولَ ﷺ وَضَعَ قَانُونًا سَمَاوِيًّا فَقَالَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا عِدَّةَ شَعْبَانَ ثَلاثِينَ اهـ [رَوَاهُ الْبُخَارِىُّ] جَمَاعَتُنَا وَقَفُوا عِنْدَ هَذَا الْحَدِيثِ وَلَمْ يُوَافِقُوا مَنْ أَثْبَتَ رَمَضَانَ بِقَوْلِ الْفَلَكِىِّ ثُمَّ أُوذُوا عَلَى ذَلِكَ أَذًى شَدِيدًا حَتَّى مِنْ قِبَلِ بَعْضِ أَصْحَابِ الْعَمَائِمِ مَعَ أَنَّ الَّذِى دَرَسُوهُ فِى دِرَاسَاتِهِمْ هُوَ أَنَّ الصِّيَامَ لا يَثْبُتُ بِقَوْلِ الْفَلَكِىِّ',
      'لا تقَدّموا رمضان بيوم أو يومين صُوموا لِرُؤيَتِهِ وأَفْطِروا لرؤيته فإن غُمَّ عَلَيكُم فَأَكْمِلُوا عِدَّةَ شَعْبَان ثَلاثين يوماً',
      'إنا أمة أمية لا نكتب ولا نحسب الشهر هكذا وهكذا يعني مرة تسعة وعشرين ومرة ثلاثين',
      'باب الدعاء للميت بعد دفنه والقعود عند قبره ساعة للدعاء لَهُ والاستغفار والقراءة',
      'فقال : « قَالَ الشَّافِعِيُّ رَحِمهُ اللَّه: وَيُسْتَحَبُّ أَنْ يُقْرَأَ عِنْدَهُ شَيْءٌ مِنَ القُرآنِ، وَإنْ خَتَمُوا القُرآنَ عِنْدَهُ كَانَ حَسَنًا »',
      '( و) الله ( الذي نفسي بيده) أي بتقديره وتدبيره',
      'وسئل الإمام أحمد رضي الله عنه عن الاستواء، فقال : استوى كما أخبر، لا كما يخطرُ للبشر',
      'حدثنـي مـحمد بن عمرو, قال: حدثنا أبو عاصم, قال: حدثنا عيسى, عن ابن أبـي نـجيح, عن مـجاهد, فـي قول الله: {وكانَ عَرْشُهُ علـى الـمَاءِ} قال : كانَ عَرْشُهُ علـى الـمَاءِ قبل أن يخـلق شيئا.',
      'و تقدم أيضا أن بلالا رضي الله تعالى عنه لما قدم من الشام لزيارة النبى صلى الله تعالى عليه وسلم أتى القبر فجعل يبكى عنده ويمرغ وجهه عليه .واسناده جيد كما سبق',
      'من زار قبري وجبت له شفاعتي',
      'أصول طريق التصوف خمسة: تقوى الله في السر والعلانية، واتباع السنة في الأقوال والأفعال، الإِعراض عن الخلق في الإِقبال والإِدبار، الرضى عن الله في القليل والكثير، والرجوع إِلى الله في السراء والضراء',
      'ولا زال أهل الإسلام يحتفلون ويهتمون بشهر مولده عليه الصلاة والسلام ويعملون الولائم ويتصدقون في لياليه بأنواع الصدقات ويظهرون السرور ويظهر عليهم من بركاته كل فضل عميم. وأول من أحدث فعل المولد الملك المظفر ابو سعيد صاحب اربل فكان يعمله في ربيع الأول ويحتفل احتفالاً هائلاً',
      'ثم يمدح الملك المظفر بقوله : « وكان شهما شجاعا بطلا عاقلا عالما عادلا »',
      'وللفظ (استوى) محامل: (جلس) و (اعتدل) و (استولى) و (علا) مكانا أو رتبة و (قصد)، كقوله تعالى: {ثُمَّ اسْتَوَى إِلَى السَّمَاءِ} [البقرة: 29]: قصد إلى فعل أمر فيها. فالأولان والرابع بمعنى علوِّ المكان محالات في حقه تعالى، بخلاف ما عداها! والعرش لغة سرير الملك والسقف',
      'وبالجملة فيجب على كل مؤمن أن يعتقد من هذا الحديث ومشابهه من المشكلات الواردة في الكتاب والسنة كـ: {الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى} ، {وَيَبْقَى وَجْهُ رَبِّكَ} ،{يَدُ اللَّهِ فَوْقَ أَيْدِيهِمْ} , وغير ذلك مما شاكله أنه ليس المراد بها ظواهرها لاستحالتها عليه تبارك وتعالى عما يقول الظالمون والجاحدون علوًا كبيرًا، ثم هو بعد ذلك مخير إن شاء أولها بنحو ما ذكرناه وهي طريقة الخلف وآثروها لكثرة المبتدعة القائلين بالجهة والجسمية وغيرهما مما هو محال على الله تعالى وإن شاء فوض علمها إلى الله تعالى وهي طريقة السلف وآثروها لخلو زمانهم عما حدث من الضلالات الشنيعة والبدع القبيحة فلم يكن لهم حاجة إلى الخوض فيها',
      'أن عمر بن الخطاب رضي الله عنه كان إذا قحطوا استسقى بالعباس بن عبد المطلب فقال اللهم إنا كنا نتوسل إليك بنبينا فتسقينا وإنا نتوسل إليك بعم نبينا فاسقنا قال فيسقون',
      'إذا سَأَلْتَ فَاسْألِ اللهَ وَ إذا اسْتَعَنْتَ فَاسْتَعِنْ بِاللهِ',
      'لا تُصَاحِبْ إلّا مُؤمِناً وَ لا تَأكُل طَعَامَكَ إلّا تَقِي',
      'وَيُطۡعِمُونَ ٱلطَّعَامَ عَلَىٰ حُبِّهِۦ مِسۡكِينً۬ا وَيَتِيمً۬ا وَأَسِيرًا',
      'اعلم رحمك الله أن زيارة قبر نبينا صلى الله عليه وسلم مشروعة مطلوبة بالكتاب والسنة وإجماع الأمة',
      '« فإن سئلنا عن قوله تعالى :{الرحمن على العرش استوى} قلنا : المراد بـ «الاستواء» القهر والغلبة والعلو. ومنه قول العرب : استوى فلان على المملكة أي استعلى عليها واطردت له. ومنه قول الشاعر : قد استوى بشر على العراق … من غير سيف ودم مهراق »',
      'أخبرنا أبو الوليد الطيالسي ثنا حماد بن سلمة عن محمد بن عمرو عن أبي سلمة عن الشريد قال أتيت النبي صلى الله عليه و سلم فقلت إن على أمي رقبة وإن عندي جارية سوداء نويبية أفتجزىء عنها قال ادع بها فقال أتشهدين أن لا إله إلا الله قالت نعم قال اعتقها فإنها مؤمنة',
      'قوله تعالى : {تجري بأعيننا} فالمراد به الأعين التي انفجرت من الأرض وإضافته إلى الله سبحانه على سبيل الملك',
      '« قال [النبي] :« صوموا لرؤيته، وأفطروا لرؤيته، فإنْ غُمَّ عليكم فأكمِلُوا العِدّة» فتبين أن ديننا لا يحتاج إلى حساب ولا كتاب، كما يفعله أهل الكتاب من ضبط عباداتهم بمسير الشمس وحسباناتها، وأن ديننا في ميقات الصيام معلق بما يُرى بالبصر وهو رؤية الهلال، فإن غمّ أكملنا عدة الشهر ولم نحتج إلى حساب.»',
      'ويلهج المسكين في موضع بحديث (أين الله) على اضطرابه متناً وسنداً مع أن (أين) قد تكون للسؤال عن المكان وقد تكون للسؤال عن المكانة، فيكون الحديث بمعنى ما هي مكانة الله عندك؟ كما نجد تفصيل ذلك في عارضة أبي بكر العربي، ومن المعروف بين العرب قولهم: فلان مكانه في السماء، يعنون علو شأنه من غير ملاحظة السماء ولا التمكن فيها أصلاً، ومن هذا القبيل قول نابغة بني جعد: علونا السماء مجدنا وجدودنا … وإنا لنبغي فوق ذلك مظهرا',
      'وأما الصلاة على النبي صلى الله عليه وسلم بعد الأذان فبدعة حسنة',
      'وقيل هذه الآية نزلت في الخوارج الذين يحرفون تأويل الكتاب والسنة ويستحلون بذلك دماء المسلمين وأموالهم كما هو مشاهد الآن في نظائرهم وهو فرقة بأرض الحجاز يقال لهم الوهابية يحسبون أنهم على شئ إلا أنهم هم الكاذبون استحوذ عليهم الشيطان فأنساهم ذكر الله أولئك حزب الشيطان ألا إن حزب الشيطان هم الخاسرون نسأل الله الكريم أن يقطع دابرهم',
      'قوله تعالى في الإنباء عن سفينة نوح عليه السلام: {تجري بأعيننا} [القمر: 14] ولم يثبت أحد من المنتمين إلى التحقيق أعينا لله تعالى. والمعنى بالأية أنها تجري بأعيننا، وهي منا بالمكان المحوط بالملائكة والحفظ والرعاية، يقال: فلان بمرأى من الملك ومسمع، إذ كان بحيث تحوطه عنايته وتكتنفه رعايته، وقيل المراد بالأعين فى هذه الآية، الأعين التي انفجرت من الأرض، وأضيفت إلى الله تعالى ملكا، وهذا غير بعيد',
      'الحمد لله الكبير المتعال، المنعوت بنعوت الجلال، الموصوف بصفات الكمال، تنزه عن الشكل و الصورة و المثال، و تعالى أن يكون في مكان أو يمر عليه زمان',
      'مباينا أيضا لجنس الحرف و الصوت و الفكرة دون خلف',
      'استوى على العرش المجيد على الوجه الذي قال، وبالمعنى الذي أراده، استواء منزها عن المماسّة والاستقرار والتمكن والحلول والانتقال، فتعالى الله الكبير المتعال عما يقوله أهل الغي والضلال، لا يحمله العرش، بل العرش وحملته محملون بلطف قدرته، مقهورون في قبضته، أحاط بكل شيء علما، وأحصى كل شيء عددا',
      '« من قال بأن الله جسم فهو كافر إجماعا . ولهذا قال إمام الحرمين في « الإرشاد » : إثبات الجهة لله كفر صراح »',
      'الإمام أبو بكر أحمد بن الحسين البيهقي قال : […] إلى أن بلغت النوبة إلى شيخنا أبي الحسن الأشعري رحمه الله فلم يحدث في دين الله حدثا ولم يأت فيه ببدعة بل أخذ أقاويل الصحابة والتابعين ومن بعدهم من الأئمة في أصول الدين فنصرها بزيادة شرح وتبيين وأن ما قالوا في الأصول وجاء به الشرع صحيح في العقول خلاف ما زعم أهل الأهواء من أن بعضه لا يستقيم في الآراء فكان في بيانه تقوية ما لم يدل عليه من أهل السنة والجماعة ونصرة أقاويل من مضى من الأئمة كأبي حنيفة وسفيان الثوري من أهل الكوفة والأوزاعي وغيره من أهل الشام ومالك والشافعي من أهل الحرمين ومن نحا نحوهما من الحجاز وغيرها من سائر البلاد وكأحمد ابن حنبل وغيره من أهل الحديث والليث بن سعد وغيره وأبي عبد الله محمد بن اسمعيل البخاري وأبي الحسن مسلم بن الحجاج النيسابوري إمامي أهل الآثار وحفاظ السنن التي عليها مدار الشرع رضي الله عنهم أجمعين وذلك دأب من تصدى من الأئمة في هذه الأمة وصار رأسا في العلم من أهل السنة في قديم الدهر وحديثه وبذلك وعد سيدنا المصطفى صلى الله عليه و سلم أمته فيما روي عنه أبو هريرة رضي الله عنه إنه قال : {يبعث الله لهذه الأمة على رأس كل مائة سنة من يجدد لها دينها}',
      'اللهم إنا نتوسل إليك بجاه أحب الخلق إليك وأعظمهم قدراً عندك سيدنا ونبينا محمد وبجاه جميع الانبياء والرسل وأهل بدر وبجميع الأولياء والصديقين والشهداء والصالحين أن لا تدع لنا ذنباً إلا غفرته ولا هماً إلا فرجته ولا عيباً إلا سترته ولا ديناً إلا أديته ولا عدواً إلا كفيته ولا مريضاً إلا شفيته ولا حاجة لك فيها رضا ولنا فيها صلاح إلا قضينا يا أرحم الراحمين يارب العالمين',
      'و إضافة عرش إلى اللّه إضافة تشريف مثل إضافة الكعبة إليه في قوله: {وَ طَهِّرْ بَيْتِيَ لِلطّٰائِفِينَ} الآية ، و اللّه منزه عن الجلوس على العرش و عن السكنى في بيت',
      'إن العلماء متفقون على انقسام البدعة إلى محمودة ومذمومة وأن عمر رضى الله عنه أول من نطق بذلك ومتفقون على أن قول النبي صلى الله عليه وسلم “كل بدعة ضلالة” عام مخصوص',
      '« وأما قوله عليه السلام : « ينزل الله في كل ليلة إلى سماء الدنيا » والمراد به انه يبعث ملكا إلى سماء الدنيا حتى ينادي على ما ورد في الخبر ثم أضاف نزول الملك إلى نفسه كما يقال نادى الأمير في البلد إذا أمر بالنداء ويقال قتل الأمير فلانا والقاتل غيره ويضاف إلى الأمير من حيث إنه هو الآمر به»',
      'وليس المحدث والبدعة مذمومًا للفظ محدث وبدعة ولا لمعناها، فقد قال الله تعالى: {مَا يَأْتِيهِمْ مِنْ ذِكْرٍ مِنْ رَبِّهِمْ مُحْدَثٍ} وقال عمر: نعمت البدعة هذه، وإنما يذم من البدعة ما خالف السنة، ويذم من المحدثات ما دعا إلى ضلالة',
      '« وقوله: « وإياكم ومحدثات الأمور » اعلم أن المحدث على قسمين: محدث ليس له أصل في الشريعة فهذا باطل مذموم. ومحدث بحمل النظير على النظير فهذا ليس بمذموم لأن لفظ « المحدث » ولفظ « البدعة » لا يذمان لمجرد الاسم بل لمعنى المخالفة للسنة والداعي إلى الضلالة ولا يذم ذلك مطلقاً . فقد قال الله تعالى: {مَا يَأْتِيهِمْ مِنْ ذِكْرٍ مِنْ رَبِّهِمْ مُحْدَثٍ} . وقال عمر رضي الله عنه: « نعمت البدعة هذه » يعني التراويح. »',
      'فأسأل النفع به على الدوام … من ربِّنا بجاه سيِّدِ الأنام',
      '« الســــؤال: أنا طالب بكلية الشريعة وقد تعلمت ودرست في علم العقيدة : أن الله موجود بلا مكان ولا يتحيز في أي جهة ، فأفتوني في ذلك ؛ حيث إن هناك بعض من يتهجم على عقيدة الأزهر .',
      'الـجـــواب : من ثوابت العقيدة عند المسلمين أن الله تعالى لا يحويه مكان ولا يحده زمان ؛ لأن المكان والزمان مخلـوقان ، وتعالى الله سبحانه أن يحيط به شيء من خلقه ، بل هو خالق كل شيء ، وهو المحيط بكل شيء ، وهذا الاعتقاد متفق عليه بين المسلمين لا يُنكره منهم مُنكِرٌ ، وقد عبَّر عن ذلك أهل العلم بقولهم : « كان الله ولا مكان ، وهو على ما كان قبل خلق المكان ؛ لم يتغير عما كان » .',
      'ومن عبارات السلف الصالح في ذلك : قول الإمام جعفر الصادق عليه السلام : « مَنْ زعم أن الله في شيء أو من شيء أو على شيء فقد أشرك ؛ إذ لو كان في شيء لكان محصورًا ، ولو كان على شيء لكان محمولا ، ولو كان من شيء لكان مُحْدَثًا » اهـ .',
      'وقيل ليحيى بن معاذ الرازي : أَخْبِرْنا عن الله عز وجل ، فقال : إله واحد ، فقيل له : كيف هو ؟ قال : ملك قادر ، فقيل له : أين هو ؟ فقال : بالمرصاد ، فقال السائل : لم أسألك عن هذا ؟ فقال : ما كان غير هذا كان صفة المخلوق ، فأما صفته فما أخبرت عنه .',
      'وسُئِل ذو النون المصري رضي الله عنه عن قوله تعالى { الرَّحْمَنُ عَلَى العَرْشِ اسْتَوَى } ، فقـال : « أثبت ذاته ونفى مكانه ؛ فهو موجود بذاته والأشياء بحكمته كما شاء » اهـ .',
      'وأما ما ورد في الكتاب والسنة من النصوص الدالة على علو الله عز وجل على خلقه فالمراد بها علو المكانة والشرف والهيمنة والقهر ؛ لأنه تعالى منـزه عن مشابهة المخلوقين ، وليست صفاته كصفاتهم ، وليس في صفة الخالق سبحانه ما يتعلق بصفة المخلوق من النقص ، بل له جل وعلا من الصفات كمالُها ومن الأسماء حُسْنَاها ، وكل ما خطر ببالك فالله تعالى خلاف ذلك ، والعجز عن درك الإدراكِ إدراكُ ، والبحث في كنه ذات الرب إشراكُ .',
      'وعقيدة الأزهر الشريف هي العقيدة الأشعرية وهي عقيدة أهل السنة والجماعة ، والسادة الأشاعرة رضي الله تعالى عنهم وأرضاهم هم جمهور العلماء من الأمة ، وهم الذين صَدُّوا الشبهات أمام المَلاَحِدَةِ وغيرهم ، وهم الذين التزموا بكتاب الله وسنة سيدنا رسول الله صلى الله عليه وآله وسلم عبر التاريخ ، ومَنْ كفّرهم أو فسّقهم يُخْشَى عليه في دينه .',
      'قال الحافظ ابن عساكر رحمه الله في كتابه « تبيين كذب المفتري فيما نسب إلى الإمام أبي الحسن الأشعري » : « اعلم وفقني الله وإياك لمرضاته ، وجعلنا ممن يتقيه حق تقاته ، أن لحوم العلماء مسمومة ، وعادة الله في هتك أستار منتقصيهم معلومة ، وأن من أطلق عليهم لسانه بالثلب ، ابتلاه الله قبل موته بموت القلب » اهـ .',
      'والأزهر الشريف هو منارة العلم والدين عبر التاريخ الإسلامي ، وقد كوَّن هذا الصرحُ الشامخُ أعظم حوزة علمية عرفتها الأمة بعد القرون الأولى المُفَضَّلة ، وحفظ الله تعالى به دينه ضد كل معاند ومشكك ؛ فالخائض في عقيدته على خطر عظيم ، ويُخْشَى أن يكون من الخوارج والمرجفين الذي قال الله تعالى فيهم :',
      'والله سبحانه وتعالى أعلم »',
      '« س: كثـر الكلام عن البدعة فمن الناس من يقسمها إلى قسمين، ومن الناس من لا يفرق فيجعل كل محدَث بعد الرسول مهما كان من البدع الضلالة، نرجو توضيح الأمر على حقيقته عند أهل السنة مع ذكر الأدلة الشرعية عند المذاهب الأربعة، مع بيان معنى البدعة لغة واصطلاحا ؟',
      'الجواب: نرفق لكم هذا البحث جوابا على سؤالكم :',
      'بيان أن البدعة بدعتان عند أهل السنة والجماعة وحديث: وكل بدعة ضلالة، عام مخصوص',
      'فالبدعة تنقسم إلى قسمين: بدعة ضلالة: وهي المحدثة المخالفة للقرءان والسنة. وبدعة هدى: وهي المحدثة الموافقة للكتاب والسنة.',
      'فإن قيل: أليس قال رسول الله صلى الله عليه وسلم فيما رواه أبو داود عن العرباض بن سارية: « وإياكم ومحدثات الأمور فإن كل محدثة بدعة وكل بدعة ضلالة ». فالجواب: أن هذا الحديث لفظه عام ومعناه مخصوص بدليل الأحاديث السابق ذكرها فيقال: إن مراد النبي صلى الله عليه وسلم ما أحدث على خلاف الكتاب أو السنة أو الإجماع أو الأثر.',
      'هذا وأما من حيث التفصيل فالبدعة منقسمة إلى الأحكام الخمسة وهي الواجب والمندوب والمباح والمكروه والحرام كما نص علماء المذاهب الأربعة.»',
      'سُئِلَ الأَوْزَاعِيُّ , وَمَالِكٌ ، وَسُفْيَانُ الثَّوْرِيُّ ، والليث بن سعد عَنْ هَذِهِ الأَحَادِيثِ فَقَالُوا : أَمِرُّوهَا كَمَا جَاءَتْ بِلا كَيْفِيَّةٍ.',
      'والاستواء في قوله تعالى : { ثُمَّ اسْتَوَى عَلَى الْعَرْشِ} معناه استولى ، قاله الواحدي وقيل معناه القهر والغلبة. تقول العرب: استوى زيد على أرض كذا أي ملكهم وقهرهم، قال الشاعر: قد استوى بشر على العراق … من غير سيف ودم مهراق ولما أن كان العرش أعظم المخلوقات المهولة اكتفى بذكره عما دونه، إذ أن ما دونه تبع له',
      'قد زرته مرارا كثيرة وما حلت بي شدة في وقت مقامى بطوس فزرت قبر على بن موسى الرضا صلوات الله على جده وعليه ودعوت الله إزالتها عنى إلا أستجيب لي وزالت عنى تلك الشدة وهذا شيء جربته مرارا فوجدته كذلك',
      'ومن الإلحاد تسمية الله بالجوهر والجسم والعقل والعلة',
      'ووقــع ذكر اليد في القرآن والحديث مضافًا إلى الله تعالى، واتفق أهل السنة والجماعة على أنه ليس المراد باليد الجارحة التي هي من صفات المحدثات',
      'والبدعة في الأصل إحداث أمر لم يكن في زمن رسول الله صلى الله عليه وسلم، ثم البدعة على نوعين، إن كانت مما تندرج تحت مستحسن في الشرع فهي بدعة حسنة وإن كانت مما يندرج تحت مستقبح في الشرع فهي بدعة مستقبحة',
      '« الحمد لله الذي تنـزه عن الحد والأين والكيف والزمان والمكان .المتكلم بكلام قديم أزلي صفة من صفاته قائم بذاته لا منفصل عنه ولا عائد إليه ولا يحُل في المحدثات ولا يجانس المخلوقات ولا يوصف بالحروف والأصوات تنـزَّهت صفات ربنا عن الأرض والسماوات. اللهم إنّا نُوَحِّدُك ولا نَحُدُّك ونؤمن بك ولا نكَيِّفُك ونعبدك ولا نُشَبِّهُك ونعتقد أن من شبهك بخلقك لم يعرف الخالق من المخلوق» و قال أيضا : « القُدُّوس على العرش استوى من غير تمكن ولا جلوس » فقال : « العرش بنفسه هو المكان وله جوانب وأركان وكان الله ولا مكان وهو الآن على ما عليه كان ليس له تحتٌ فيُقِلَّه ولا فوقٌ فيُظِلَّه ولا جوانب فتعدله ولا خلْف فيسنده ولا أمام فيحده. جل عن التجريد والتقرير والتكيف والتصوير والتشبيه والنظير.﴿لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّمِيعُ البَصيرُ﴾ »',
      'وقوله {يخافون ربهم من فوقهم} معناه يخافون ربهم أن ينزل عليهم عذابا من فوقهم',
      'لأن استواءه على العرش سبحانه ليس على معنى التمكن والاستقرار، بل هو على معنى العلو بالقهر والتدبير وارتفاع الدرجة بالصفة، على الوجه الذي يقتضي مباينة الخلق',
      '[ومما يستحيل في حق الله : ] المماثلة للحوادث بأن يكون جِرما أي تأخذ ذاته العليّة قدرا من الفراغ أو يكون عَرَضا يقوم بالجرم أو يكون في جهة للجرم أو له هو جهة أو يتقيد بمكان أو زمان أو تتصف ذاته العليّة بالحوادث أو يتصف بالصغر أو الكبر',
      '« وفسر الوجه بالملك. وكذا نقل الطبري عن بعض أهل العربية. وكذا ذكره الفراء وعن أبي عبيد إلا وجهه : إلا جلاله. قوله « ويقال » إلى آخره ، قال سفيان : معناه إلا ما أريد به رضاء الله والتقرب لا الرياء ووجه الناس »',
      'صِفَاتُ اللَّهِ جَلَّ وَعَلا لا تُكَيَّفُ ، وَلا تُقَاسُ إِلَى صِفَاتِ الْمَخْلُوقِينَ ، فَكَمَا أَنَّ اللَّهَ جَلَّ وَعَلا مُتَكَلِّمٌ مِنْ غَيْرِ آلَةٍ بَأَسْنَانٍ وَلَهَوَاتٍ وَلِسَانٍ وَشَفَةٍ كَالْمَخْلُوقِينَ ، جَلَّ رَبُّنَا وَتَعَالَى عَنْ مِثْلِ هَذَا وَأَشْبَاهِهِ ، وَلَمْ يَجُزْ أَنْ يُقَاسَ كَلامُهُ إِلَى كَلامِنَا ، لأَنَّ كَلامَ الْمَخْلُوقِينَ لا يُوجَدُ إِلا بِآلاتٍ ، وَاللَّهُ جَلَّ وَعَلا يَتَكَلَّمُ كَمَا شَاءَ بِلا آلَةٍ',
      '« فصل في تحقيق معنى البدعة وحكمها :',
      'اعلم أن البدعة لغة ما أحدث على غير مثال سابق يقال: جئت بأمر بديع أي محدث عجيب لم يعرف قبل ذلك. وفي الشرع المحدَثُ الذي لم ينص عليه القرءان ولا جاء في السنة، قال ابن العربي: « ليست البدعة والمحدَث مذمومين للفظ بدعة ومحدث ولا معنييهما، وإنما يذم من البدعة ما يخالف السنة، ويذم من المحدثات ما دعا إلى الضلالة » ا.هـ.',
      'أقسام البدعة: والبدعة تنقسم إلى قسمين: بدعة ضلالة: وهي المحدَثة المخالفة للقرءان والسنة. وبدعة هدى: وهي المحدَثة الموافقة للقرءان والسنة.',
      'وهذا التقسيم مفهوم من حديث البخاري ومسلم عن عائشة رضي الله عنها قالت: قال رسول الله صلى الله عليه وسلم: « مَن أحدث في أمرنا هذا ما ليس منه فهو رد ». ورواه مسلم بلفظ ءاخر وهو: « من عمل عملا ليس عليه أمرنا فهو رد ». فأفهم رسول الله صلى الله عليه وسلم بقوله: »ما ليس منه » أن المحدَث إنما يكون ردًّا أي مردوداً إذا كان على خلاف الشريعة، وأن المحدَث الموافق للشريعة ليس مردودًا.',
      'وهو مفهوم أيضًا مما رواه مسلم في صحيحه من حديث جرير بن عبد الله البجلي رضي الله عنه أنه قال: قال رسول الله صلى الله عليه وسلم : « من سن في الإسلام سنة حسنة فله أجرها وأجر من عمل بها بعده من غير أن ينقص من أجورهم شىء، ومن سن في الإسلام سنة سيئة كان عليه وزرها ووزر من عمل بها من بعده من غير أن ينقص من أوزارهم شىء ».',
      'وفي صحيح البخاري في كتاب صلاة التراويح ما نصه: « قال ابن شهاب: فتوفي رسول الله صلى الله عليه وسلم والناس على ذلك »، قال الحافظ ابن حجر: « أي على ترك الجماعة في التراويح ». ثم قال ابن شهاب في تتمة كلامه: « ثم كان الأمر على ذلك في خلافة أبي بكر وصدرًا من خلافة عمر رضي الله عنه ». وفيه أيض تتميمًا لهذه الحادثة عن عبد الرحمن بن عبد القاريّ أنه قال:خرجت مع عمر بن الخطاب رضي الله عنه ليلة في رمضان إلى المسجد، فإذا الناس أوزاع متفرقون يصلي الرجل لنفسه ويصلي الرجل فيصلي بصلاته الرهط، فقال عمر: إني أرى لو جمعت هؤلاء على قارىء واحد لكان أمثل، ثم عزم فجمعهم على أُبيّ بن كعب، ثم خرجت معه ليلة أخرى والناس يصلون بصلاة قارئهم قال عمر: « نعم البدعة هذه ».ا.هـ. وفي الموطأ بلفظ: « نِعمت البدعة هذه ». »',
      'إن البدعة لم تنحصر في الحرام والمكروه، بل قد تكون أيضا: مباحة ومندوبة وواجبة',
      'قوله صلى الله عليه وسلم : (من سن في الإسلام سنة حسنة فله أجرها) إلى آخره ، فيه : الحث على الابتداء بالخيرات وسن السنن الحسنات ، والتحذير من اختراع الأباطيل والمستقبحات.',
      'فقال الإمام النووي : « وفي هذا الحديث تخصيص قوله صلى الله عليه وسلم : كل محدثة بدعة وكل بدعة ضلالة ، وأن المراد به المحدثات الباطلة والبدع المذمومة ، وقد سبق بيان هذا في كتاب صلاة الجمعة ، وذكرنا هناك أن البدع خمسة أقسام : واجبة ومندوبة ومحرمة ومكروهة ومباحة. »',
      'ولا يجوز عليه تعالى ما يجوز على الجواهر والأجسام من الحركة والسكون والزوال والانتقال والتغير والمنافع والمضار، ولا تحويه الأمكنة ولا تحيط به الأزمنة',
      '« حدثنا علي بن حجر حدثنا إسمعيل بن عياش عن محمد بن إسحق عن عمرو ابن شعيب عن أبيه عن جده أن رسول الله صلى الله عليه وسلم قال :',
      'إذا فزع أحدكم في النوم فليقل «أعوذ بكلمات الله التامات من غضبه وعقابه وشر عباده ومن همزات الشياطين وأن يحضرون» فإنها لن تضره.',
      'وكان عبد الله بن عمرو يلقنها من بلغ من ولده ومن لم يبلغ منهم كتبها في صك ثم علقها في عنقه.',
      'قال أبو عيسى هذا حديث حسن غريب.»',
      'ما عرف الله تعالى من شبهه وجسمه من اليهود ، أو أجاز عليه البدا ، أو أضاف إليه الولد منهم ، أو أضاف إليه الصاحبة والولد ، وأجاز الحلول عليه ، والانتقال والامتزاج من النصارى ، أو وصفه بما لا يليق به ، أو أضاف إليه الشريك والمعاند في خلقه و ملكه من المجوس والثنوية فمعبودهم الذي عبدوه ليس بالله وإن سموه به إذ ليس موصوفا بصفات الإله الواجبة له . فإذن ما عرفوا الله و لا عبدوه',
      'وفي هذا الحديث دليل على استحباب التبرك بآثار الصالحين وثيابهم',
      'وقال بعضهم : المبتدعة أقسام : الأول : ما نكفره قطعا ، كقاذف عائشة رضي الله عنها ومنكر علم الجزئيات ، وحشر الأجساد ، والمجسمة ، والقائل بقدم العالم .',
      '{ وَهُوَ مَعَكُمْ } يعني بقدرته وسلطانه وعلمه { أَيْنَ مَا كُنتُمْ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ } يبصر أعمالكم ويراها ولا يخفى عليه شيء منها. وقد جمع في هذه الآية بين { ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ } وبين { وَهُوَ مَعَكُمْ } والأخذ بالظاهرين تناقض فدل على أنه لا بدّ من التأويل، والإعراضُ عن التأويل ٱعتراف بالتناقض.',
      'الله تعالى لا يوصف بالجهات ، و لا أنه في جهة',
      'وأما قوله تعالى {ورافعك إلي} معناه إلى كرامتي ورحمتي',
      'وَكَانَ يذهب -أي الثلجي – مَذْهَب النجار فِي القَوْل بِأَن الله فِي كل مَكَان وَهُوَ مَذْهَب الْمُعْتَزلَة وَهَذَا التَّأْوِيل عندنَا مُنكر من أجل أَنه لَا يجوز أَن يُقَال إِن الله تَعَالَى فِي مَكَان أَو فِي كل مَكَان',
      'أن القول بربوبية النجم كفر بالإجماع والكفر غير جائز بالإجماع على الأنبياء',
      'لا يجوز أن يقال : إن إبراهيم – عليه السلام – قال على سبيل الجزم : هذا ربي',
      'نقول قوله : ( هذا ربي ) معناه هذا ربي في زعمكم واعتقادكم',
      'أن المراد منه الاستفهام على سبيل الإنكار إلا أنه أسقط حرف الاستفهام',
      'وقد قال الإمام أبو المعالي (الجويني) : إن محمداً صلى الله عليه وسلم ليلة الإسراء لم يكن بأقرب إلى الله عز وجل من يونس بن متى حين كان في بطن الحوت',
      'يَنْزِلُ – يعني الله – بِلا آلَةٍ ، وَلا تَحَرُّكٍ ، وَلا انْتِقَالٍ مِنْ مَكَانٍ إِلَى مَكَانٍ […] وَكَذَلِكَ يَنْزِلُ كَيْفَ يَشَاءُ بِلا آلَةٍ مِنْ غَيْرِ أَنْ يُقَاسَ نُزُولُهُ إِلَى نُزُولِ الْمَخْلُوقِينَ ، كَمَا يُكَيَّفُ نُزُولُهُمْ ، جَلَّ رَبُّنَا وَتَقَدَّسَ مِنْ أَنْ تُشَبَّهَ صِفَاتُهُ بِشَيْءٍ مِنْ صِفَاتِ الْمَخْلُوقِينَ',
      'الإجماع على أن الكفار لا تنفعهم أعمالهم , ولا يثابون عليها بنعيم ولا بتخفيف عذاب',
      '« أن رجلاً كان يختلف إلى عثمان بن عفان في حاجة له فكان عثمان لا يلتفت إليه ولا ينظر في حاجته (أي لنسيانه لها كما يأتي) فلقى عثمان بن حنيف فشكا ذلك إليه فقال له عثمان بن حنيف:',
      'ائت الميضأة فتوضأ ثم ائت المسجد فصل فيه ركعتين، ثم قل: اللهم إني أسألك وأتوجه إليك بنبينا محمد صلى الله عليه وسلم نبي الرحمة يا محمد إني أتوجه بك إلى ربي فيقضي لي حاجتي، وتذكر حاجتك، ورح إلي حين أروح معك.',
      'فانطلق الرجل فصنع ما قال له ثم أتى باب عثمان فجاء البواب حتى أخذ بيده فأدخله على عثمان بن عفان فأجلسه معه على الطنفسة وقال: حاجتك؟ فذكر حاجته فقضاها له ثم قال له: ما ذكرت حاجتك حتى كانت هذه الساعة، وقال: ما كانت لك من حاجة فائتنا،',
      'ثم إن الرجل خرج من عنده فلقي عثمان بن حنيف فقال له: جزاك الله خيرًا ما كان ينظر في حاجتي ولا يلتفت إلي حتى كلمته فيّ،',
      'فقال عثمان بن حنيف: والله ما كلمته ولكن شهدت رسول الله صلى الله عليه وسلم وأتاه رجل ضرير فشكا إليه ذهاب بصره ،',
      'فقال له النبي صلى الله عليه وسلم: « أو تصبر؟ » فقال: يا رسول الله إنه ليس لي قائد وقد شق علي، فقال له النبي صلى الله عليه وسلم: « ائت الميضأة فتوضأ ثم صل ركعتين ثم ادع بهذه الدعوات » ،',
      'فقال عثمان بن حنيف: فوالله ما تفرقنا وطال بنا الحديث حتى دخل علينا الرجل كأنه لم يكن به ضرر قط.',
      '[وقد قال الطبر اني : ] والحديث صحيح »',
      'نور: في أَسماء الله تعالى: النُّورُ؛ قال ابن الأَثير: هو الذي يُبْصِرُ بنوره ذو العَمَاية ويَرْشُدُ بهداه ذو الغَوايَةِ، وقيل: هو الظاهر الذي به كل ظهور، والظاهر في نفسه المُظْهِر لغيره يسمى نوراً. قال أَبومنصور: والنُّور من صفات الله عز وجل، قال الله عز وجل: الله نُورُ السموات والأَرض؛ قيل في تفسيره: هادي أَهل السموات والأَرض، وقيل: مَثل نوره كمشكاة فيها مصباح؛ أَي مثل نور هداه في قلب المؤمن كمشكاة فيها مصباح.',
      'إنّه – يعني الإمام أحمد بن حنبل – كان لا يقول بالجهة للباري تعالى',
      '« قوله : « ينزل ربنا إلى السماء الدنيا» استدل به من أثبت الجهة ، وقال : هي جهة العلو؛ وأنكر ذلك الجمهور لأن القول بذلك يفضى إلى التحيز تعالى الله عن ذلك .وقد اختلف في معنى النزول على أقوال:',
      'فمنهم من حمله على ظاهره وحقيقته وهم المشبهة تعالى الله عن قولهم،',
      'ومنهم من أنكر صحة الأحاديث الواردة في ذلك جملة وهم الخوارج والمعتزله وهو مكابرة والعجب إنهم أولوا ما في القرءان من نحو ذلك وانكروا ما في الحديث إما جهلا وإما عنادا،',
      'ومنهم من اجراه على ما ورد مؤمنا به على طريق الإجمال منزها الله تعالى عن الكيفيه والتشبيه وهم جمهور السلف ونقله البيهقي وغيره عن الأئمة الأربعة والسفيانين والحمادين والأوزاعي والليث وغيرهم،',
      'ومنهم من أوله على وجه يليق مستعمل في كلام العرب ومنهم من أفرط في التأويل حتى كاد أن يخرج إلى نوع من التحريف،',
      'ومنهم من فصل بين مايكون تأويله قريبا مستعملا في كلام العرب وبين ما يكون بعيدا مهجورا فأول في بعض وفوض في بعض وهو منقول عن مالك وجزم به من المتأخرين بن دقيق العيد،',
      'قال البيهقي : واسلمها الإيمان بلا كيف والسكوت عن المراد »',
      'و{العليّ} يُراد به علو القدر والـمنـزلة لا علو الـمكان ، لأنَّ الله سبحانه منـزه عن التحيز؛ و كذا {العظيم} هي صفة بمعنى عظم القدر والخطر، لا على معنى عظم الأجرام',
      'قال أبو حنيفة : من قال لا أعرف الله أفي السماء أم في الأرض فقد كفر، لأنه بهذا القول يوهم أن يكون له مكان فكان مشركاً',
      'قال نعيم بن حماد : من شبه الله بشىء من خلقه فقد كفر ومن أنكر ما وصف الله به نفسه فقد كفر',
      'حدثنا ابن عبد الأعلى، قال: ثنا ابن ثور، عن معمر، عن قتادة، في قوله { يَوْمَ يُكْشَفُ عَنْ ساقٍ } قال: يوم يكشف عن شدة الأمر',
      'وأخرج البيهقي في شعب الإِيمان عن سفيان [الثوري] في قوله : {كل شيء هالك إلا وجهه} قال: إلا ما أريد به وجهه من الأعمال الصالحة',
      'ومنها حديث النزول وهو في الصحيحين من حديث أبي هريرة رضي الله عنه أنه قال ينزل ربنا كل ليلة إلى السماء الدنيا حين يبقى ثلث الليل الآخر يقول من يدعوني فأستجيب له إلى آخره .وهذا الحديث رواه عشرون نفسا من الصحابة رضي الله عنهم .وقد تقدم أنه تستحيل على الله عزوجل الحركة والتنقل والتغير لأن ذلك من صفات الحدث فمن قال ذلك في حقه تعالى فقد ألحقه بالمخلوق وذلك كفر صريح لمخالفة القرآن في تنزيهه لنفسه سبحانه وتعالى',
      'وقال إمامنا الشافعي رضي الله عنه لما سئل عن ذلك (أي آية الإستواء) : آمنت بلا تشبيه وصدقت بلا تمثيل واتهمت نفسي في الإدراك وأمسكت عن الخوض فيه كل الإمساك',
      'قال [يعني الإمام الأشعري] في النوادر: من اعتقد أن الله جسم فهو غير عارف بربه وإنه كافر به، كما في شرح الإرشاد لأبي القاسم الأنصاري',
      'قال العلامة إسماعيل حقي في تفسيره روح البيان : من قال إن الله في السماء إن أراد به المكان كفر وإن أراد به الحكاية عما جاء في ظاهر الأخبار لا يكفر',
      'الفرق بين الرسول والنبى : ان كل من نزل عليه الوحى من الله تعالى على لسان ملك من الملائكة وكان مؤيدا بنوع من الكرامات الناقضة للعادات فهو نبى ومن حصلت له هذه الصفة وخص ايضا بشرع جديد او بفسخ بعض احكام شريعة كانت قبله فهو رسول',
      'و قوله {لِمَا خَلَقْتُ بِيَدَيَّ} أي بقدرتي و نعمتي',
      'قَالَ الشَّافِعِي رضِيَ اللَّهُ عَنْهُ: الْمُحْدَثَاتُ مِنَ الْأُمُورِ ضِرْبَانِ: أَحَدُهُمَا: مَا أُحْدِثَ يُخَالِفُ كِتَابًا أَوْ سَنَةً أَوْ أَثَرًا أَوْ إِجْمَاعًا , فَهَذِهِ لَبِدْعَةُ الضَّلَالَةِ. وَالثَّانِيةُ: مَا أُحْدِثَ مِنَ الْخَيْرِ لَا خِلَافَ فِيهِ لِوَاحِدٍ مِنْ هَذَا , فَهَذِهِ مُحْدَثَةٌ غَيْرُ مَذْمُومَةٍ وَقَدْ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فِي قِيَامِ شَهْرِ رَمَضَانَ: «نِعْمَتِ الْبِدْعَةُ هَذِهِ» يَعْنِي أَنَّهَا مُحْدَثَةٌ لَمْ تَكُنْ',
      'خَرَجْتُ مَعَ عُمَرَ بْنِ الْخَطَّابِ فِي رَمَضَانَ إِلَى الْمَسْجِدِ فَإِذَا النَّاسُ أَوْزَاعٌ مُتَفَرِّقُونَ يُصَلِّي الرَّجُلُ لِنَفْسِهِ وَيُصَلِّي الرَّجُلُ فَيُصَلِّي بِصَلَاتِهِ الرَّهْطُ ، فَقَالَ عُمَرُ : » وَاللَّهِ إِنِّي لَأَرَانِي لَوْ جَمَعْتُ هَؤُلَاءِ عَلَى قَارِئٍ وَاحِدٍ ، لَكَانَ أَمْثَلَ » فَجَمَعَهُمْ عَلَى أُبَيِّ بْنِ كَعْبٍ ، قَالَ : ثُمَّ خَرَجْتُ مَعَهُ لَيْلَةً أُخْرَى وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ قَارِئِهِمْ ، فَقَالَ عُمَرُ : » نِعْمَتِ الْبِدْعَةُ هَذِهِ',
      '« قول عمر: « نعم البدعة » فالبدعة اختراع ما لم يكن قبل، فما خالف السنة فهو بدعة ضلالة، وما وافقها فهو بدعة هُدى »',
      'النور ، معناه الهادى',
      'ف(فوق) : لا يجوز أن تكون للجهة، وإنما هى لعلو القدر والشأن، على حد ما تقول الياقوت فوق الحديد',
      'فيكون ما أجمع عليه أهل الحق من علماء السلف والخلف من تنـزه الحق عن الجهة وتقدسه عن المكان وتعاليه عن التجزؤ والتبعيض والصعود والنـزول والقرب والبعد والذهاب والمجيء والحركة والسكون وما أشبه ذلك',
      '{كل شيء هالك إلا وجهه } أي : إلا هو ، وقيل : إلا ملكه ، قال أبو العالية : إلا ما أريد به وجهه',
      'وروى البيهقي بإسناده في مناقب الشافعي عن الشافعي رضي الله عنه قال : المحدثات من الأمور ضربان، أحدهما ما أُحدث مما يخالف كتابا أو سنة أو أثرا أو اجماعا فهذه البدعة الضلالة، والثانية ما أحدث من الخير لا خلاف فيه لواحد من العلماء وهذه محدثة غير مذمومة، وقد قال عمر رضي الله عنه في قيام شهر رمضان: نعمتُ البدعة هذه، يعني أنها محدثة لم تكن',
      '“عَالِمُ قُرَيْشٍ يَمْلأُ طِبَاقَ الأَرْضِ عِلْمًا”',
      'قال الله عز وجل : {كل شيء هالك إلا وجهه} ؛ وقال : {ويبقى وجه ربك} ؛ المعنى: ويبقى ربك؛ والمعنى: كل شيء هالك إلا الله عز وجل.',
      'إنه سبحانه ليس في مكان من الأمكنة ولا في زمان من الأزمنة، لأن المكان والزمان من جملة المخلوقات وهو سبحانه كان موجودا في الأزل ولم يكن معه شىء من الموجودات',
      'وقلنا المراد بقوله الرحمن على العرش استوى بالقدرة فإن قيل إذا حملتم على القدرة لم يكن لتخصيص العرش فائدة قلنا فائدته أن العرش أعظم المخلوقات فإذا قدر عليه علم من طريق التنبيه أنه قادر على ما هو دونه',
      '« ومعنى «ينزل ربّنا» أي : ينزل أمره أو ملائكته أو رحمته »',
      'لا يجوز عليه التغيير ولا التبديل ولا الانتقال ولا التحريك',
      'النزول بمعنى الحركة والانتقال من علو الى سفل من صفات الحوادث فهو مستحيل في حق الله تعالى و ما ورد مما ظاهره نسبة النزول الى الله تعالى فهو مصروف عن ظاهره بإجماع السلف والخلف',
      '« قَالَ سَعِيدُ بْنُ عَامِرِ بْنِ جُذَيْمٍ : « شَهِدْتُ مَصْرَعَ خُبَيْبٍ، وَقَدْ بَضَعَتْ قُرَيْشٌ لَحْمَهُ ، ثُمَّ حَمَلُوهُ عَلَى جَذْعَةٍ ، فَقَالُوا : أَتُحِبُّ أَنَّ مُحَمَّدًا مَكَانَكَ ؟ فَقَالَ : وَاللَّهِ مَا أُحِبُّ أَنِّي فِي أَهْلِي ، وَوَلَدِي ، وَأَنَّ مُحَمَّدًا شِيكَ بِشَوْكَةٍ ، ثُمَّ نَادَى يَا مُحَمَّدُ »',
      'أخبرنا أبو سعيد الشريحي ، أخبرنا أبو إسحاق الثعلبي ، أخبرني الحسن بن محمد الشيباني أخبرنا محمد بن سليمان بن الفتح الحنبلي ، حدثنا علي بن محمد المصري ، أخبرنا أبو إسحاق بن منصور الصعدي ، أخبرنا العباس بن زفر ، عن أبي جعفر الرازي ، عن أبيه عن الربيع بن أنس ، عن أبي العالية ، عن أبي بن كعب عن النبي – صلى الله عليه وسلم – في قوله : » وأن إلى ربك المنتهى » ، قال : » لا فكرة في الرب » ، وهذا مثل ما روي عن أبي هريرة مرفوعا : » تفكروا في الخلق ولا تتفكروا في الخالق » فإنه لا تحيط به الفكرة .',
      'في الحديث: إِن الله تعالى وتقدّس يَنزِل كل ليلة إِلى سماء الدنيا؛ النُّزول والصُّعود والحركة والسكونُ من صفات الأَجسام، والله عز وجل يتعالى عن ذلك ويتقدّس، والمراد به نُزول الرحمةِ',
      'وأنه لا يحويه مكان في سماواته ولا أرضه، بل هو كما كان قبل خلق المكان، وأنه ليس بجوهر ولا جسم، ولا على صورة ولا شكل، ولا له شبيه ولا مثل، بل هو الأحد الصمد الذي لم يلد ولم يولد، ولم يكن له كفؤا أحد',
      'وليس معنى قول المسلمين: إن الله استوى على العرش هو أنه مماس له أو متمكن فيه أو متحيز في جهة من جهاته لكنه بائن من جميع خلقه، وإنما خبر جاء به التوقيف. فقلنا به، ونفينا عنه التكييف، إذ ليس كمثله شيء وهو السميع البصير',
      'وفي الجملة يجب أن يُعلم أن استواء الله سبحانه وتعالى، ليس باستواء اعتدال عن اعوجاج، ولا استقرار في مكان، ولا مماسة لشيء من خلقه، لكنه مستو على عرشه كما أخبر بلا كيف بلا أين',
      '[عن] قوله تعالى وجاء ربك قال الإمام أحمد معناه جاء أمر ربك',
      '« وعن ابن عَبَّاسٍ ، رَضَيَ اللَّه عنهما ، قال : مَرَّ رسُولُ اللَّهِ صَلّى اللهُ عَلَيْهِ وسَلَّم بِقُبورٍ بالمَدِينَةِ فَأَقْبَلَ عَلَيْهِمْ بوَجْهِهِ فقالَ : « السَّلامُ عَلَيْكُمْ يا أَهْلَ القُبُورِ ، يَغْفِرُ اللَّهُ لَنا وَلَكُمْ ، أَنْتُم سَلَفُنا ونحْنُ بالأَثَرِ » رواهُ الترمذي وقال : حديث حسن»',
      'قال المتكلمون هذه المعية إما بالعلم وإما بالحفظ والحراسة وعلى التقديرين فقد انعقد الإجماع على أنه سبحانه ليس معنا بالمكان والجهة والحيز فإذا قوله (وهو معكم) لا بد فيه من التأويل وإذا جوزنا التأويل في موضع وجب تجويزه في سائر المواضع',
      'ويجبُ له تعالى: السمعُ: المقدَّسُ عن الأُذُنِ والصِماخ.',
      'ويجب الجزم بأنّه تعالى ليس بجسم ولا جوهر ولا عرض ،لا تحلّ به الحوادث ولا يحلّ في حادث ولا ينحصر فيه، فمن اعتقد أنّ الله بذاته في كلّ مكان أو في مكان فهو كافر. بل يجب الجزم بأنّه تعالى بائن من خلقه (أي لا يشبههم)، فالله تعالى كان ولا مكان ثم خلق المكان وهو الآن كما كان قبل خلق المكان',
      'بائن من جميع خلقه، وأن إتيانه ليس بإتيان من مكان إلى مكان وأن مجيئه ليس بحركة وأن نزوله ليس بنقلة وأن نفسه ليس بجسم وأن وجهه ليس بصورة أن يده ليست بجارحة وأن عينه ليست بحدقة، وإنما هذه أوصاف جاء بها التوقيف فقلنا بها ونفينا عنها التكييف. فقد قال الله تعالى : (لَيْسَ كَمِثْلِهِ شَيْء). وقال : (وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَد). وقال : (هَلْ تَعْلَمُ لَهُ سَمِيَّا).',
      'قال الله تعالى :{إِنَّ الله وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى النَّبِيِّ} قال ابن عباس : معناه : إن الله و ملائكته يباركون على النبي .وقيل : إن الله يترحم على النبي ، وملائكته يدعون له .',
      'جل عن التمثيل والتشبيه وعن مكان يستقر فيه لأنه كان ولا مكان في أزل لم يحوه الزمان',
      'ولو قال : لا إله إلا ساكن السماء ، لم يكن مؤمنا ، وكذا لو قال : لا إله إلا الله ساكن السماء ; لأن السكون محال على الله تعالى',
      'فإذا قال لك: أين الله؟ فقل: مع كل أحد بعلمه لا بذاته ، وفوق كل أحد بقدرته، وظاهر بكل شىء باثار صفاته، وباطن بحقيقة ذاته أي لا يمكن تصويره في النفس، منزه عن الجهة والجسمية. فلا يقال: له يمين ولا شمال ولا خلف ولا أمام، ولا فوق العرش ولا تحته، ولا عن يمينه ولا عن شماله، ولا داخل في العالم ولا خارج عنه، ولا يقال: لا يعلم مكانه إلا هو. ومن قال: لا أعرف الله في السماء هو أم في الأرض كفر لأنه جعل أحدهما له مكانا. فإذا قال لك: ما دليلك على ذلك؟ فقل: لأنه لو كان له جهة أو هو في جهة لكان متحيزا، وكل متحيز حادث، والحدوث عليه محال',
      'في قوله تعالى : {يد الله فوق أيديهم} : المراد باليد القدرة',
      'ويستحب زيارة قبر رسول الله صلى الله عليه وسلم لما روى ابن عمر رضي الله عنهما أن النبي صلى الله عليه وسلم قال : { من زار قبري وجبت له شفاعتي }',
      'وإن استواءه ليس باستقرارٍ ولا ملاصقةٍ لأن الاستقرار والـملاصقة صفة الأجسام الـمخلوقة ، والرب عز وجل قديمٌ أزليٌّ',
      'باب ما يقوله إذا خدرت رجله : […] عن الهيثم بن حنش قال : ” كنا عند عبد الله بن عمر رضي الله عنهما فخدرت رجله ، فقال له رجل : اذكر أحب الناس إليك ، فقال : يا محمد صلى الله عليه وسلم ، فكأنما نشط من عقال',
      '[قال الإمام أحمد بن حنبل:] قال الله جلَّ ذكره{وجاء ربك والملك صفا صفا} وإنما تأتي قدرته',
      'والرِّدَّةُ ثَلاثَةُ أقْسامٍ: اعْتِقاداتٌ وأفْعالٌ وأقْوالٌ، وكُلُّ قِسْمٍ يَتَشَعَّبُ شُعَبًا كَثِيرَةً',
      'إذا قال لك قائلٌ: من تعبدُ؟ فقل: أعبدُ اللهَ الذي لا إله إلا هو، الذي ليس متحيزًا في الأرضِ ولا في السماء، كان قبلَ المكانَ والزمان وهو الآن كما كان، لا يُمكن تصويرُهُ في القلب لأنهُ لا شبيه له في الموجوداتِ',
      'منزه عن الحلـــــول والجهــــــه والاتصال الانفصال والسفه',
      'قال تعالى {كُلُّ شَيْءٍ هَالِكٌ إِلاَّ وَجْهَهُ} لا بمعنى الجارحة بل بمعنى الذات أي :إلا ذاته',
      'وإن أصل جميع المخلوقات الماء',
      'قال جعفر بن محمد الصادق عليه السلام : من زعم أن الله تعالى في شىء ، أومن شىء أو على شىء فقد أشرك . لأنه لو كان على شىء لكان محمولا ، ولو كان في شىء لكان محصوراً ، ولو كان من شىء لكان محدثًا (أي مخلوقاً) و الله يتعالى عن جميع ذلك',
      'أَجْمَعَ الْعُلَمَاءُ الَّذِينَ يُعْتَدُّ بِهِمْ عَلَى أَنَّ مَنْ تَرَكَ صَلَاةً عَمْدًا لَزِمَهُ قَضَاؤُهَا',
      'وقوله سبحانه: { ثم استوى على العرش} معناه عند أبي المعالي وغيره من حذاق المتكلمين : الملك والسلطان، وخص العرش بالذكر تشريفاً له إذ هو أعظم المخلوقات',
      'وأثبت اليدين والوجه صفات خبرية فيقول ورد بذلك السمع فيجب الاقرار به كما ورد وصغوه إلى طريقة السلف من ترك التعرض للتأويل وله قول أيضا في جواز التأويل',
      'ومعنى: {بأعيننا} أي بإبصارنا إليك وحفظنا لك',
      'وقوله تعالى {وَجَاءَ رَبُّكَ} معناه جاء أمره و قضاؤه',
      'قاضي مكة العالم الصالح العابد نجم الدين محمد بن إمام العالم محيي الدين الطبري، وهو فاضل كثير الصدقات والمؤاساة للمجاورين، حسن الأخلاق كثير الطواف والمشاهدة للكعبة الشريفة، يطعم الطعام الكثير في المواسم المعظمة، وخصوصًا في مولد رسول الله صلى الله عليه وسلم، فإنه يطعم فيه شرفاء مكة وكبراءها وفقراءها وخدام الحرم الشريف وجميع المجاورين.',
      'إنَّه (أي الله) ليس بجسمٍ ولا عَرَضٍ ولا في مكانٍ ولا زمان',
      '« وقد سئل شيخ الإسلام حافظ العصر أبو الفضل ابن حجر عن عمل المولد ، فأجاب بما نصه :',
      'أصل عمل المولد بدعة لم تنقل عن أحد من السلف الصالح من القرون الثلاثة ، ولكنها مع ذلك قد اشتملت على محاسن وضدها ، فمن تحرى في عملها المحاسن وتجنب ضدها كان بدعة حسنة وإلا فلا ، قال : وقد ظهر لي تخريجها على أصل ثابت وهو ما ثبت في الصحيحين من أن النبي صلى الله عليه وسلم قدم المدينة فوجد اليهود يصومون يوم عاشوراء ، فسألهم فقالوا : هو يوم أغرق الله فيه فرعون ونجى موسى فنحن نصومه شكرا لله تعالى ، فيستفاد منه فعل الشكر لله على ما من به في يوم معين من إسداء نعمة أو دفع نقمة ، ويعاد ذلك في نظير ذلك اليوم من كل سنة ، والشكر لله يحصل بأنواع العبادة كالسجود والصيام والصدقة والتلاوة ، وأي نعمة أعظم من النعمة ببروز هذا النبي نبي الرحمة في ذلك اليوم ؟ وعلى هذا فينبغي أن يتحرى اليوم بعينه حتى يطابق قصة موسىفي يوم عاشوراء ، ومن لم يلاحظ ذلك لا يبالي بعمل المولد في أي يوم من الشهر ، بل توسع قوم فنقلوه إلى يوم من السنة ، وفيه ما فيه . فهذا ما يتعلق بأصل عمله . وأما ما يعمل فيه فينبغي أن يقتصر فيه على ما يفهم الشكر لله تعالى من نحو ما تقدم ذكره من التلاوة والإطعام والصدقة وإنشاد شيء من المدائح النبوية والزهدية المحركة للقلوب إلى فعل الخير والعمل للآخرة »',
      'وأن من لم يكفر من دان بغير الإسلام كالنصارى ، أو شك في تكفيرهم ، أو صحح مذهبهم ، فهو كافر ، وإن أظهر مع ذلك الإسلام واعتقده',
      'يجوز التوسل بالرجل الصالح على الصحيح من المذهب، وقيل: يُستحب. قال الإمام أحمد للمروذي : يتوسل بالنبي (صلى الله عليه وسلم) في دعائه وجزم به في المستوعب وغيره.',
      '« وكيف يمكن أن يقال إن السلف ما استعملوا التأويل وقد ورد في الصحيح عن سيد الكونين صلى الله عليه وسلم أنه قدّم له ابن عباس وَضوءه فقال:{ من فعل هذا}, فقال: قلت: أنا يا رسول الله, فقال:{ اللهم فقّهه في الدين وعلّمه التأويل} , فلا يخلو إما أن يكون الرسول أراد أن يدعو له أو عليه, فلا بد أن تقول أراد الدعاء له لا دعاءً عليه, ولو كان التأويل محظورا لكان هذا دعاء عليه لا له. ثم أقول: لا يخلو إما أن تقول: إن دعاء الرسول ليس مستجابا فليس بصحيح, وإن قلت: إنه مستجاب فقد تركت مذهبك وبَطَل قولك: إنهم ما كانوا يقولون بالتأويل,',
      'وكيف والله يقول:{ وَمَا يَعْلَمُ تَأْوِيلَهُ إِلاَّ اللهُ وَالرَّاسِخُونَ فِي الْعِلْمِ يَقُولُونَ ءامَنَّا بِهِ}(7)[سورة ءال عمران] »',
      'اللهم فقِّهْهُ قي الدين وعلِّمهُ التأويلَ',
      'باب ما يقوله إذا خدرت رجله : روينا في كتاب ابن السني عن الهيثم بن حنش قال : » كنا عند عبد الله بن عمر رضي الله عنهما فخدرت رجله ، فقال له رجل : اذكر أحب الناس إليك ، فقال : يا محمد صلى الله عليه وسلم ، فكأنما نشط من عقال',
      'عمل المولد وإن حدث بعد السلف الصالح ليس فيه مخالفة لكتاب الله ولا لسنة رسوله صلى الله تعالى عليه وسلم ولا لإجماع المسلمين، فلا يقول من له مسكة من عقل ودين بأنه مذموم',
      'وَالْكَلامُ الذي لَيْسَ بِحَرْفٍ، وَلاَ صَوْتٍ',
      'وعن علي رضي الله عنه : سيرجعُ قومٌ من هذهِ الأمّةِ عندَ اقتراب السّاعةِ كفّارًا ، قال رجلٌ يا أميرَ المؤمنينَ ، كفرهم بماذا أبِالإحداثِ أم بالإنكارِ ، قال بل بالإنكارِ ، يُنكرونَ خالِقَهُم فيَصِفونهُ بالجِسمِ والأعضاءِ',
      'فمَن شبّهه بخَلقِه فقَد كفَر كمَن اعتَقدَه جِسمًا أو قالَ إنّه جِسمٌ لا كالأجسام',
      'والله تعالى عالٍ على كل شَىء ، وليس الـمراد بالعلو ارتفاع الـمحلِّ ، لأن الله تعالى يجلُّ عن الـمحلِّ والـمكان ، وإنَّما العُلو علوُّ الشأن وارتفاعُ السلطان',
      'غرض البخاري في هذا الباب الرد على الجهمية المجسمة في تعلقها بهذه الظواهر وقد تقرر أن الله ليس بجسم فلا يحتاج الى مكان يستقر فيه فقد كان ولا مكان وانما أضاف المعارج اليه إضافة تشريف ومعنى الارتفاع اليه اعتلاؤه مع تنزيهه عن المكان',
      'وهذا مُنتَظمٌ مَن كفرُهُ مُجمَعٌ عَليهِ ومَن كفَّرناهُ مِن أهلِ القِبلةِ كالقائلينَ بِخَلقِ القُرءآنِ وَبأنَّهُ لايَعلَمُ المَعدوماتِ قَبلَ وُجودِها ومَن لايُؤمِنُ بالقَدرِ وكذا مَن يَعتقدُ أنَّ اللهَ جالسٌ على العَرشِ كما حَكاهُ القاضي حُسَينُ عن نَصِّ الشَّافِعيِّ',
      'حدثنا القاضي أبو علي ، قال : حدثنا أبو الفضل بن خيرون ، قال : حدثنا الحسن بن جعفر ، قال : حدثنا أبو الحسن علي بن عمر الدارقطني ، قال : حدثنا القاضي المحاملي ، قالا : حدثنا محمد بن عبد الرزاق ، قال : حدثنا موسى بن هلال ، عن عبد الله بن عمر ، عن نافع ، عن ابن عمر – رضي الله عنهما – ، قال : قال النبي – صلى الله عليه وسلم – من زار قبري وجبت له شفاعتي .',
      'العلي: هو فَعِيل في معنى فاعل، فالله تعالى عالٍ على خَلْقِه وهو عليٌّ عليهم بقدرته، ولا يجب أن يُذهَب بالعلو ارتفاع مكانٍ، إذ قد بيَّنَّا أن ذلك لا يجوز في صفاته تقدست، ولا يجوز أن يكون على أن يُتصور بذهن، تعالى الله عن ذلك عُلوًّا كبيرًا',
      '« [عن قول مالك لذاك الرجل « صاحب بدعة » : ] لأن سؤاله عن كيفية الاستواء يدل على أنه فهم الاستواء على معناه الظاهر الحسي الذي هو من قبيل تمكن جسم على جسم واستقراره عليه، وإنما شك في كيفية هذا الاستقرار. فسأل عنها، وهذا هو التشبيه بعينه الذي أشار إليه الإمام بالبدعة »',
      'معنى العبادة في اللغة الطاعة مع الخضوع',
      'وإن نواه أي صوم يوم الثلاثين من شعبان بلا مستند شرعيّ من رؤية هلاله أو إكمال شعبان أو حيلولة غيم أو قتر ونحوه ان صامه لحساب ونجوم ولو كثرت إصابتهما أو مع صحو فبان منه لم يجزئه صومه لعدم استناده لما يعوّل عليه شرعًا',
      '… ويسمى الاعتقاد الفاسد كاعتقاد قدم العالم أو تعدد الاله أو أن الله تعالى جسم، وصاحب هذا الاعتقاد مجمع على كفره',
      'يَجِبُ أن يكونَ تفسيرُ هذه الآية بغيرِ الاستِقْرارِ والجلُوسِ ونحوِ ذلكَ ويَكْفُر منْ يعتَقِدُ ذَلِكَ، فَيَجِبُ تَركُ الحَمْلِ علَى الظّاهِر بَلْ يُحمَلُ على مَحْمِلٍ مُسْتَقِيمٍ في العُقُولِ فتُحمَلُ لفْظَةُ الاسْتِواءِ علَى القَهْرِ ففي لُغَةِ العَرَبِ يُقَالُ اسْتَوى فُلانٌ على المَمَالِكِ إذَا احْتَوَى علَى مَقَالِيدِ المُلْكِ واسْتَعْلَى علَى الرّقَابِ كَقَوْلِ الشَّاعِرِ: [الزجر] قَد اسْتَوَى بِشْرٌ علَى العِراقِ مِنْ غَيْرِ سَيْفٍ ودَمٍ مُهْراقِ',
      'وفَائِدَةُ تَخْصِيص العَرْشِ بالذّكْرِ أنَّهُ أعْظَمُ مَخلُوقَاتِ الله تَعَالى حجمًا فيُعْلَمُ شُمُولُ ما دُوْنَه مِنْ بَابِ الأَوْلَى. قَالَ الإمَامُ عَلِيٌّ: « إنَّ الله تَعَالى خَلَقَ العَرْشَ إِظْهَارًا لقُدْرَتِهِ، ولمْ يَتّخِذْهُ مَكَانًا لِذَاتِهِ »، رواهُ الإمامُ المحدثُ الفقيهُ اللغويُّ أبو منصورٍ التميميُّ في كتابهِ الفرق بين الفرق، أَوْ يُقَالُ اسْتَوَى اسْتِوَاءً يَعْلَمُهُ هُوَ مَع تَنزِيْهِهِ عن اسْتِواءِ المخْلُوقِيْنَ كَالجُلوسِ والاسْتِقرارِ.',
      'واعْلَم أَنَّه يَجِبُ الحَذَرُ مِنْ هؤلاءِ الذينَ يُجِيزُوْنَ علَى الله القُعُودَ علَى العَرْشِ والاسْتِقْرارَ عليه مُفَسّرينَ لِقَوله تعالى: ﴿الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى (5)﴾ بالجُلُوسِ أو المحاذاةِ من فوق، ومُدَّعِينَ أَنَّه لا يُعْقَلُ مَوْجُودٌ إلا في مَكَانٍ، وحُجَّتُهم دَاحِضَةٌ، ومُدَّعِيْنَ أيضًا أنَّ قَوْلَ السَّلَفِ اسْتَوى بلا كَيْفٍ مُوافِقٌ لذَلِكَ وَلم يَدْرُوا أنَّ الكَيْفَ الذي نَفاهُ السَّلَفُ هُوَ الجُلُوسُ والاسْتِقْرارُ والتّحَيُّزُ في المَكَانِ والمُحَاذاةُ وكلُّ الهيئاتِ من حركةٍ وسكونٍ وانتقالٍ. »',
      'وحدثني مالك عن بن شهاب عن عبيد الله بن عبد الله بن عتبة بن مسعود أن رجلا من الأنصار جاء إلى رسول الله صلى الله عليه وسلم بجارية له سوداء فقال يا رسول الله ان علي رقبة مؤمنة فإن كنت تراها مؤمنة اعتقها فقال لها رسول الله صلى الله عليه وسلم أتشهدين أن لا إله إلا الله قالت نعم قال أتشهدين أن محمدا رسول الله قالت نعم قال أتوقنين بالبعث بعد الموت قالت نعم فقال رسول الله صلى الله عليه وسلم اعتقها',
      'علي رضي الله عنه قال : لما رمس رسول الله صلى الله عليه وسلم جاءت فاطمة رضي الله عنها فوقفت على قبره وأخذت قبضة من تراب القبر ووضعته على عينيها وبكت وأنشأت تقول: ماذا على من شم تربة أحمد ; أن لا يَشُمَّ مدى الزمان غَوَالَيَا ; صُبَّتْ عَليَّ مصائبٌ لو أنها ; صُبَّت على الأيام عُدْنَ لَيَالِيَا',
      'قال الباجي : وإجماع السلف الصالح حجة عليهم',
      '« فَعَلَّقَ (النبيُّ) الْحُكْمَ بِالصَّوْمِ وَغَيْرِهِ بِالرُّؤْيَةِ (في حديث: صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ) لِرَفْعِ الْحَرَجِ عَنْهُمْ فِي مُعَانَاةِ حِسَابِ التَّسْيِيرِ (أي حِساب تسيير النجوم والقمر) وَاسْتَمَرَّ الْحُكْمُ فِي الصَّوْمِ وَلَوْ حَدَثَ بَعْدَهُمْ مَنْ يَعْرِفُ ذَلِكَ (أي مِن الحُسّاب والمنجِّمين ونحوهم) بَلْ ظَاهِرُ السِّيَاقِ يُشْعِرُ بِنَفْيِ تَعْلِيقِ الْحُكْمِ بِالْحِسَابِ أَصْلًا وَيُوَضِّحُهُ قَوْلُهُ فِي الْحَدِيثِ الْمَاضِي: « فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ ثَلَاثِينَ وَلَمْ يَقُلْ فَسَلُوا أَهْلَ الْحِسَابِ » »',
      'الباب الخامس عشر في بيان اعتقاد أهل السنة والجماعة : وأن تَعلـم أن كل ما دل على حدوث شىءٍ من الحد ، والنهاية ، والـمكان ، والجهة ، والسكون ، والحركة ، فهو مستحيل عليه سبحانه وتعالى ، لأن ما لا يكون محدَثاً لا يجوز عليه ما هو دليل على الحدوث',
      'والاستواء: الاستيلاء، ولم يـزل الله سبحانه مستوليا على الأشياء كلها، إلا أن تخصيص العرش لتعظيم شأنه',
      'والله تعالى نفى المماثلة بين ذاته وبين غيره من الأشياء، فيكون القول باثبات المكان له ردا لهذا النص المحكم- أي قوله تعالى ﴿ليس كمثله شيء﴾ – الذي لا احتمال فيه لوجهٍ ما سوى ظاهره، ورادُّ النص كافر، عصمنا الله عن ذلك',
      'وقد وصف الشافعي رضي الله عنه توبته (أي المرتد) فقال: أن يشهد أن لا إله إلا الله، وأن محمدا رسول الله، ويبرأ من كل دين خالف الاسلام',
      'أو فعل يتضمنه كإلقاء مصحف بقذر',
      'قال الشهاب القرافي عن سند : لو كان إمام يرى الحساب فأثبت به الهلال لم يتبع لإجماع السلف على خلافه',
      'وقالوا: معنى استوى استولى',
      'وَلَوْ كَتَبَ الْقُرْآنَ فِي إنَاءٍ ثُمَّ غَسَلَهُ وَسَقَاهُ الْمَرِيضَ فَقَالَ الْحَسَنُ الْبَصْرِيُّ وَمُجَاهِدٌ وَأَبُو قِلَابَةَ وَالْأَوْزَاعِيُّ لَا بَأْسَ بِهِ',
      'وَنُنَزِّلُ مِنَ الْقُرْآنِ مَا هُوَ شِفَاء وَرَحْمَةٌ لِّلْمُؤْمِنِينَ وَلاَ يَزِيدُ الظَّالِمِينَ إَلاَّ خَسَاراً',
      'قديم لا أوّل له ، باقٍ لا آخِرَ لهُ ، مُخَالفٌ للحوادثِ ، ما هو بجرمٍ، ولا صفَةٍ للْجِرمِ، ولا جهةَ لهُ ولا مكانَ لهُ ، غَنِيٌّ عنِ المَحَلِّ والمُخَصِّصِ، قائم بنفسهِ',
      'ولا تقبل شهادة المجسمة لأنهم كفرة',
      'واحتاط بعضهم أكثر احتياط حتى لم يقرأ اليد بالفارسية ولا الوجه ولا الاستواء ولا ما ورد من جنس ذلك بل إن احتاج في ذكرها إلى عبارة عبر عنها بما ورد : لفظا بلفظ . فهذا هو طريق السلامة وليس هو من التشبيه في شيء',
      'قال المتولي : […] أو أثبت ما هو منفي عنه بالاجماع، كالالوان، أو أثبت له الاتصال والانفصال، كان كافرا',
      'ومن كفرناه من اهل القبلة القائلين بخلق القرءان وبأنه لا يعلم المعدومات قبل وجودها ومن لا يؤمن بالقدر وكذا من يعتقد ان الله جالس على العرش كما حكاه القاضي حسين هنا عن نص الشافعي',
      'وسمعت الإِمَام أبا بَكْر بْن فورك رحمه اللَّه تعالي يَقُول : سمعت أبا عُثْمَان المغربي يَقُول : كنت أعتقد شَيْئًا من حَدِيث الجهة فلما قدمت بغداد زال ذَلِكَ عَن قلبي فكتبت إِلَى أَصْحَابنا بمكة إني أسلمت الآن إسلاما جديدا.',
      'أخبرنا محمد بن أبي بكر الحافظ قال، أخْبَرَنا أبو الفضل أحمد بن إبراهيم بن أحمد البلخي من أصل كتابه أخبرنا جعفر بن محمد بوران الحكاك ببلخ، حَدَّثَنا سليمان بن داود الهروي، حَدَّثَنا إسحاق بن منصور، حَدَّثَنا أبو داود الطيالسي، حَدَّثَنا شعبة، حَدَّثَنا مالك بن أنس عن ابن شهاب قال: دخلت على أنس بن مالك فرأيته يعلق التعويذ على ابن له فقلت له: ياأبا حمزة هل نزل به بلاء؟ قال: لا ثم ضرب بيده على منكبي فقال: يا أبا بكر سمعت رسول الله صلى الله عليه وسلم يقول: لا بأس بتعليق التعويذ من القرآن قبل نزول البلاء وبعد نزول البلاء.',
      'وسواء كفر بقول صريح في الكفر كقوله كفرت بالله أو برسول الله أو بالقرآن أو الإله اثنان أو ثلاثة أو المسيح ابن الله أو العزيز ابن الله أو بلفظ يقتضيه أي يستلزم اللفظ الكفر استلزاما بينا كجحد مشروعية شيء مجمع عليه معلوم من الدين ضرورة ، فإنه يستلزم تكذيب القرآن أو الرسول، وكاعتقاد جسمية الله وتحيزه، فإنه يستلزم حدوثه واحتياجه لمحدِث',
      'و قال رجل لمالك : » يا أبا عبد الله { الرحمن على العرش استوى } كيف استوى ؟ قال : الاستواء غير مجهول و الكيف منه غير معقول و السؤال عنه بدعة و الإيمان به واجب ، و أراك صاحب بدعة ، أخرجوه',
      'وفيه أن من المسلمين من يخرج من الدين من غير أن يقصد الخروج منه ومن غير أن يختار دينًا على دين الإسلام',
      'إِنَّ العَبْدَ لَيَتَكَلَّمُ بِالكَلِمَةِ لا يَرىَ بِهَا بَأْساً يَهْوِي بِهَا فِي النَّارِ سَبْعِينَ خَرِيفاً',
      'المُجسّمة كفّار لأنهم اعتقدوا أنّ كلّ ما لا يكون متحيزاً ولا في جهة فليس بموجود ونحن نعتقد أنّ كلّ متحيّز فهو مُحْدَثٌ وخالقه موجود ليس بمُتحيّز ولا في جهة فالمُجسّمة نَفَوا ذات الشىء الذي هو الإله فيلزمهم الكفر',
      'وهذا الأذان الثاني أحدثه بنو أمية',
      'أعني بالجسم عبارة عن مقدار له طول وعرض وعمق',
      'من عبد جسمًا فهو كافر بإجماع الأئمة السلف منهم والخلف',
      'فترى أقواماً يسمعون أخبار الصفات فيحملونَها على ما يقتضيه الحس ، كقول قائلهم : ينـزل بذاته إلى السماء ويتنقل ، وهذا فهم ردىء ، لأن الـمتنقـل يكون من مكان إلى مكان ، ويوجب ذلك كون الـمكان أكبر منه ، ويلزم منه الحركة ، وكل ذلك محال على الحق عزَّ وجلَّ',
      'ينـزل ربنا إلى سماء الدنيا',
      'أَخْبَرَنَا أَبُو زَكَرِيَّا بْنُ أَبِي إِسْحَاقَ، وَأَبُو بَكْرِ بْنُ الْحَسَنِ قَالَا: ثنا أَبُو الْعَبَّاسِ الْأَصَمُّ، ثنا بَحْرُ بْنُ نَصْرٍ، ثنا ابْنُ وَهْبٍ، أَخْبَرَنِي نَافِعُ بْنُ يَزِيدَ، أَنَّهُ سَأَلَ يَحْيَى بْنَ سَعِيدٍ عَنِ الرُّقَى وَتَعْلِيقِ الْكُتُبِ، فَقَالَ: كَانَ سَعِيدُ بْنُ الْمُسَيِّبِ يَأْمُرُ بِتَعْلِيقِ الْقُرْآنِ وَقَالَ: لَا بَأْسَ بِهِ. قَالَ الشَّيْخُ رَحِمَهُ اللهُ: وَهَذَا كُلُّهُ يَرْجِعُ إِلَى مَا قُلْنَا مِنْ أَنَّهُ إِنْ رَقَى بِمَا لَا يُعْرَفُ أَوْ عَلَى مَا كَانَ مِنْ أَهْلِ الْجَاهِلِيَّةِ مِنْ إِضَافَةِ الْعَافِيَةِ إِلَى الرُّقَى لَمْ يَجُزْ , وَإِنْ رَقَى بِكِتَابِ اللهِ أَوْ بِمَا يُعْرَفُ مِنْ ذِكْرِ اللهِ مُتَبَرِّكًا بِهِ وَهُوَ يَرَى نُزُولَ الشِّفَاءِ مِنَ اللهِ تَعَالَى فَلَا بَأْسَ بِهِ، وَبِاللهِ التَّوْفِيقُ.',
      'ولا بأس بالاكتواء والرقى بكتاب الله وبالكلام الطيب. ولا بأس بالمعاذة تعلق، وفيها القرآن',
      'ولو قال كافر لمسلم : اعرض علي الإسلام ، فقال : حتى أرى ، أو اصبر إلى الغد ، أو طلب عرض الإسلام من واعظ ، فقال : اجلس إلى آخر المجلس ، كفر. وقد حكينا نظيره عن المتولي',
      'قال السخاوي : عمل المولد حدث بعد القرون الثلاثة ثم لا زال أهل الإسلام في سائر الأقطار والمدن الكبار يعملون المولد ويتصدقون في لياليه بأنواع الصدقات ويعتنون بقراءة مولده الكريم ويظهر عليهم من بركاته كل فضل عميم',
      '«وفي الحديث : « من تقرب إلي شبرا تقربت إليه ذراعا ». المراد بقرب العبد من الله تعالى القرب بالذكر والعمل الصالح لا قرب الذات والمكان لأن ذلك من صفات الأجسام والله يتعالى عن ذلك ويتقدس »',
      'من تقرب إلي شبرا تقربت إليه ذراعا',
      'قَالَ أَبُو سُلَيْمَانَ فِيمَا أُخْبِرْتُ عَنْهُ : وَلا يَجُوزُ أَنْ يُتَوَهَّمَ أَنَّ اللَّهَ سُبْحَانَهُ وَتَعَالَى نُورٌ مِنَ الأَنْوَارِ ، فَإِنَّ النُّورَ تُضَادُّهُ الظُّلْمَةُ وَتُعَاقِبُهُ فَتُزِيلُهُ , وَتَعَالَى اللَّهُ أَنْ يَكُونَ لَهُ ضِدٌّ أَوْ نِدٌّ',
      'الاحتفال بالمولد : و لا زال أهل الإسلام يحتفلون بشهر مولده ـ عليه السَّلام ـ ، ويعملون الولائم ويتصدقون في لياليه بأنواع الصدقات،ويظهرون السرور، ويزيدون في المبرات ويعتنون بقراءة مولده الكريم. ويظهر عليهم من بركاته كل فضل عميم',
      'اعلم أن الصحابة رضوان الله عليهم كانوا يتبركون بآثار النبي صلى الله عليه وسلم في حياته وبعد مماته ولا زال المسلمون بعدهم إلى يومنا هذا على ذلك وجواز هذا الأمر يعرف من فعل النبي صلى الله عليه وسلم وذلك أنه صلى الله عليه وسلم قسم شعره حين حلق في حجة الوداع و أظفاره',
      'قال الإمام أبو شامة شيخ النووي : ومن أحسن ما إبتدع في زماننا ما يفعل كل عام في اليوم الموافق ليوم مولده صلى الله عليه و سلم من الصدقات والمعروف ، وإظهار الزينة والسرور ، فإن ذلك – مع ما فيه من الإحسان للفقراء – مشعر بمحبة النبي صلى الله عليه و سلم وتعظيمه في قلب فاعل ذلك وشكر الله تعالى على ما من به من إيجاد رسول الله صلى الله عليه و سلم الذي أرسله رحمة للعالمين.',
      '[…] والكلام كله في مبتدع لا يكفر ببدعته أما من كفر بها كمنكر العلم بالجزئيات، وزاعم التجسيم أو الجهة أو الكون أو الاتصال بالعالم أو الانفصال عنه فلا يوصف عمله بقبول ولا رد لأنه أحقر من ذلك',
      'من يدخل الجنة يَنعَم لا ييْأس، لا تبلى ثيابه، ولا يفنى شبابه',
      'البارئ تعـالى يتقدس عن أن يُحَدَّ بالجهــــات أو أن تكتنفه الأقطار',
      '« فائدة : جرت العادة أن الناس إذا سمعوا ذكر وضعه صلى الله عليه و سلم يقومون تعظيماً له صلى الله عليه و سلم ، وهذا القيام مستحسن لما فيه من تعظيم النبي صلى الله عليه و سلم ، وقد فعل ذلك كثير من علماء الأمة الذين يقتدى بهم. قال الحلبي في السيرة : فقد حكى بعضهم أن الإمام السبكي إجتمع عنده كثير من علماء عصره فأنشد منشده قول الصرصري في مدحه صلى الله عليه و سلم:',
      'قليل لمدح المصطفى الخط بالذهب * على ورق من خط أحسن من كتب وأن تنهض الأشراف عند سماعه * قياماً صفوفاً أو جثياً على الركب',
      'فعند ذلك قام الإمام السبكي وجميع من بالمجلس ، فحصل أنس كبير في ذلك المجلس ، وعمل المولد وإجتماع الناس له كذلك مستحسن.»',
      'الله سبحانه وتعالى هادي أهل السماوات والأرض',
      'وأما البراءة من التشبيه بإثبات أنه ليس بجوهر ولا عرض فلأن قوما زاغوا عن الحق فوصفوا الباري جل وعز ببعض صفات المحدثين ، فمنهم من قالك إنه جوهر، ومنهم من قال إنه جسم، ومنهم من أجاز أن يكون على العرش قاعدا كما يكون الملك على سريره وكل ذلك في وجوب اسم الكفر لقائله كالتعطيل والتشريك',
      'إبليس رن أربع رنات رنة حين لعن ورنة حين أهبط ورنة حين ولد رسول الله صلى الله عليه و سلم ورنة حين أنزلت فاتحة الكتاب',
      'قال الحافظ أبو الخير السخاوي رحمه الله تعالى في فتاويه : عمل المولد الشريف لم ينقل عن أحد من السلف الصالح في القرون الثلاثة الفاضلة، وإنما حدث بعد، ثم لا زال أهل الإسلام في سائر الأقطار والمدن الكبار يحتفلون في شهر مولده صلى الله عليه وسلم بعمل الولائم البديعة، المشتملة على الأمور البهجة الرفيعة، ويتصدقون في لياليه بأنواع الصدقات، ويظهرون السرور ويزيدون في المبرات، ويعتنون بقراءة مولده الكريم، ويظهر عليهم من بركاته كل فضل عميم',
      'فصل في الاحتفال بالمولد الشريف، وذكر أدلة جوازه : من البدع الحسنة الاحتفال بمولد رسول الله صلى الله عليه وسلم، فهذا العمل لم يكن في عهد النبي صلى الله عليه وسلم ولا فيما يليه، إنما أحدث في أوائل القرن السابع للهجرة، وأول من أحدثه ملك إربل وكان عالمًا تقيًّا شجاعًا يقال له المظفر. جمع لهذا كثيرًا من العلماء فيهم من أهل الحديث والصوفية الصادقين. فاستحسن ذلك العمل العلماء في مشارق الأرض ومغاربها، منهم الحافظ أحمد بن حجر العسقلاني، وتلميذه الحافظ السخاوي، وكذلك الحافظ السيوطي وغيرهم',
      'سئلت عن أصل عمل المولد الشريف. فأجبت: لم ينقل عن أحد من السلف الصالح في القرون الثلاثة الفاضلة، وإنما حدث بعد، ثم ما زال أهل الإسلام في سائر الأقطار والمدن العظام يحتفلون في شهر مولده صلى الله عليه وسلم وشرف وكرم يعملون الولائم البديعة المشتملة على الأمور البهجة الرفيعة، ويتصدقون في لياليه بأنواع الصدقات، ويظهرون السرور، ويزيدون في المبرات بل يعتنون بقراءة مولده الكريم وتظهر عليهم من بركاته كل فضل عميم',
      'ولا يجوز أن يثبت له كيفية لأن الشرع لم يرد بذلك، ولا أخبر النبي عليه السلام فيه بشىء، ولا سألته الصحابة عنه، ولأن ذلك يرجع إلى التنقل والتحول وإشغال الحيّز والافتقار إلى الأماكن وذلك يؤول إلى التجسيم وإلى قِدم الأجسام وهذا كفرعند كافة أهل الإسلام',
      'وكذا إذا قيل لرجل : ألا تخشى الله تعالى ؟ فقال في حالة الغضب : لا، يصير كافرًا كذا في فتاوى قاضيخان',
      'والله تعَالى غَنِيٌّ عن العَالمينَ أي مُسْتَغنٍ عَن كُلّ ما سِوَاهُ أَزَلا وأَبَدًا فَلا يَحْتَاجُ إلى مَكَانٍ يتحيز فيه أو شَىءٍ يَحُلُّ به أو إلى جِهَةٍ لأنه ليس كشىءٍ منَ الأشياء ليس حجمًا كثيفًا ولا حجمًا لطيفًا والتحيزُ من صفاتِ الجسمِ الكثيفِ واللطيفِ فالجسمُ الكثيفُ والجسمُ اللطيفُ متحيزٌ في جهةٍ ومكانٍ قال الله تعالى: ﴿وَهُوَ الَّذِي خَلَقَ اللَّيْلَ وَالنَّهَارَ وَالشَّمْسَ وَالْقَمَرَ كُلٌّ فِي فَلَكٍ يَسْبَحُونَ (33)﴾ [سورة الأنبياء] فأثبتَ الله تعالى لكل من الأربعة التحيز في فلكه وهو المدار. ويَكفِي في تَنزِيهِ الله عن المَكَانِ والحَيّزِ والجِهَةِ قَولُه تَعالى: ﴿لَيْسَ كَمِثْلِهِ شَىْءٌ (11)﴾ [سورة الشورى] لأنه لَو كَانَ لَه مَكانٌ لَكَانَ لَهُ أَمثَالٌ وأبعَادٌ طُولٌ وعَرْضٌ وعُمْقٌ، ومَنْ كَانَ كذَلِكَ كَانَ مُحْدَثًا مُحْتَاجًا لِمَنْ حَدَّهُ بِهَذَا الطُّولِ وبِهَذَا العَرْضِ وبِهَذَا العُمْقِ، هذَا الدليلُ منَ القُرءانِ.',
      'أما احتفالنا بذكرى مولده فإنا لم نفعل غير ما فعله حسان بن ثابت رضي الله عنه حين كان يجلس إليه الناس و يُسمعهم مديح رسول الله صلى الله عليه و سلم في شعر, و لم نفعل غير ما فعل علي بن أبي طالب أو البراء بن عازب أو أنس بن مالك رضي الله عنهم حين يتحدثون عن محاسن رسول الله الخُلقية و الخلقية في جماعة',
      'موجودٌ قبل الخلقِ، ليس له قبلٌ ولا بعدٌ، ولا فوقٌ ولا تحتٌ، ولا يَمينٌ ولا شمالٌ، ولا أمامٌ ولا خلفٌ، ولا كلٌّ، ولا بعضٌ. ولا يقالُ متى كانَ ولا أينَ كانَ ولا كيفَ، كان ولا مكان، كوَّنَ الأكوانَ ودبَّر الزمانَ، لا يتقيَّدُ بالزمانِ ولا يتخصَّصُ بالمكان، ولا يشغلُهُ شأنٌ عن شأن، ولا يلحقُهُ وهمٌ، ولا يكتَنِفُهُ عقلٌ، ولا يتخصَّصُ بالذهنِ، ولا يتمثلُ في النفسِ، ولا يتصورُ في الوهمِ، ولا يتكيَّفُ في العقلِ، لا تَلحقُهُ الأوهامُ والأفكارُ، » لَيْسَ كَمِثلِهِ شَىءٌ وَهُوَ السَّمِيعُ البَصِيرُ »',
      'وهو الهادي لا يعلم العباد إلا ما علمهم ولا يدركون إلا ما يسر لهم إدراكه ، فالحواس والعقل فطرته وخلقه وعطيته',
      'كان الله ولـم يكن شىءٌ غيره فلـم يكن زمانٌ ولا مكان ولا قُطْرٌ ولا أوانٌ ، ولا عرشٌ ولا ملكٌ ، ولا كوكبٌ ولا فلكٌ ، ثم أوجد العالـم من غير احتياجٍ إليه ، ولو شاء ما أوجده . فهذا العالـم كله بما فيه من جواهر وأعراض حادثٌ عن عدم ، ليس فيه شائبة من قِدم ، حسبما اقتضته قضايا العقول ، وأيدته دلائل النقول ، أجمع عليه الـملِّيُّون قاطبةً إلاّ شُذاذاً من الفلاسفة قالوا بقدم العالـم ، وهم كفار بلا نزاع',
      '« عن عمر بن الخطاب رضي الله عنه قال: قال رسول الله (صلى الله عليه وسلم): « لما اعترف آدم عليه السلام بالخطيئة قال: يا رب أسألك بحق محمد لما غفرت لي. فقال الله: يا آدم، وكيف عرفت محمدا ولم أخلقه؟ قال: يا رب لأنك لما خلقتني بيدك، ونفخت فيّ من روحك رفعت رأسي، فرأيت على قوائم العرش مكتوبا: (لا إله إلا الله، محمد رسول الله) فعرفت أنك لم تضف إلى اسمك إلا أحب الخلق إليك، فقال الله: صدقت يا آدم، إنه لأحب الخلق إليّ، إذ سألتني بحقه فقد غفرت لك، ولولا محمد ما خلقتك ». قال الحاكم: هذا حديث صحيح الإسناد »',
      '{وَجَاءَ رَبُّكَ} أي أمره و قضاؤه. قاله الحسن ، وهو من باب حذف المضاف',
      'والله جل ثناؤه لا يوصف بالتحول من مكانٍ إلى مكانٍ ، وأنَّى له التحول والانتقال ولا مكان له ولا أوان ، ولا يجري عليه وقتٌ ولا زمــان ، لأن في جريان الوقت على الشىء فــوت الأوقات ، ومن فــاته شىء فهو عاجز',
      'ليس – أي الله – بجسم مصوَّر ، ولا جوهرٍ محدودٍ مقدَّرٍ ، ولا يُشبه شيئاً، ولا يُشبهه شىءٌ ، ولا تحيط به الجهات ، ولا تكتنفه الأرضون ولا السموات ، كان قبل أن كوَّن الـمكان ودبَّر الزمان ، وهو الآن على ما عليه كان',
      'حدثني عليّ، قال: ثنا أبو صالح، قال: ثنا معاوية، عن ابن عباس، قوله { يَوْمَ يُكْشَفُ عَن ساقٍ } هو الأمر الشديد المفظع من الهول يوم القيامة',
      'فـكـل مـا يـخـطـر بالبـال أبـد فـبخـلاف ذاك ربـنـا الأحـد »',
      'ومن علم أن الله سبحانه الغني على الاطلاق نزهه عن المكان و الزمان و الجهة',
      'ويكفر باثبات المكان لله تعالى، فإن قال: الله في السماء، فإن قصد حكاية ما جاء في ظاهر الأخبار لا يكفر، وإن أراد المكان كفر',
      'إن الذي أين الأين لا يقال له أين',
      'إن الذي كيف الكيف لا يقال له كيف',
      'يقول تعالى ذكره { يَوْمَ يُكْشَفُ عَنْ ساقٍ } قال جماعة من الصحابة والتابعين من أهل التأويل : يبدو عن أمر شديد',
      'وزيارة قبره – صلى الله عليه وسلم – سنة من سنن المسلمين مجمع عليها ، وفضيلة مرغب فيها روي عن ابن عمر رضي الله عنه',
      'اعلم أنّ الناس في أخبار الصفات على ثلاث مراتب : إحداها : إصرارها على ما جاءت من غير تفسير ولا تأويل ، إلّا أن تقع ضرورة كقوله تعالى : { وَجَاءَ رَبُّكَ } [الفجر : 22]، أي جاء أمره وهذا مذهب السلف',
      'وقالت المجسمة : فعلو المسافة و بعد المقدار و محاذاة الاجرام تعالى الله عن قولهم',
      '{من في السماء} هذا مجاز وقد قام البرهان العـقلي على أنه تعالى ليس بمتحـيز في جهـة',
      'القول بالـمكان – أي في حق الله – منافيٌ للتوحيد',
      'والمراد هنا ظل العرش كما جاء في حديث آخر مبينا ، والمراد يوم القيامة إذا قام الناس لرب العالمين ودنت منهم الشمس واشتد عليهم حرها ، وأخذهم العرق ، ولا ظل هناك لشيء إلا للعرش',
      'وقد قال جمع من السلف والخلف إن من اعتقد أن الله في جهة فهو كافر كما صرح به العراقي ، وبه قال أبو حنيفة ومالك والشافعي وأبو الحسن الأشعري والباقلاني ، ذكره العلامة ملا علي قاري في شرح المشكاة',
      'فرجعت إلى أسماء فخبرتها فقالت هذه جبة رسول الله صلى الله عليه وسلم فأخرجت إلي جبة طيالسة كسروانية لها لبنة ديباج وفرجيها مكفوفين بالديباج فقالت هذه كانت عند عائشة حتى قبضت فلما قبضت قبضتها وكان النبي صلى الله عليه وسلم يلبسها فنحن نغسلها للمرضى يستشفى بها',
      'وأما علوّه تعالى على خلقه الـمُستفاد من نحو قوله تعالى {وهُوَ القاهرُ فَوْقَ عِبَادِهِ} (سورة الأنعام / 18) فعلوّ مكانة ومَرتبةٍ لا علوّ مكانٍ كما هو مُقرَّرٌ عند أهل السنة والجماعة',
      'إنـه تعـالى ليـس فـي جـهـة',
      'وكفر من يثبت الحركة والقعود والحدود له تعالى مما لا يتنازع فيه مسلمان',
      'وقالت طائفة من العلماء : هو عالي بمعنى منزه عن صفات الحدوث و التشبيه و التحيز و هو قول حسن',
      '« س: كيف يكون الدخول في الإسلام؟',
      'ج: بالنطق بالشهادتين الدخول في الإسلام، وليس بقول أستغفر الله،',
      'أما قول الله تعالى إخبارا عن نوح أنه قال: {فقلت استغفروا ربكم} [سورة نوح]، فمعناه أن نوحا طلب من قومه أن يدخلوا في الإسلام بالإيمان بالله وبنبيه نوح ليغفر الله لهم. الحديث: « أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأني رسول الله » متفق عليه.»',
      'أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَن لاَ إِلَـهَ إِلاَّ اللهُ وَأَنِّي رَسُولُ اللهِ',
      'الاستواء له معان و للعرش ايضا معان في اللغة و ليس فيما يضاف إليه تعالى معنى الاستقرار و التمكن و القعود و الجلوس و الركوب بإجماع أهل الحق بل حكم الآية التفويض مع التنزيه أو الحمل على مثل معنى الملك و الاستئثار بالملك و البدء في إصدار الأمر و النهي و نحو ذلك مما هو مشروع في محله على مقتضى اللغة و لسان التخاطب',
      'وأما التشبيه : فهو الاعقاد ان الله تعالى يشبه شيئا من خلقه، كالذين يعتقدون أن الله تعالى جسم فوق العرش، أو يعتقدون أن له يدين بمعنى الجارحتين، وأن له الصورة الفلانية أو على الكيفية الفلانية، أو أنه نور يتصوره العقل، أو أنه في السماء أو في جهة من الجهات الست، أو أنه في مكان من الاماكن، او في جميع الأماكن، أو أنه ملأ السموات والأرض، أو أن له حلول في شىء من الأشياء، أو في جميع الأشياء، أو أنه متحد بشىء من الاشياء، أو في جميع الأشياء، أو أن الأشياء منحلة منه، أو شيئا منها. وجميع ذلك كفر صريح والعياذ بالله تعالى، وسببه الجهل بمعرفة الامر غلى ما هو عليه',
      'وأما ما قيل من أنه يلزم من نفي الجهات الست عن الله نفي وجوده !! فهو قول باطل بالبداهة لما هو معلوم من أن الله عز وجل كان موجودا قبل وجود الجهات الست المذكورة ، وهي فوق وتحت وأمام وخلف ويمين وشمال ، بل كان موجودا قبل وجود العالم كله بإجماع السابقين واللاحقين ، فكيف يتوهم من عنده أدنى شائبة عقل أنه يلزم من نفي تلك الجهات عنه سبحانه وتعالى نفي وجوده جل وعلا ؟؟!! وكيف يتصور أن الله عز وجل القديم يتوقف وجوده على وجود بعض الحوادث أو كل الحوادث التي خلقها ؟؟!! سبحانك هذا بهتان عظيم',
      'وروى البيهقي بسنده إلى الأعمش عن ابي صالح قال أصاب الناس قحط في زمن عمر رضى اللّه عنه فجاء رجل إلى قبر النبي صلى الله عليه وسلم فقال: يا رسول الله استسق لأمتك فأتاه رسول الله في المنام فقال: أئت عمر فاقرأه مني السلام وأخبره أنهم مسقون وقل له: عليك الكيس،قال فأتى الرجل عمر فأخبره فبكى عمر رضى اللّه عنه وقال: يا ربّ ما ءالو إلا ما عجزت عنه',
      '« ما معنى قوله تعالى: {لم يلد ولم يولد} ج: معناه نفي المادية والانحلال عن الله. فالله لا يحل في شيء ولا ينحل منه شيء ولا يحل فيه شيء.',
      'قال الإمام جعفر الصادق: « من زعم أن الله في شيء أو من شيء أو على شيء فقد أشرك » رواه القشيري في الرسالة القشيرية. »',
      'مَن زَعَمَ أَنَّ اللهَ فِي شِىءٍ أَوْ مِن شَىءٍ أَوْ عَلٰى شَىءٍ فَقَدْ أَشْرَكَ',
      '« وقيل المراد ظل عرشه ، ويدل عليه حديث سلمان عند سعيد بن منصور بإسناد حسن « سبعة يظلهم الله في ظل عرشه» »',
      'حدّثنا عبد الله، حدّثنا محمّد بن عبد الله المخزوميُّ، حدّثنا أحمد بن نصر بن مالك، حدّثنا الحسين بن الوليد، عن هارون بن موسى قال: أوّل مَن نقط المصاحف يحيى بن يعمر',
      'سألته عن الرجل يمس منبر النبي صلى الله عليه وسلم ويتبرك بمسه ويقبله ويفعل بالقبر مثل ذلك أو نحو هذا يريد بذلك التقرب إلى الله عز و جل فقال: لا بأس بذلك',
      '« حكم ساب الله انه كافر‚ بين ذلك مع الدليل : ج: نقل القاضي عياض الإجماع على ان ساب الله كافر ولو كان غاضبا أو مازحا أو غير منشرح الصدر. قال تعالى: ( ولئن سألتهم ليقولن إنما كنا نخوض ونلعب قل ابالله وءاياته ورسوله كنتم تستهزئون لا تعتذروا قد كفرتم بعد إيمانكم) سورة التوبة ءاية 65ـ 66. الحديث : « ان العبد ليتكلم بالكلمة لا يرى بها بأسا يهوي بها في النار سبعين خريفا » رواه الترمذي. »',
      'وأما إقرار الرسول صلى الله عليه وآله وسلم الجارية على إشارتها نحو السماء فاكتفاء منها بما يدل على عدم شركها لتعتق ، لأنه بإشارتها إلى السماء علم أنها ليست ممن يعبد الأصنام التي في الأرض',
      'و أقول : إن التوسل بالنبي (صلى الله عليه وسلم) جائز في كل حال: قبل خلقه، وبعد خلقه، في مدة حياته في الدنيا، وبعد موته، في مدة البرزخ، وبعد البعث في عرصات القيامة والجنة.',
      'يدُهُ صفتُهُ بلا كيفٍ، وغضبُهُ ورضاهُ صفتانِ من صفاتِهِ بلا كيفٍ',
      '« ما هو أول المخلوقات ؟ ج: أول المخلوقات الماء. قال تعالى: ﴿ وَجَعَلْنَا مِنَ المَاءِ كُلَّ شَىءٍ حَيّ ﴾ سورة الأنبياء ءاية 30. الحديث : « كُلُّ شَىءٍ خُلِقَ مِنَ المَاءِ » رواه ابن حبان.»',
      'كُلُّ شَىْءٍ خُلِقَ مَنَ الْمَاءِ',
      'وعند هنا لا يراد بِها ظرف الـمكان لأنه تعالى منـزه عن الـمكان ، بل الـمعنى شرف الـمكانة وعلو الـمنـزلة',
      'لمّا قضى اللهُ الخلق كتب في كتابه فهو عنده فوق العرش: إن رحمتي غلبت غضبي',
      'فمن أظلم ممن كذب على الله أو من ادعى إدعاء معيناً مشتملاً على إثبات المكان والهيئة والجهة من مقابلة وثبوت مسافة وأمثال تلك الحالة ، فيصير كافراً لا محالة',
      '« س: ما حكم نداء نبي أو ولي ولو كان غائبا أو طلب شيء منه لم تجر به العادة ؟ ج: يجوز ذلك لأن مجرد ذلك لا يعد عبادة لغير الله وليس مجرد قول يا رسول الله إشراكا بالله، وقد ثبت أن بلال بن الحارث المزني أتى قبر الرسول عام الرمادة أيام عمر فقال: يا رسول الله استسق لأمتك فإنهم قد هلكوا رواه البيهقي وغيره فلم ينكر عليه عمر ولا غيره بل استحسنوا فعله.',
      'قال تعالى: {ولو أنهم إذ ظلموا أنفسهم جاءوك فاستغفروا الله واستغفر لهم الرسول لوجدوا الله توابا رحيما} [سورة النساء].',
      'وثبت أن ابن عمر قال « يا محمد » لما خدرت رجله رواه البخاري في الأدب المفرد.»',
      'الانبياء كثير و الرسل منهم ثلثمائة عشر واول الرسل أبو جميع البشر و هو آدم عليه السلام وآخرهم محمد صلى الله عليه و السلم',
      'ءادم فمن سواه من الأنبياء تحت لوائي يوم القيامة',
      'لأن كل من في السموات والأرض وما فيهما وما بينهما خلق الله تعالى وملك له وإذا كان كذلك يستحيل على الله أن يكون في السماء أو في الأرض إذ لو كان في شىء لكان محصورا أو محدودا ولو كان كذلك لكان محدثا وهذا مذهب أهل الحق والتحقيق وعلى هذه القاعدة قوله تعالى: {ءأمنتم من في السماء} وقوله عليه السلام للجارية: أين الله؟ قالت في السماء، ولم يُنكر عليها وما كان مثله ليس على ظاهره بل هو مؤول تأويلات صحيحة قد أبداها كثير من أهل العلم في كتبهم',
      '« كُنَّا عِنْدَ مَالِكِ بْنِ أَنَسٍ ، فَجَاءَ رَجُلٌ , فَقَالَ : يَا أَبَا عَبْدِ اللَّهِ ، الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى (سورة طه آية 5) ، كَيْفَ اسْتَوَى ؟ , فَأَطْرَقَ مَالِكٌ رَأْسَهُ ، ثُمَّ عَلاهُ الرُّحَضَاءُ , ثُمَّ قَالَ : الاسْتِوَاءُ غَيْرُ مَجْهُولٍ ، وَالْكَيْفُ غَيْرُ مَعْقُولٍ ، وَالإِيمَانُ بِهِ وَاجِبٌ ، وَالسُّؤَالُ عَنْهُ بِدْعَةٌ ، وَمَا أَرَاكَ إِلا مُبْتَدِعًا ، فَأَمَرَ بِهِ أَنْ يَخْرُجَ .',
      'قَالَ الشَّيْخُ [البيهقي] : وَعَلَى مِثْلِ هَذَا دَرَجَ أَكْثَرُ عُلَمَائِنَا فِي مَسْأَلَةِ الاسْتِوَاءِ وَفِي مَسْأَلَةِ الْمَجِيءِ وَالإِتْيَانِ وَالنُّزُولِ ، قَالَ اللَّهُ عَزَّ {وَجَاءَ رَبُّكَ وَالْمَلَكُ صَفًّا صَفًّا} (سورة الفجر آية 22) وَقَالَ : {هَلْ يَنْظُرُونَ إِلا أَنْ يَأْتِيَهُمُ اللَّهُ فِي ظُلَلٍ مِنَ الْغَمَامِ} (سورة البقرة آية 210) .»',
      'وهو شىءٌ لا كالأشياءِ، ومعنى الشىءِ إثباتُهُ بلا جسمٍ ولا جوهرٍ ولا عَرَضٍ، ولا حدَّ لهُ، ولا ضدَّ لهُ، ولا ندَّ له، ولا مِثلَ لهُ',
      'ومعنى {ينـزل ربنا إلى سماء الدنيا} ينـزل رسوله أو رحمته',
      '« قوله : «قال فرجعت إلى ربي» أي إلى المكان الذي ناجيت فيه ربي و ليس المراد أنَّ اللهَ في ذلك المكان و رجع له فإنَّ اعتقاد ذلك كُفر »',
      'إنّما ذاكَ جبرِيلُ عليه السلام كان يأتِيه، وإنّما أتَاهُ هذِه المرّةَ في صُورَتِه التي هي هَيئَتُه الأصليَّةُ فسَدَّ أُفُقَ السّماء',
      'من سبَّ النبيَّ صلى الله عليه وسلم أو عابَه أو ألَحقَ به نقصَا في نفسِه أو نسَبه أو دِينه أو خصلهً من خصاله أو عرَّضَ به أو شبَّهه بشىء على طريق السبّ له أو الإَزراءِ عَليه أو التصغَير لشأنه أو الغضّ منه والعيب له فهو سَابُّ له',
      'قلتُ : أرأيتَ لو قيل أين الله تعالى ؟ فقال – أي أبو حنيفة – : يقال له كان الله تعالى ولا مكان قبل أن يخلق الخلق ، وكان الله تعالى ولـم يكن أين ولاخَلْق ولاشىء ، وهو خالق كل شىء',
      'إن الله تعالى لا يحويه مكان ولا تحصره جهة، لا فوق ولا تحت، كان الله تعالى في الأزل ولم يكن شيء من الكائنات والأمكنة والجهات على الإطلاق',
      'قال القرطبي : هذا أقرب بالرتبة والكرامة لا بالـمسافة ، لأنه منـزه عن الـمكان والـمساحة والزمان . وقال البدر بن الصاحب في تذكرته : في الحديث إشارةٌ إلى نفي الجهة عن الله تعالى',
      'ومعنى { ءأمنتم من في السماء } من في السماء عذابه أو سلطانه ومصدر أمره ، أو هو كناية عن تعظيم الله تعالى بوصفه بالعلو والعظمة ، وتنـزيهه عن السفل والتحت لا أنه سبحانه وتعالى حال فيها !! لأن الحلول من صفات الأجسام وأمارات الحدوث والله منـزه عن ذلك',
      'اعتاد الناس الاحتفال لاستماع قصة مولده الشريف عليه الصلاة والسلام ولنعمة الذكرى بمولد النبي العظيم الذي أخرج اللهُ الخلق بهديه من الظلمات إلى النور',
      'قال الضحَّاك وأبو عبيدة في قوله: { كُلُّ شَيْءٍ هَالِكٌ إِلاَّ وَجْهَهُ } [ القصص: الآية 88 ] ، أي: إلا هو',
      'قال جمع منهم ومن الخلف : إن معتقد الجهة كافر ، كما صرح به العراقي ، وقال : إنه قول لأبي حنيفة ومالك والشافعي والأشعري والباقلاني',
      'قلت : يا رسول الله إني إذا رأيتك طابت نفسي وقرت عيني أنبئني عن كل شيء ، قال : كُلُّ شَىْءٍ خُلِقَ مَنَ الْمَاءِ',
      'وأما الخلف رحمهم الله تعالى فيقولون في هذه الآيات والأحاديث هي معروفة المعنى ، فمعنى { الرحمن على العرش استوى } استولى بالقهر والتصرف',
      'ليس له (أي حديث جابر) إسناد يعتمد عليه',
      'أنه لا يحل في شئ، ولا يحل فيه شئ، تعالى عن أن يحويه مكان كما تقدس عن أن يحويه زمان، بل كان قبل أن يخلق الزمان والمكان وهو الآن على ما عليه كان',
      'إن الأسماء مأخوذة من الشريعة واللغة، وأهل اللغة وضعوا هذا الاسم على ذي طولٍ وعرضٍ وسمكٍ وتركيبٍ وصورةٍ وتأليف والله تعالى خارج عن ذلك كله، فلم يجز أن يسمى جسمًا لخروجه عن معنى الجسمية، ولم يجىء في الشريعة ذلك فبطل',
      'واعلـم أَنَّا إذا قلنا إن الله عزّ وجل فوق ما خلق لـم يُرْجَعْ به إلى فوقية المكان والارتفاع على الأمكنة بالـمسافة والإشراف عليها بالـمماسة لشىء منها',
      'قوله – صلى الله عليه وسلم – : ( ينزل ربنا كل ليلة إلى السماء الدنيا فيقول : من يدعوني فأستجيب له ) هذا الحديث من أحاديث الصفات ، وفيه مذهبان مشهوران للعلماء سبق إيضاحهما في كتاب الإيمان ومختصرهما أن أحدهما وهو مذهب جمهور السلف وبعض المتكلمين : أنه يؤمن بأنها حق على ما يليق بالله تعالى ، وأن ظاهرها المتعارف في حقنا غير مراد ، ولا يتكلم في تأويلها مع اعتقاد تنزيه الله تعالى عن صفات المخلوق ، وعن الانتقال والحركات وسائر سمات الخلق . والثاني : مذهب أكثر المتكلمين وجماعات من السلف وهو محكي هنا عن مالك والأوزاعي : أنها تتأول على ما يليق بها بحسب مواطنها . فعلى هذا تأولوا هذا الحديث تأويلين أحدهما : تأويل مالك بن أنس وغيره معناه : تنزل رحمته وأمره وملائكته كما يقال : فعل السلطان كذا إذا فعله أتباعه بأمره . والثاني : أنه على الاستعارة ، ومعناه : الإقبال على الداعين بالإجابة واللطف . والله أعلم .',
      'وأما مذهب السلف والخلف بالنسبة للآيات والأحاديث المتشابهة فقد اتفق الكل على أن الله تعالى منـزه عن صفات الحوادث ، فليس له عز وجل مكان في العرش ولا في السماء ولا في غيرهما ، ولا يتصف بالحلول في شيء من الحوادث ، ولا بالاتصال بشيء منها ، ولا بالتحول والانتقال ونحوهما من صفات الحوادث ، بل هو سبحانه وتعالى على ما كان عليه قبل خلق العرش والكرسي والسماوات وغيرها من الحوادث',
      'فإذا معبود هذا الخاسر يقوم ويمشي ويتحرك، ولعل هذا الاعتقاد ورثه هذا السجزي من جيرانه عباد البقر، ومن اعتقد ذلك في إله العالمين يكون كافرًا باتفاق، فيا ويح من يقتدي بمثله في الصلاة أو يناكحه',
      'قال القاضي عياض : لا خلاف بين المسلمين قاطبة فقيههم ومحدثهم ومتكلمهم ونظارهم ومقلدهم أن الظواهر الواردة بذكر الله تعالى في السماء كقوله تعالى {أأمنتم من في السماء أن يخسف بكم الارض} ونحوه ليست على ظاهرها بل متأولة عند جميعهم',
      'وهو فوق العرش والسماء وفوق كل شيء إلى تخوم الثرى، فوقية لا تزيده قرباً إلى العرش والسماء كما لا تزيده بعداً عن الأرض والثرى بل هو رفيع الدرجات عن العرش والسماء كما أنه رفيع الدرجات عن الأرض والثرى',
      'بَابُ مَا يَقُولُ الرَّجُلُ إِذَا خَدِرَتْ رِجْلُهُ : حَدَّثَنَا أَبُو نُعَيْمٍ ، قَالَ : حَدَّثَنَا سُفْيَانُ ، عَنْ أَبِي إِسْحَاقَ ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ , قَالَ : خَدِرَتْ رِجْلُ ابْنِ عُمَرَ ، فَقَالَ لَهُ رَجُلٌ : اذْكُرْ أَحَبَّ النَّاسِ إِلَيْكَ ، فَقَالَ » يَا مُحَمَّد »',
      'لا يجوز على الله عز وجل الحلول في الأماكن لاستحالة كونه محدودًا ومتناهياً وذلك لاستحالة كونه مُحدَثاً',
      'واعلم أنّ القرافيّ وغيره حكوا عن الشّافعيّ ومالكٍ وأحمد وأبي حنيفة رضي الله عنهم القول بكفر القائلين بالجهة والتّجسيم وهم حقيقون بذلك',
      'واستدلاله على زعمه الباطل بهاتين الآيتين ونحوهما أن الله عز وجل يحل في عرشه أو يجلس عليه أو يحل في سماء أو نحو ذلك مما تزعمه تلك الشرذمة ، مع أن كلام الله غير مخلوق وهو من صفات الله تعالى القديمة الموجودة قبل وجود العرش والسماوات ، فالله تعالى موصوف بأنه استوى على العرش قبل وجود العرش ، وهل كان جالسا ـ على زعمهم ـ على العرش المعدوم قبل وجوده ؟؟!! وهل جل جلاله في السماء قبل خلق السماء ؟؟!! هذا مما لا يتوهمه عاقل ، وهل العقل يصدق بحلول القديم في شيء من الحوادث ؟؟!! فإنا لله وإنا إليه راجعون ، وعلى الجملة فهذا القائل المجازف وأمثاله قد ادعوا ما لا يقبل الثبوت لا عقلا ولا نقلا ، وقد كفروا وهم يحسبون أنهم يحسنون صنعا ، والطامة الكبرى التي نـزلت بهؤلاء دعواهم أنهم ( سلفيون ) !!! ، وهم عن سبيل الحق زائغون ، وعلى خيار المسلمين يعيبون ، فلا حول ولا قوة إلا بالله العلي العظيم',
      'اسْتَوَى : استولى عن الزجاج ونبه بذكر العرش وهو أعظم المخلوقات على غيره وقيل لما كان الاستواء على العرش وهو سرير الملك مما يرادف الملك جعلوه كناية عن الملك فقالوا استوى فلان على العرش أي ملك وإن لم يقعد على السرير البتة وهذا كقولك يد فلان مبسوطة أي جواد وإن لم يكن له يد رأسا والمذهب قول علي رضي الله عنه : الاستواء غير مجهول والتكييف غير معقول والإيمان به واجب والسؤال عنه بدعة لأنه تعالى كان ولا مكان فهو على ما كان قبل خلق المكان لم يتغير عما كان',
      'اعتقاده هو أن الله يحويه مكان، وقله سطح، وذلك قول بالتجسيم، ومن يعد الله سبحانه متمكناً بمكان فهو عابد وثن، خارج عن جماعة المسلمين، كما نص على ذلك غير واحد من أئمة أصول الدين، تعالى الله عن إفك الأفاكين.',
      'قال الله تعالى : {وَيَبْقَى وَجْهُ رَبِّكَ ذُو الْجَلاَلِ وَالإِكْرَامِ} [الرحمن: الآية 27]، قال المفسرون : معناه : يبقى ربك',
      'قوله تعالى { وَهُوَ العَلِيُّ العَظِيمُ } لا يجوز أن يكون الـمراد بكونه عليًّا العلو في الجهة والـمكان لـما ثبتت الدلالة على فساده ، ولا يجوز أن يكون الـمراد من العظيم العظمةَ بالجثةَ وكبرَ الجسم ، لأن ذلك يقتضي كونه مؤلَّفًا من الأجزاء والأبعاض ، وذلك ضد قوله : { اللَّهُ أَحَدٌ } ، فوجب أن يكون الـمراد من العَلي الـمتعالي عن مشابَهة الـممكنات ومناسبة الـمحدَثات ، ومن العظيم العظمة بالقدرة والقهر بالاستعلاء وكمال الإلـهية',
      'وأنه مستو على العرش على الوجه الذي قاله وبالمعنى الذي أراده استواء منزهاً عن المماسة والاستقرار والتمكن والحلول والانتقال لا يحمله العرش بل العرش وحملته محمولون بلطف قدرته ومقهورون في قبضته',
      'قد سألني بعض الراغبين في معرفة عقائد الدين ، والوقوف على مذهب السلف والخلف في المتشابه من الآيات والأحاديث بما نصه : ما قول السادة العلماء حفظهم الله تعالى فيمن يعتقد أن الله عز وجل له جهة !! وأنه جالس على العرش في مكان مخصوص !! ويقول : ذلك هو عقيدة السلف',
      'فالحكم أن هذا الاعتقاد باطل ومعتقده كافر بإجماع من يعتد به من علماء المسلمين ، والدليل العقلي على ذلك : قدم الله تعالى ومخالفته للحوادث ، والنقلي قال تعالى : ليس كمثله شىء وهو السميع البصير',
      'والمشتهر المتفق عليه بالإجماع القاطع كجبريل و ميكائيل ومالك […] وكعزرائيل…',
      '« قال الشافعي: لا يكفر أحد من أهل القبلة.',
      '[ فقال السيوطي : ] واستثنى من ذلك المجسم، ومنكر علم الجزئيات »',
      'اتفق علمـاء السنــة على أنّ الله غني عن كلّ شيء وكلَّ شيء مفتقـِر إليه، قائمٌ بنفسِه لا يحتاج إلى محـلّ ولا إلى مُخَـَصَّص، فهو الذي خلق الزمان والمكان وهو على مــا عليه كان قبل أن لا زمان و لا مكان',
      'ورؤيةُ الله تعالى جَائزَةٌ في العقلِ واجبةٌ بالنقلِ، وقد وردَ الدليلُ السَّمعيُّ بإيجاب رؤيةِ المؤمنينَ لله تعالى في دارِ الآخرةِ، فيُرى لا في مكانٍ، ولا على جهةٍ من مُقابلةٍ أو اتصالِ شُعاعٍ أو ثبوتِ مسافةٍ بين الرائي وبينَ الله تعالى',
      'حدثنا آدم قال: حدثنا ابن أبي ذئب، عن الزهري، عن السائب بن يزيد قال: كان النداء يوم الجمعة، أوله إذا جلس الإمام على المنبر، على عهد النبي صلى الله عليه وسلم وأبي بكر وعمر رضي الله عنهما، فلما كان عثمان رضي الله عنه، وكثر الناس، زاد النداء الثالث على الزوراء .',
      'وأنه ليس بجسم مصور ولا جوهر محدود مقدر وأنه لا يماثل والأجسام ولا في التقدير ولا في قبول الانقسام وأنه ليس بجوهر ولا تحله الجواهر ولا بعرض ولا تحله الأعراض بل لا يماثل موجوداً ولا يماثله موجود {ليس كمثله شيء} ولا هو مثل شيء. وأنه لا يحده المقدار ولا تحويه الأقطار ولا تحيط به الجهات ولا تكتنفه الأرضون ولا السموات',
      'أَنَّ النَّبِيَّ صَلَّى الله عَلَيْهِ وَسَلَّمَ اسْتَسْقَى ، فَأَشَارَ بِظَهْرِ كَفَّيْهِ إِلَى السَّمَاءِ',
      '« قوله – صلى الله عليه وسلم – : ( أين الله ؟ قالت في السماء قال : من أنا؟ قالت : أنت رسول الله قال : أعتقها فإنها مؤمنة )',
      'هذا الحديث من أحاديث الصفات ، وفيها مذهبان تقدم ذكرهما مرات في كتاب الإيمان .',
      'أحدهما : الإيمان به من غير خوض في معناه ، مع اعتقاد أن الله تعالى ليس كمثله شيء وتنزيهه عن سمات المخلوقات .',
      'والثاني تأويله بما يليق به ، فمن قال بهذا قال : كان المراد امتحانها ، هل هي موحدة تقر بأن الخالق المدبر الفعال هو الله وحده ، وهو الذي إذا دعاه الداعي استقبل السماء كما إذا صلى المصلي استقبل الكعبة ؟ وليس ذلك ؛ لأنه منحصر في السماء كما أنه ليس منحصرا في جهة الكعبة ، بل ذلك لأن السماء قبلة الداعين ، كما أن الكعبة قبلة المصلين ، أو هي من عبدة الأوثان العابدين للأوثان التي بين أيديهم ، فلما قالت : في السماء ، علم أنها موحدة وليست عابدة للأوثان . »',
      'احتج علماء التوحيد قديماً وحديثاً بهذه الآية في نفي كونه تعالى جسماً مركباً من الأعضاء والأجزاء وحاصلاً في المكان والجهة، وقالوا لو كان جسماً لكان مثلاً لسائر الأجسام، فيلزم حصول الأمثال والأشباه له، وذلك باطل بصريح قوله تعالى: {لَيْسَ كَمِثْلِهِ شَيْءٌ}',
      'قال الخطابي وقد تأول البخاري الضحك في موضع آخر على معنى الرحمة ، وهو قريب ، وتأويله على معنى الرضا أقرب',
      'يضحك الله إلى رجلين يقتل أحدهما الآخر يدخلان الجنة، يقاتل هذا في سبيل الله فيقتل، ثم يتوب الله على القاتل فيقاتل فيستشهد',
      'وأولُ الأنبياءِ ءادمُ عليه السلام وءاخرهم محمدٌ صلى الله عليه وسلم',
      'فكل من اعتقد أنه تعالى حل في مكان أو اتصل به أو بشيء من الحوادث كالعرش أوالكرسي أو السماء أو الأرض أو غير ذلك فهو كافر قطعا ، ويبطل جميع عمله من صلاة وصيام وحج وغير ذلك ، وتبين منه زوجه وعليه أن يتوب فورا ، وإذا مات على هذا الاعتقاد ـ والعياذ بالله تعالى ـ لا يغسل ولا يصلى عليه ولا يدفن في مقابر المسلمين ، ومثله في ذلك كله من صدقه في اعتقاده أعاذنا الله تعالى من شرور أنفسنا وسيئات أعمالنا ، وأما حمله الناس على أن يعتقدوا هذا الاعتقاد المكفر وقوله لهم من لم يعتقد ذلك يكون كافرا !! فهو كفر وبهتان عظيم',
      'فإن قيل: كيف يرى؟ قيل: بلا كيف، إذ الكيفية تكون لدى صورة بل يرى بلا وصف قيام وقعود واتكاء وتعلق واتصال وانفصال ومقابلة ومدابرة، وقصير وطويل، ونور، وظلمة وساكن ومتحرك، ومماس ومباين، وخارج وداخل ولا معنى يأخذه الوهم أو يقدره العقل لتعاليه عن ذلك',
      'وليسَ قربُ اللهِ تعالى ولا بُعدُهُ منْ طريقِ طولِ المسافةِ وقِصَرِها و لكن على معنى الكرامةِ والهوانِ، و المطيعُ قريبٌ منهُ بلا كيفٍ، والعاصي بعيدٌ عنهُ بلا كيفٍ',
      'إنه تعالى كان ولا مكان فهو على ماكان قبل خلق الـمكان ، لـم يتغير عما كان',
      'وتنـزيه الله سبحانه عن الـمكان والـمكانيات والزمان والزمانيات هو عقيدة أهل الحق رغم اغتياظ الـمجسمة الصرحاء',
      'يكفر بإثبات المكان لله تعالى',
      'ولو قال الله تعالى في السماء، فإن قصد به حكاية ما جاء فيه ظاهر الأخبار لا يكفر و إن أراد به المكان يكفر',
      'واعلـم أن المشبِّهة احتجوا على إثبات الـمكان لله تعالى بقوله : { ءأَمِنتُم مَّن فيِ السَّمَاءِ }',
      '« يا أبا عبد الله، أستقبل القبلة ، وأدعو أم أستقبل رسول الله – صلى الله عليه وسلم – ؟',
      'فقال : ولم تصرف وجهك عنه ، وهووسيلتك ، ووسيلة أبيك آدم – عليه السلام – إلى الله – تعالى – يوم القيامة ؟ بل استقبله ، واستشفع به ، فيشفعه الله. قال الله تعالى : {وَلَوْ أَنَّهُمْ إِذْ ظَلَمُوا أَنْفُسَهُمْ جَاءُوكَ فَاسْتَغْفَرُوا اللهَ وَاسْتَغْفَرَ لَهُمُ الرَسُولُ لَوَجَدُوا اللهَ تَوَّابًا رَحِيمًا} »',
      'بسم الله الرحمن الرحيم الحمد لله رب العالمين ، المنـزه عن صفات المخلوقين ، كالجهة والجسمية والمكان والفوقية ، والصلاة والسلام على سيدنا محمد ، الذي جاء بمحو الشرك والإلحاد وأمرنا بتنـزيه الله تعالى عن صفات العباد',
      'وعن جعفر الصادق رضي اللَّه عنه أنه قال: التوحيدُ ثلاثةُ أحرفٍ، أن تعرفَ أنه ليس من شيءٍ، ولا في شيءٍ، ولا على شيءٍ، لأنه من وصفَهُ أنه من شيءٍ فقد وصفهُ بأنه مخلوقٌ فيكفرُ، ومن قال: إِنه في شيءٍ. فقد وصفه بأنه مُحدَثٌ فيكفرُ. ومن قال على شيءٍ فقد وصفهُ بأنه محتاجٌ محمولٌ فيكفر',
      '« لما رمى رسول الله صلى الله عليه وسلم الجمرة, و نحر نسكه و حلق, ناول الحالق شقه الأيمن فحلقه. ثم دعا أبا طلحة الأنصاري فأعطاه إياه. ثم ناوله الشق الأيسر. فقال « احلق » فحلقه, فأعطاه أبا طلحة. فقال « اقسمه بين الناس » »',
      'قال ابن كيسان : قوة الله ونصرته فوق قوتهم ونصرتهم',
      '« وقال الإمام الأعظم (يعني الإمام أبو حنيفة) رحمه الله في كتابه « الوصية » : ولقاء الله تعالى لأهل الجنة بلا كيف ولا تشبيه ولا جهةٍ حقٌّ »',
      '« قال ابن عقيل : « تعالى الله أن يكون له صفة تشغل الأمكنة ، لأنّ هذا عين التجسيم ، وليس الحق بذي أجزاء وأبعاض يعَالج بِها »',
      '« ذكر الشيخ الإمام ابن عبد السلام في كتاب حل الرموز: أنه قال الإمام أبو حنيفة رحمه الله :',
      'من قال لا أعرف الله تعالى في السماء هو أم في الأرض كفر، لأن هذا القول يوهم أن للحق مكانا، ومن توهم أن للحق مكانا فهو مشبه',
      'ولا شك أن ابن عبد السلام من أجل العلماء وأوثقهم، فيجب الاعتماد على نقله »',
      'وقوله تعالى {كل شىء هالك الا وجهه} قالت فرقة : المعنى : كل شىء هالك الا هو سبحانه، قاله الطبرى وجماعة منهم ابو المعالى (الجويني) رحمه الله ، وقال الزجاج الا اياه',
      'معناه : المرتفع عن أن يجوز عليه ما يجوز على المحدَثين من الأزواج والأولاد والجوارح والأعضاء واتخاذ السرير للجلوس عليه، والاحتجاب بالستور عن أن تنفذ الأبصار إليه، والانتقال من مكان إلى مكان ونحو ذلك، فإن إثبات بعض هذه الأشياء يوجب النهاية، وبعضها يوجب الحاجة، وبعضها يوجب التغير والاستحالة، وشىء من ذلك غير لائق بالقديم ولا جائز عليه',
      'واعلـم أن السَّلَفَ قائلون باستحالة العلو الـمكاني عليه تعالى ، خلافاً لبعض الجهلة الذين يخبطون خبط عشواء في هذا الـمقام ، فإن السلف والخلف متفقان على التنـزيه',
      'سمعت خطبة أبي بكر الصديق وعمر بن الخطاب وعثمان بن عفان وعلي بن أبي طالب رضى الله عنهم والخلفاء هلم جرا إلى يومي هذا فما سمعت الكلام من فم مخلوق أفخم ولا أحسن منه من في عائشة رضى الله عنها',
      'وهو الذي إذا دعاه الداعي استقبل السماء كما إذا صلى المصلي استقبل الكعبة وليس ذلك لأنه منحصر في السماء كما أنه ليس منحصرا في جهة الكعبة بل ذلك لأن السماء قبلة الداعين كما أن الكعبة قبلة المصلين',
      'وقيل ليحيى بن معاذ (الرازي) : أَخْبِرْني عن الله عز وجل ، فقال : إله واحد ، فقيل له : كيف هو ؟ قال : ملك قادر ، فقيل : أين هو ؟ فقال : هو بالمرصاد ، فقال السائل : لم أسألك عن هذا ؟ فقال : ما كان غير هذا كان صفة المخلوق ، فأما صفته فما أخبرتك عنها .',
      'وأما ما ورد في التنزيل من الاستواء والوجه واليدين والجنب والمجيء والإتيان والفوقية وغير ذلك فأجروها على ظاهرها أعني ما يفهم عند الإطلاق على الأجسام',
      'وهو متكلمٌ بكلامٍ هو صفةٌ لهُ أزليةٌ ليس من جنسِ الحروفِ والأصواتِ وهو صفةٌ منافيةٌ للسكوتِ والآفةِ، والله تعالى متكلمٌ بها ءامرٌ ناهٍ مخبِرٌ، والقرءانُ كلامُ الله تعالى غيرُ مخلوقٍ',
      'فلا يقال أين ولا كيف ولا متى لأنه خالق الزمان والـمكان',
      'قال البخاري معنى الضحك الرحمة',
      'والأعلى صفة الرب ، والـمراد بالعلو العلو بالقهر والاقتدار ، لا بالـمكان والجهة ، لتنـزهه عن ذلك',
      'والقاعدة تنـزيهه – جل و عز – عن الحركة والانتقال وشغل الأمكنة',
      'الأصل السابع : العلـم بأنَّ الله تعالى منـزه الذات عن الاختصاص بالجهات ، فإنَّ الجهة إما فوق وإما أسفل وإما يمين وإما شمال أو قدَّام أو خلف ، وهذه الجهات هو الذي خلقها',
      '« و سئل ذو النون المصري عن قوله تعالى : « ٱلرَّحۡمَـٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ ».',
      'فقال : أثبتَ ذاته و نفى مكانه، فهو موجود بذاته، والأشياء موجودة بحكمه، كما شاء سبحنه »',
      'اللهم ربَّ السموات ورب الأرض، ورب العرش العظيم، ربنا ورب كل شيء، فالق الحب والنوى، ومُنزل التوراة والإنجيل والفرقان، أعوذ بك من شر كل شيء أنت آخذٌ بناصيته، اللهم أنت الأول فليس قبلك شيء، وأنت الآخر فليس بعدك شيء، وأنت الظاهر فليس فوقك شيء، وأنت الباطن فليس دونك شيء، اقض عنا الدَّيْنَ واغننا من الفقر',
      'والمحدِثُ للعالم هو الله تعالى الواحدُ القديمُ الحيُّ القادرُ العليمُ السميعُ البصيرُ الشائي المريدُ ليس بِعَرَضٍ، ولا جسمٍ، ولا جوهرٍ، ولا مُصوَّرٍ، ولا محدودٍ، ولا معدودٍ، ولا متبعِّضٍ، ولا متجزّ، ولا مُتَركّبٍ، ولا متناهٍ، ولا يُوصف بالماهيةِ، ولا بالكيفيةِ، ولا يتمكَّنُ في مكانٍ، ولا يجري عليهِ زمانٌ، ولا يُشبههُ شىءٌ، ولا يَخرُجُ عن علمِهِ وقدرتِهِ شىءٌ.',
      '{كُلُّ شَىءٍ هَالِكٌ إِلَّا وَجهَهُ}: إِلَّا مُلكَهُ ، ويقال: إلا ما أريد به وجه الله',
      '« أن كل رسول نبي ، وليس كل نبي رسولا . وأول الرسل آدم ، وآخرهم محمد (صلى الله عليه وسلم). وفي حديث أبي ذر (رضي الله عنه): « إن الأنبياء مائة ألف ، وأربعة وعشرون ألف نبي». وذكر أن الرسل منهم ثلاثمائة وثلاثة عشر ، أولهم آدم (عليه السلام). »',
      '« قال محمد بن سحنون : أجمع العلماء أن شاتم النبي – صلى الله عليه وسلم – المتنقص له كافر . والوعيد جار عليه بعذاب الله ، […] ومن شك في كفره ، وعذابه كفر » .',
      'اعلم أن النزول الذي هو الانتقال من علو إلى سفل لا يجوز حمل الحديث عليه، لوجوه : الأول : النزول من صفات الأجسام والمحدَثات ويحتاج إلى ثلاثة : منتقِل، ومنتقَل عنه ومنتقَل إليه، وذلك على الله تعالى محال. الثاني : لو كان النزول لذاته حقيقة لتجددت له في كل يوم وليلة حركات عديدة تستوعب الليل كله، وتنقلات كثيرة، لأن ثلث الليل يتجدد على أهل الأرض مع اللحظات شيئا فشيئا، فيلزم انتقاله في السماء الدنيا ليلا نهارا، من قوم إلى قوم، وعوده إلى العرش في كل لحظة على قولهم، ونزوله فيها إلى سماء الدنيا، ولا يقول ذلك ذو لب وتحصيل. الثالث، أن القائل بأنه فوق العرش، وأنه ملأه كيف تسعه سماء الدنيا، وهي بالنسبة إلى العرش كحلقة في فلاة، فيلزم عليه أحد أمرين: إما اتساع سماء الدنيا كل ساعة حتى تسعه، أو تضاؤل الذات المقدس عن ذلك حتى تسعه، ونحن نقطع بانتفاء الأمرين.',
      'من قال أن الله جسم لا كالأجسام كفر',
      'فَيُرَى سبحانه لا في مكانٍ ولا جهةٍ ولا باتصال شعاعٍ ولا ثبوت مسافةٍ بين الرائيين وبينه تعالى بل على الوجه الذي يليق بقدسيته وجلاله سبحانه',
      'يتفق الجميع من علـماء سلف أهل السنة وخلفهم- وكذا العقلانيون من الـمتكلـمين – على أن ظاهر الاستواء على العرش بمعنى الجلوس على كرسي والتمكن عليه والتحيز فيه مستحيلٌ ، لأن الأدلة القطعية تُنَـزِّهُ الله تعالى عن أن يُشبهَ خلقه أو أن يحتاج إلى شىءٍ مخلوق ، سواء أكان مكاناً يحل فيه أو غيره ، وكذلك لأنه سبحانه نفى عن نفسه الـمماثلة لخلقه في أي شىء فأثبت لذاته الغِنى الـمطلق فقال تعالى :{ لَيْسَ كَمِثْلِهِ شَىءٌ}',
      'قال جعفر الصادق : من زعم أن الله في شىء ، أومن شىء أو على شىء فقد أشرك . إذ لو كان على شىء لكان محمولا ، ولو كان في شىء لكان محصوراً ، ولو كان من شىء لكان محدثًا (أي مخلوقاً)',
      'قال البيضاوي : لـما ثبت بالقواطع أنه سبحانه منـزه عن الجسمية والتحيز امتنع عليه النـزول على معنى الانتقال من موضعٍ إلى موضعٍ أخفض منه',
      'ولا يلزم من كون جهتي العلو والسفل مُحالاً على الله أن لا يوصف بالعلو ، لأن وصفه بالعلو من جهة الـمعنى ، والـمستحيل كون ذلك من جهة الحس، ولذلك ورد في صفته العالي والعلي والـمتعالي ، ولـم يرد ضد ذلك وإن كان قد أحاط بكل شىءٍ علـماً',
      'قوله سبحانه { لَيْسَ كَمِثْلِهِ شَىءٌ} [ سورة الشورى / 11] نصٌّ في نفي الجهة عنه تعالى ، إذ لو لـم تنف عنه الجهة لكانت له أمثال لا تحصى ، تعالى الله عن ذلك',
      'مَنْ سَنَّ فِى الإِسْلامِ سُنَّةً حَسَنَةً فَلَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا بَعْدَهُ مِنْ غَيْرِ أَنْ ينْقُصَ مِنْ أُجُورِهِمْ شَىْءٌ ، وَمَنْ سَنَّ فِى الإِسْلام سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ ينْقصَ مِنْ أَوْزَارِهِمْ شَىْءٌ',
      'وإنَّما ترفع الأيدي بالدعاء إلى السماء لأنَّ السَّماء مهبط الوحي ومنـزل القطر ومحل القُدس (أي الطهر) ومعدن الـمطهَّرين من الـملائكة ، وإليها ترفع أعمال العباد ، وفوقها عرشه وجنته ، كما جعل الله الكعبة قِبلةً للدعاء والصلاة ، ولأنه خلق الأمكنة وهو غير محتاج إليها ، وكان في أزله قبل خلق الـمكان والزمان ولامكان له ولازمان ، وهو الآن على ما عليه كان',
      'أنا سيّدُ ولد ءادم يوم القيامةِ ولا فخر',
      'أن الله تعالى ليس كمثله شيء وأنه منزه عن التجسم والانتقال والتحيز في جهة وعن سائر صفات المخلوق',
      'واستدل به على جواز إحداث ذكر في الصلاة غير مأثور إذا كان غير مخالف للمأثور',
      'وكذا حكى عن مالك أنه أوله بنزول رحمته وأمره أو ملائكته كما يقال فعل الملِك كذا أي أتباعه بأمره',
      'الواجب علينا أن نعتقد أن ذات الله تعالى لا تتبعض و لا يحويها مكان ولا توصف بالتغـيّر والانتقال',
      'وقال ابن خلكان في ترجمة الحافظ أبي الخطاب بن دحية : كان من أعيان العلماء ومشاهير الفضلاء ، قدم من المغرب ، فدخل الشام والعراق واجتاز بإربل سنة أربع وستمائة ، فوجد ملكها المعظم مظفر الدين بن زين الدين يعتني بالمولد النبوي ، فعمل له كتاب التنوير في مولد البشير النذير ، وقرأه عليه بنفسه ، فأجازه بألف دينار',
      'إن الله منـزهٌ عن جميع النقائص ، وسمات الحدوث ، ومنها الزمان والـمكان ، فلا يُقارنه زمانٌ ولا يحويه مكانٌ إذ هو الخالق لهما فكيف يحتاج إليهما',
      'قوله تعالى { ليس كمثله شيء } فيه الرد على المشبهة وأنه تعــــــالى ليس بجوهـــــر ولا جسم ولا عرض ولا لــــــون ولا طعم ولا حالّ في مكان ولا زمان',
      'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَ كُنَّا يَوْمًا نُصَلِّي وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ قَالَ مَنْ الْمُتَكَلِّمُ قَالَ أَنَا قَالَ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلُ',
      'والـمراد بِها توقيره [مراده : تعظيمه ] وتنـزيهه عن السفل والتحت ، ووصفه بالعلوِّ والعظمة لا بالأماكن والجهات والحدود لأنَّها صفات الأجسام',
      'فمعتقد سلف الأئمة وعلـماء السنة من الخلف أن الله منـزه عن الحركة والتحول والحلول ، ليس كمثله شىء',
      'كان أحمد – يعني الإمام أحمد بن حنبل – لا يقول بالجهة للباري',
      'وقال البيضاوي : لـما ثبت بالقواطع أنه سبحانه منـزه عن الجسمية والتحيز امتنع عليه النـزول على معنى الانتقال من موضعٍ إلى موضعٍ أخفض منه',
      '« قوله « في السماء » ظاهره غير مراد، إذ الله منـزه عن الحلول في الـمكان، لكن لما كانت جهة العلو أشرف من غيرها أضافها إليه إشارة إلى علو الذات والصفات »',
      'ولانقول إن العرش له ( أي لله ) قرارٌ ولامكانٌ ، لأن الله تعالى كان ولا مكان ، فلـما خلق الـمكان لـم يتغيّر عما كان',
      '« قوْلُهُ : « لا عِبْرَةَ بِقَوْلِ المُوَقّتينَ» أيْ في وجوبِ الصومِ على الناسِ »',
      'وقال : « لا يُعْتَبَرُ قولهُمْ بالإجماعِ ولا يجوزُ للمنجّمِ أنْ يعملَ بحسابِ نَفْسِهِ »',
      'قال شيخنا – يعني الحافظ ابن حجر العسقلاني – : إنَّ علـم الله يشمل جميع الأقطار ، والله سبحانه وتعالى منـزه عن الحلول في الأماكن ، فإنه سبحانه وتعالى كان قبل أن تحدث الأماكن',
      'و{العليّ} يُراد به علو القدر والـمنـزلة لا علو الـمكان ، لأنَّ الله منـزه عن التحيز. وحكى الطبري عن قوم أنهم قالوا : هو العلي عن خلقه بارتفاع مكانه عن أماكن خلقه . قال ابن عطية : وهذا قول جهلة مجسمين',
      '« البدعة بكسر الباء في الشرع هي: إحداث ما لم يكن في عهد رسول الله صلّى الله عليه وءاله وسلم، وهي منقسمة إلى حسنة وقبيحة.',
      'قال الإمام الشيخ المجمع على إمامته وجلالته وتمكنه في أنواع العلوم وبراعته أبو محمد عبد العزيز ابن عبد السلام رحمه الله ورضي عنه في ءاخر كتاب القواعد: البدعة منقسمة إلى: واجبة ومحرمة ومندوبة ومكروهة ومباحة. قال: والطريق في ذلك أن تعرض البدعة على قواعد الشريعة، فإن دخلت في قواعد الإيجاب فهي واجبة أو في قواعد التحريم فمحرمة أو الندب فمندوبة أو المكروه فمكروهة أو المباح فمباحة »',
      'وإضافته – أي العرش – إلى الله تعالى إنَّما هو بمعنى التشريف له كما يقال : بيتُ الله وحرمه ، لا أنه محلٌّ له وموضع لاستقراره اذ ليس – الله – في مكان ، فقد كان قبل أن يَخْلُقَ الـمكان',
      'مذهب أهل الحق قاطبةً أن الله سبحانه وتعالى يتعالى عن التحيّز والتخصص بالجهات',
      'ويجب أن يُعلـم أن كل ما يدل على الحدوث أو على سمة النقص فالرَّبُّ تعالى يتقدّس عنه ، فمن ذلك : أنه تعالى متقدّسٌ عن الاختصاص بالجهات ، والاتصاف بصفات الـمحدثات ، وكذلك لا يوصف بالتحول والانتقال ، ولا القيام ولا القعود ، لقوله تعالى : { لَيْسَ كَمِثْلِهِ شَىءٌ } [سورة الشورى/ 11] ، وقوله : { وَلـم يَكُن لَّهُ كُفُواً أَحَدٌ } [سورة الإخلاص/ 4] ، ولأن هذه الصفات تدل على الحدوث والله تعالى يتقدّس عن ذلك',
      'البارئ سبحانه وتعالى قائمٌ بنفسه، متعال عن الافتقار إلى محلٍّ يحله أو مكانٍ يُقله',
      'والناس فيها وفيما شاكلها على ثلاثة أوجه قال بعضهم : نقرؤها ونؤمن بها ولا نفسرها ، وذهب إليه كثير من الأئمة ، وهذا كما روي عن مالك رحمه الله أن رجلا سأله عن قوله تعالى : الرحمن على العرش استوى ، قال مالك : الاستواء غير مجهول ، والكيف غير معقول ، والإيمان به واجب ، والسؤال عنه بدعة ، وأراك رجل سوء أخرجوه . وقال بعضهم : نقرؤها ونفسرها على ما يحتمله ظاهر اللغة . وهذا قول المشبهة . وقال بعضهم : نقرؤها ونتأولها ونحيل حملها على ظاهرها',
      'خرجت مع عمر بن الخطاب – رضي الله عنه – ليلة في رمضان إلى المسجد فإذا الناس أوزاع متفرقون يصلي الرجل لنفسه ، ويصلي الرجل فيصلي بصلاته الرهط ، فقال عمر : إني أرى لو جمعت هؤلاء على قارئ واحد لكان أمثل ، ثم عزم فجمعهم على أبي بن كعب ، ثم خرجت معه ليلة أخرى والناس يصلون بصلاة قارئهم ، قال عمر : نعم البدعة هذه',
      'والله تعالى يُرى في الآخرة، ويراه المؤمنون وهم في الجنة بأعين رؤوسهم بلا تشبيه ولا كيفية، ولا يكون بينه وبين خلقه مسافة',
      'وَقَدْ تَأَوَّلَهُ بَعْضُهُمْ عَلَى مَعْنَى قَوْلِهِ : » يَوْمَ يُكْشَفُ عَنْ سَاقٍ » فَرُوِيَ عَنِ ابْنِ عَبَّاسٍ , أَنَّهُ قَالَ : عَنْ شِدَّةٍ وَكَرْبٍ . قَالَ أَبُو سُلَيْمَانَ : فَيُحْتَمَلُ أَنْ يَكُونَ مَعْنَى قَوْلِهِ : » يَوْمَ يَكْشِفُ رَبُّنَا عَنْ سَاقِهِ » ، أَيْ عَنْ قُدْرَتِهِ الَّتِي تَنْكَشِفُ عَنِ الشِّدَّةِ وَالْمَعَرَّةِ',
      'ومعنى { فَوقَ عِباَدِهِ } فوقية الاستعلاء بالقهر والغلبة عليهم ، أي : هم تحت تسخيره ، لا فوقية مكان',
      'ويتكلم ( يعني الله) لا ككلامنا. و نحن نتكلم بالآلات و الحروف و الله تعالى يتكلم بلا آلة و لا حروف , و الحروف مخلوقة و كلام الله تعالى غير مخلوق',
      'قوله قال عمر: (نعم البدعة) في بعض الروايات (نعمت البدعة) بزيادة التاء، والبدعة أصلها ما أحدث على غير مثال سابق، وتطلق في الشرع في مقابل السنة فتكون مذمومة، والتحقيق أنها إن كانت مما تندرج تحت مستحسن في الشرع فهي حسنة، وإن كانت مما تندرج تحت مستقبح في الشرع فهي مستقبحة، وإلا فهي من قسم المباح، وقد تنقسم إلى الأحكام الخمسة',
      'يجب لله الوجود والقدم كذا البقاء و الغنى المطلق عم وخلفه لخلقه بلا مـثال و وحدة الذات ووصف الفعال و قدرة إرادة علم حـياة سمع كلام بصر ذي واجبات',
      'الحمد لله الذي ليس له حدٌّ محدودٌ فيُحتوى ، ولا له أجلٌ معدودٌ فيَفنى ، ولا يحيط به جوامع الـمكان ، ولا يشتمل عليه تواتر الزمان',
      'أنت الله الَّذي لا يَحويك مكان',
      'أنت اللهُ الذي لاَ تُحَدُّ فَتـكُونَ مـحدوداً',
      'البدعة بدعتان : بدعة محمودة ، وبدعة مذمومة ، فما وافق السنة فهو محمود ، وما خالف السنة فهو مذموم . واحتج بقول عمر بن الخطاب في قيام رمضان : نعمت البدعة هي',
      'سمعت الشَّافِعيُّ رَضِيَ اللهُ عَنْهُ يَقُولُ: إِنِّي لأَتَبَرَّكُ بِأَبي حَنِيفَةَ وَأَجِيءُ إِلى قَبْرِهِ في كُلِّ يَوْمٍ فَإِذَا عَرَضَتْ لي حَاجَةٌ صَلَّيْتُ رَكْعَتَيْنِ وَجِئْتُ إِلى قَبْرِهِ وَسَأَلْتُ اللهَ تَعَالى الْحَاجَةَ عِنْدَهُ فَمَا تَبْعُدُ عَنِّي حَتَّى تُقْضَى',
      'نُقِرُّ بأنَّ اللهَ تعالى على العرشِ استوى من غيرِ أن يكونَ له حاجةٌ إليه واستقرار عليه وهو الحافظُ للعرش وغيرِ العرش منْ غيرِ احتياج، فلو كان محتاجا لما قَدَرَ على إيجادِ العالم وتدبيرِه كالمخلوق ولو كان محتاجا إلى الجلوس والقرار فقبل خلقِ العرشِ أين كان الله تعالى الله عن ذلك علوًا كبير',
      'ويستحب أن يقعد عنده بعد الفراغ ساعة قدر ما يُنحَر جَزُورٌ ويُقَسَّم لحمُها. ويشتغل القاعدون بتلاوة القرآن، والدعاء للميت، والوعظ، وحكايات أهل الخير، وأحوال الصالحين',
      'قال الشافعي والأصحاب: يُستحبّ أن يقرؤوا عنده شيئاً من القرآن، قالوا: فإن ختموا القرآن كلَّه كان حسناً',
      'وروينا في سنن البيهقي بإسناد حسن؛ أن ابن عمر استحبَّ أن يقرأ على القبر بعد الدفن أوّل سورة البقرة وخاتمتها',
      '« المحدثات من الأمور ضربان:',
      '– أحدهما : ما أحدث يخالف كتاباً أو سنة أو أثراً أو إجماعاً، فهذه البدعة الضلالة.',
      '– والثانية: ما أحدث من الخير لا خلاف فيه لواحد من هذا، وهذه محدثة غير مذمومة.',
      '[وقد] قال عمر، رضي الله عنه، في قيام شهر رمضان: نعمت البدعة هذه يعني أنها محدثة لم تكن، وإذا كانت فليس فيها ردّ لما مضى »',
      'قوله : { مَن فِي السَّمَاءِ } في الـموضعين من قبيل الـمتشابه الذي يعطي ظاهره معنى الحلول في مكان ، وذلك لا يليق بالله',
      'اتفق العقلاء من أهل السنة الشافعية والحنفية والـمالكية وفضلاء الحنابلة وغيرهم على أن الله تبارك وتعالىَ مُنَـزَّهٌ عن الجهة والجسمية والحد والـمكان ومشابَهة مخلوقاته',
      'مذهب الفرقة الناجية وما عليه أجمع السُّنِّيُّـون أن الله تعالى مُنَـزَّهٌ عن مشابـهة الحوادث مخالف لها في جميع سمات الحدوث، ومن ذلك تَنَـزُّهُهُ عن الجهة والـمكان كما دلت على ذلك البراهين القطعية',
      '« قالت النجارية : « إن الباري سبحانه بكل مكان من غير حلول ولا جهة »، وقالت الحشوية والمجسمة : « إنه سبحانه حالٌ في العرش، وإن العرش مكان له وهو جالس عليه »، فسلك -أي الإمام الأشعري رضي الله عنه- طريقة بينهما فقال: « كان ولا مكان، فخلق العرش والكرسي ولم يحتج إلى مكان، وهو بعد خلق المكان كما كان قبل خلقه ».»',
      'إنَّ الذي يجبُ علينا وعلى كلِّ مسلم أن يَعلَمَهُ أنَّ ربنا ليس بذي صورةٍ ولا هيئة فإنَّ الصورة تقتضي الكيفية وهي عن الله وعن صفاته منفية',
      '« واستدل بعض أصحابنا في نفي الـمكان عنه بقول النبيِّ صلى الله عليه و سلم :',
      '« أنت الظاهر فليس فوقك شىء ، وأنت الباطن فليس دونك شىء » ،',
      'وإذا لـم يكن فوقه شىء ولا دونه شىء لـم يكن في مكان »',
      'فقد وقع السؤال عن عمل المولد النبوي في شهر ربيع الأول ، ما حكمه من حيث الشرع ؟ وهل هو محمود أو مذموم ؟ وهل يثاب فاعله أو لا ؟ الجواب : عندي أن أصل عمل المولد الذي هو اجتماع الناس وقراءة ما تيسر من القرآن ورواية الأخبار الواردة في مبدأ أمر النبي صلى الله عليه وسلم وما وقع في مولده من الآيات ، ثم يمد لهم سماط يأكلونه وينصرفون من غير زيادة على ذلك – هو من البدع الحسنة التي يثاب عليها صاحبها لما فيه من تعظيم قدر النبي صلى الله عليه وسلم وإظهار الفرح والاستبشار بمولده الشريف ، وأول من أحدث فعل ذلك صاحب إربل الملك المظفر أبو سعيد كوكبري بن زين الدين علي بن بكتكين ، أحد الملوك الأمجاد والكبراء الأجواد ، وكان له آثار حسنة ، وهو الذي عمر الجامع المظفري بسفح قاسيون',
      'لا خلاف أن ساب الله تعالى من المسلمين كافر',
      'حدثني أبي, قال: حدثنا يحيى بن زكريا بن أبي زائدة, قال: أخبرني إسماعيل بن أبي خالد, عن فراس, عن الشعبي قال: لا بأس بالتعويذ من القرءان يعلق على الإنسان',
      'فقد تكون البدعة واجبة كنصب الأدلّة للردّ على أهل الفِرق الضالّة، وتعلّم النحو المفهم للكتاب والسنّة، ومندوبة كإحداث نحو رباط ومدرسة، وكل إحسان لم يكن في الصدر الأول، ومكروهة كزخرفة المساجد، ومباحة كالتوسّع بلذيذ المآكل والمشارب والثياب',
      'تـعـالى – أي الله – عن الحدود والغايات والأركان والأعضاء والأدوات لا تحـويه الجهـاتُ السـِتُّ كسائر المبتَدَعات',
      '« قوله صلى الله عليه وسلم : ( وكل بدعة ضلالة ) هذا عام مخصوص ، والمراد غالب البدع .',
      'قال أهل اللغة : هي كل شيء عمل على غير مثال سابق . قال العلماء : البدعة خمسة أقسام : واجبة ، ومندوبة ومحرمة ، ومكروهة ، ومباحة . فمن الواجبة : نظم أدلة المتكلمين للرد على الملاحدة والمبتدعين وشبه ذلك . ومن المندوبة : تصنيف كتب العلم ، وبناء المدارس والربط وغير ذلك . ومن المباح : التبسط في ألوان الأطعمة وغير ذلك . والحرام والمكروه ظاهران . وقد أوضحت المسألة بأدلتها المبسوطة في تهذيب الأسماء واللغات ، فإذا عرف ما ذكرته علم أن الحديث من العام المخصوص . وكذا ما أشبهه من الأحاديث الواردة ، ويؤيد ما قلناه قول عمر بن الخطاب – رضي الله عنه – في التراويح : نعمت البدعة ، ولا يمنع من كون الحديث عاما مخصوصا . قوله : ( كل بدعة ) مؤكدا ( بكل ) ، بل يدخله التخصيص مع ذلك ، كقوله تعالى : تدمر كل شيء . »',
      'إنه تعالى كان ولا مكان فخلق الـمكان وهو على صفة الأزلية كما كان قبل خلقه الـمكان لا يجوز عليه التغيِير فى ذاته ولا في صفاته',
      'أَجمعَ أَهْلُ الحَقِّ قَاطِبَةً على أنَّ الله تَعالى لاجِهَةَ له، فلا فوقَ ولا تحتَ ولايمينَ ولا شمالَ ولا أمامَ ولا خَلْفَ',
      'العَجْزُ عن دَرَكِ الإِدْرَاكِ إِدْرَاكُ والبَحْثُ عن ذَاتِهِ كُفْرٌ وإِشْرَاكُ',
      '﴾ وَلاَ يُحِيطُونَ بِهِ عِلْمًا ﴿'
    ]::text[]);
    GET DIAGNOSTICS n = ROW_COUNT;
    RAISE NOTICE 'paroles : % ligne(s) supprimée(s) (islamsunnite.net).', n;
  END IF;
END $$;

